INSERT INTO `videoinfo` VALUES ('BV1164y117J1', '760466049', '26798384', '【柴知道】流浪猫真的是“百亿杀手”吗？这种天文数字是怎么算出来的？', '猫猫这么可爱，能有什么坏心眼？根据南京大学团队的估算，中国的流浪猫一年要杀死 121.3~319.8 亿只野生动物——不过很多人并不认同这个结论，然后大家就吵了起来。所以121亿的天文数字，究竟是怎么得出来的？搞清楚这个问题，我们才能真正理解“百亿杀手”的含义。于是我们阅读了论文原文和与之相关的一堆文献，梳理出了121亿背后的计算模型和数据来源，希望能让你看懂科学数据背后的意义~', 741059, 19429, -1, 980, 2682, 3225, 4630, 5907, '2021-5-7 13:19:17', 410, 1, '2025-8-28 09:46:06', 0.0132743, 0.136943);
