INSERT INTO `videoinfo` VALUES ('BV11t411X7cq', '37175021', '26798384', '我们不是作，只是生病了。', '全球上有3亿多人罹患抑郁症。在中国，社会大众对抑郁症的污名化，导致很多患者怀有强烈的病耻感。其实，抑郁症不是作，也不是矫情，它是一种很难自愈的情绪障碍，是大脑内部出了问题。抑郁症是基因与环境相互作用的结果，我们每一个人，在一生中的某一个阶段，都有患上抑郁症的可能…', 90541, 5206, -1, 2236, 847, 3011, 4094, 1371, '2018-12-1 11:12:33', 391, 1, '2025-8-28 09:46:06', 0.00978481, -0.195966);
