INSERT INTO `videoinfo` VALUES ('BV11t4y1C7XT', '625815742', '138832847', '一直被抄袭，从未被超越！罗pd是如何做出高分原创综艺的？【哇妹】', '老罗的成功、韩国综艺的成功，\n是众多综艺人长年累月的积累，\n是残酷竞争制度优胜劣汰的结果。\n他们因热爱而敬业，因敬业而不断创作，因创作才能走得长远。\n这是一个良性的循环。\n比起抄袭罗PD的创意，更应该学习的是他做综艺的精神。\n认真对待节目，认真对待观众，\n用热爱去创造，用真心去表达。\n\n部分视频出处：\n@凤凰天使TSKS韩剧社官方账号  @女汉子字幕组  @百度李昇基吧', 1477025, 99348, -1, 13153, 12450, 19724, 52949, 3949, '2020-5-29 10:00:57', 707, 1, '2025-8-28 09:46:06', 0.0048277, -0.668892);
INSERT INTO `videoinfo` VALUES ('BV11u4y187gi', '918214868', '2374194', '【古筝】李清照写如梦令那一晚到底在和谁喝酒？', '《易安居士》终于发完整版啦！！！创作的背景是一个脑洞大开的小故事····\n\n据史籍记载，李清照在写出《如梦令•昨夜雨疏风骤》的那个前夜一直在与友人饮酒。且词中写到“浓睡不消残酒”，可见酒尽兴，人投缘。而到底是在和谁喝酒，第二天何来灵感写出这首绝妙的《如梦令•昨夜雨疏风骤》却一直是个谜……\n \n后来，江湖上出现了一位可以通过琴声自由穿越古今的女侠，名曰墨韵。一日她看到了李清照的《如梦令•常记溪亭日暮》后，非常喜爱，随即弹起了她的步摇筝，琴声款款，人影绰绰，李清照逐渐靠近，并和墨韵一起诵读自己的词句。推杯换盏', 125065, 5048, -1, 179, 111, 984, 1761, 165, '2023-11-10 10:00:00', 275, 1, '2025-8-28 09:46:06', 0.00700738, -0.460943);
