INSERT INTO `videoinfo` VALUES ('BV12G4y167HE', '815152315', '98608863', '官宣：我们的感情出问题了', '本以为是 dream couple 的我们俩，前一段「冷静期」了一下。\n\n我和阿姐夫处在一段长期「异地婚」的关系中。刚开始觉得这段关系又有自己的空间，又有很坚固的信任，还挺不错的。直到有了菜卷之后，我经常觉得无法和阿姐夫共享我在育儿过程中所收获的细腻的甜蜜，在崩溃、疲惫的时候也没有得到他的支持。我甚至有想过，我又不是养不活菜卷，不如离婚算了。那段时间，异地的状态对我们来说不单是有距离上的困难，它还形成了一堵无形的墙。\n\n我决定鼓起勇气邀请阿姐夫一起来回顾我们在十年关系、六年婚姻过程中经历的起伏。', 519188, 15325, -1, 4451, 1437, 2497, 4682, 1348, '2022-9-5 11:00:00', 747, 1, '2025-8-28 09:46:06', 0.00340897, -0.804244);
