INSERT INTO `videoinfo` VALUES ('BV12p4y1Y7G9', '969414363', '11799651', '不喝酒就要被扇耳光？谁在拼死维护“酒桌文化”【中国观察】', '不喝酒就要被扇耳光？不喝茅台就是没长大的小屁孩，还不懂事？能喝酒就是中华民族稀缺之人才？\n关于酒桌的“文化”，是谁在定义，又是谁在拥护？\n\n酒桌上的劝酒与喝酒本质上是权力的流动。\n令人遗憾的是，年轻人今天能够站起来拒绝喝掉这一杯杯“权力的液体”，却很难说是因为足够平等了。', 105101, 5719, -1, 508, 721, 1367, 1790, 444, '2020-8-29 05:16:32', 528, 1, '2025-8-28 09:46:06', 0.0322448, 1.9468);
