INSERT INTO `videoinfo` VALUES ('BV12r4y1Y7Et', '765774520', '2374194', '【墨韵古筝】大哥没有输！明け星 - 鬼灭之刃无限列车OP', '又是新的一年，很高兴又收到了来自拜年纪的邀请，担任2022新春拜年官~ 还有几天就过年了！在这预祝大家新年吉祥！阖家团圆！幸福美满！\n虽然成都的半夜很冷，但依然不能阻止我在这个火车前面燃烧我的心！大哥没有输！呜呜呜呜……其实很想搞个大哥同款猫头鹰发型，结果最后只剩了猫头鹰眉毛，可惜！不过我参透了鬼杀队队服如此抗造的秘密——是羽绒服！我在里面加了羽绒服！（我还穿了三条裤子笑死～\nLiSA唱的OP依然是非常抓耳，只是这个bE转#F给我整懵了2333～不过现在我有很多琴，转调都不是问题！希望大家喜欢～\n最后，2', 472011, 97058, -1, 739, 5751, 7761, 91306, 757, '2022-1-23 10:00:17', 101, 1, '2025-8-28 09:46:06', 0.0113308, -0.0484728);
INSERT INTO `videoinfo` VALUES ('BV12s41187Gi', '8370156', '26798384', '科普：虚拟现实（VR）是什么原理？', '【科普：虚拟现实(VR)是什么原理?】最近这一年，我们身边出现了很多基于虚拟现实(VR)技术的新玩具：比如VR眼镜，明明只是播放了一些逼真立体的虚拟画面，却让你感觉这些虚拟的画面才是现实。其实这是因为，VR内容模拟了人眼的视觉体验。', 121636, 1264, -1, 1721, 449, 2794, 1048, 363, '2017-2-3 05:32:21', 284, 1, '2025-8-28 09:46:06', 0.00217876, -0.92161);
INSERT INTO `videoinfo` VALUES ('BV12s411B7jZ', '4686255', '116683', '【咬人猫】染上你的颜色❤o(*≧▽≦)ツ', '一直很喜欢这样欢快的舞蹈，就像旅行时的心情一样开心～于是和露露在厦门录了这支舞。几乎每次异地的录制，都会受到一些条件的影响，这次的这片草坪也是通往沙滩人行用的，经常会有路人经过，很洒脱的就跳完了却没有办法再多录几遍～也有很多不足的地方很遗憾～最后会有一点点游玩的画面，希望能和大家分享一份轻松的心情就好～也要特别感谢摄影、后勤：露露！！\r\n参考舞蹈：sm27753880 音源：sm27529228 ', 4266638, 33440, -1, 18818, 13734, 54443, 96084, 6066, '2016-5-17 15:42:53', 220, 1, '2025-8-28 09:46:06', 0.00718585, -0.443916);
INSERT INTO `videoinfo` VALUES ('BV12s411s7Cm', '6902685', '26798384', '囧知-什么是基因编辑技术？', '四十年前，人类从没想过，基因还可以被人为地修改；而今天，科学家们已经在尝试通过基因编辑来治愈血友病、肌肉萎缩症、甚至癌症等复杂的疾病。那么，这个具有革命性意义的技术，到底是什么原理呢？', 36958, 455, -1, 452, 280, 855, 561, 201, '2016-10-31 06:26:22', 237, 1, '2025-8-28 09:46:06', 0.0102269, -0.153789);
