INSERT INTO `videoinfo` VALUES ('BV137411s72p', '86436223', '98608863', '你今天还好吗 | 我生病了，不知道该不该去医院', '在这段大家都不得不待在家的日子里，很多人都在面对着同样的问题：每天信息过载，愤怒难过压抑，要在处理自己的情绪和继续面对生活中调整自己。我也会在接下来的几天里，每天和一个朋友视频电话，聊聊每天的感受，怎么度过这些日子，如何排解每天的情绪，也把这些做成视频分享给大家。今天的嘉宾是我的好朋友和前同事 巧，她以前常在《微在不懂爱》的节目里出现。', 14625, 820, -1, 78, 46, 38, 153, 53, '2020-2-3 04:17:10', 452, 1, '2025-8-28 09:46:06', 0.00742398, -0.421198);
