INSERT INTO `videoinfo` VALUES ('BV13b421H7ft', '1805652962', '98608863', '到底要不要母乳？这事儿别人还真给不了答案。', '“到底要不要母乳”这几乎是每个有生育计划的女性都在问的问题。\n\n菜卷我喂到了一岁半自然离乳，现在二胎我也打算先继续试着母乳。但开头的问题，我可以告诉你出奶阵是什么体验，涨奶到底有多疼，什么是正确的衔乳姿势、什么吸奶器好用、背奶是什么体验和孩子的连接有多幸福，就是无法回答到底要不要母乳。\n\n任何一个除妈妈之外的人，都不能帮她做决定，但 TA 们可以分享经验，可以尊重她喂养的空间，可以提供更可以给无论选择哪种哺育方式的妈妈更多的支持和理解。', 41134, 1884, -1, 232, 35, 399, 539, 125, '2024-6-10 09:57:58', 456, 1, '2025-8-28 09:46:06', 0.0224918, 1.01633);
