INSERT INTO `videoinfo` VALUES ('BV13U4y1c7UQ', '676295175', '98608863', '我不接受没道理的规则 ｜ 姐姐教我', '我又开新坑了。我想每次分享3位酷姐姐，她们在小小的地方影响着我，好像无形中改造着我，组装我成为日益成长的自己。\n这次的3位姐姐都有点刚，她们不是顺从的、乖巧的玩偶，不是规训之下的服从者。她们提醒我，不去接受没道理的规则，每一次正面硬钢，都是在丰满自己的独立人格。成为自己的“利刃”，划破束缚。\n这让我想到流星，它不仅代表着浪漫，更是包含冲击力，棱角鲜明地划破长空，留下着自己存在的痕迹。这也是APM的Divine流星系列设计的本意，APM倡导独立自由，它是我的勇气加成，鼓励我刻画出生活有态度的轨迹。', 79826, 8803, -1, 355, 393, 1414, 3448, 208, '2021-10-28 11:00:17', 411, 1, '2025-8-28 09:46:06', 0.0021379, -0.925509);
