INSERT INTO `videoinfo` VALUES ('BV1444y1875b', '975268515', '98608863', '小时候，你们为什么会那样对我？', '生育会带来的其中一个奇特的反应是，我会在看到自己小孩的时候回想起我的童年。也会在自己习得如何做母亲的时刻，去试图回忆，我的妈妈那时是怎么对我的。我开始产生了一些想向她求证的问题，于是开始策划这次拍摄。好像有镜头架在这里，我的这些唐突的疑问就有了存在的正当理由，而我们两个也因为被置于镜头之下，就必须要面对这些问题，不能逃避。', 110759, 9157, -1, 794, 922, 1396, 3781, 583, '2021-9-6 13:39:19', 614, 1, '2025-8-28 09:46:06', 0.00467771, -0.683202);
