INSERT INTO `videoinfo` VALUES ('BV14a4y1Y7sH', '668546214', '11799651', '你为什么结不了婚【中国观察】', '爱情从不永恒，也不要企图通过“结婚”来维系所谓的爱情。婚姻从来保障的都只是财产权和继承权。 \n但是，我从来不否认我们这一代对爱情的追求。物质文明发展到今天，传统婚姻中的好处很大程度被社会化分工取代，我们追求更高层次的恋爱和婚姻关系理所应当。\n祝大家既能快快乐乐恋爱，也能坦坦荡荡单身。\n如果你妈问你为啥还不结婚，建议你把这个视频转发给她（当然妈妈们也不一定看...）', 231654, 13883, -1, 2294, 7495, 4733, 6895, 2810, '2020-6-24 10:45:11', 602, 1, '2025-8-28 09:46:06', 0.016398, 0.43496);
