INSERT INTO `videoinfo` VALUES ('BV14b4y127qG', '632972511', '1377430946', '土耳其野心暴露！宣布成立“突厥联军”，欲与美俄三分天下', '土耳其宣布成立突厥国家联盟（又称突厥联军），这个联盟的成立，不但具有经济上的合作，更有军事上的联盟。土耳其显然是想形成世界上另外一种重要的政治军事力量，可能想和俄美三足鼎立。', 238987, 6056, -1, 455, 1885, 983, 190, 1595, '2021-9-9 09:10:15', 590, 1, '2025-8-28 09:46:06', 0.0138814, 0.194866);
INSERT INTO `videoinfo` VALUES ('BV14b4y1d7Q7', '631028294', '546195', '《你眼里的光》bilibili x老番茄x老坛胡说 ｜ 不要关掉你眼里的光', '#你眼里的光二创# 同步开启https://www.bilibili.com/blackboard/dynamic/146573\n2021年毕业前夕，我们前往各高校拍摄，并将这些真实画面制作成MV，记录下毕业前夕最珍贵的时光。\nbilibili x 老番茄 x 老坛胡说 联合发布《你眼里的光》，送给所有即将或已经毕业的你——不管今后是躺着、站着、还是奔跑着，都睁开双眼，去拥有天空、朋友和时光！\n \nbilibili 出品｜SG胜加 联合出品｜光明日报 中国青年报 联合发布', 7012326, 476960, -1, 35849, 15608, 141693, 219567, 16719, '2021-6-10 01:00:15', 329, 1, '2025-8-28 09:46:06', 0.00842297, -0.325891);
