INSERT INTO `videoinfo` VALUES ('BV14G411578B', '430050452', '98608863', '女人行不行，上场来证明【国际月经简报·ep7】', '这个世界的气候并不相同，但我们的悲欢可以相通。因为我们能做的就是去理解这个世界的苦难，去庆祝这个世界所取得的努力。\n· 环法破天荒举办了女子比赛，但赛段设置依然不平等；\n· 美国将首次推出适合女性作战人员的胸罩，女性不是「小一号的男人」。\n· 小威 Serena Williams 宣布了即将自己退役的消息。作为全人类中打出了最多的大满贯的网球运动员，但总收入还是比收入最高的男性网球运动员差了 6000 万美元。在听到小威退役的消息的时候，总觉得有点唏嘘，但谁又知道告别之后没有别的花路可走呢？', 63653, 8397, -1, 608, 433, 1243, 5377, 177, '2022-8-31 11:09:24', 491, 1, '2025-8-28 09:46:06', 0.00454083, -0.696261);
