INSERT INTO `videoinfo` VALUES ('BV14i421v7Lu', '1455474412', '2920960', '开在北京胡同中的米其林餐厅什么样？', '店名：曲廊院       位置：北京东城区东四十一条附近\n连续三年米其林推荐，但没摘到星，也没评上过餐盘。\n主厨是一位年轻女主厨，能看得出来有自己的理念，和对食材独特的理解。\n虽然黑松露鲍鱼和甜口的喉黑鱼对于我个人而言实在欣赏不来。\n但餐厅装修风格和用餐环境还有服务上都给这家餐厅提了不少分。', 839775, 45407, -1, 993, 3558, 8193, 20784, 898, '2024-6-7 10:00:00', 870, 1, '2025-8-28 09:46:06', 0.00623775, -0.534369);
