INSERT INTO `videoinfo` VALUES ('BV14JGwzhEP5', '114822058351205', '98608863', '性感是自由，还是陷阱？', '当女孩表达性感，是在自我赋权？还是在自我欺骗？\n一个女人，可以自我选择性感，但拒绝被性化吗？\n「服从式的性感」是对矫枉过正的不沾男文化的反抗？还是一种危险的反扑？\n\n今天这个视频是在我成为妈妈之后，关于「该不该性感」的第二波思考：\n\n上次评论有人说我「半醒不醒」，好的，我决定认领这个标签，挖坑一个新的系列——半醒不醒——一个仍在学习女性主义的后进生、一个生女儿之后的我拧巴又真实的自白。', 108537, 9666, -1, 674, 411, 3283, 3538, 567, '2025-7-9 09:30:00', 532, 1, '2025-8-28 09:46:06', 0.0041957, -0.729187);
