INSERT INTO `videoinfo` VALUES ('BV14p421S7RD', '1853700992', '98608863', '共读《零诺》｜ 用女性野心一脚把霸总踢开', '大家期待已久的《零诺》读书会终于来了！\n\n最开始我们被《零诺》吸引到是因为，它几乎是一本零差评的网文。在我们对于网络文学还停留在「霸总」「娇妻」「强制爱」的想象时，行烟烟带着宋零诺、季夏、施谨走来了，用女性群像，打破了我们所有的惯性思维，在《零诺》的世界里，女性的职业是没有天花板的，女性可以有男人，有很多的男人，但不需要归宿。\n\n但这样的女性形象我们希望她不止是出现在小说里，而是在现实生活中，她们也可以鲜活地存在，她不完美，但为自己的野心而活，她不贞洁，但尊重自己感情和欲望......', 33001, 2640, -1, 259, 194, 707, 932, 115, '2024-4-27 13:05:00', 948, 1, '2025-8-28 09:46:06', 0.00532932, -0.621036);
