INSERT INTO `videoinfo` VALUES ('BV14P4y1X7EV', '903580602', '98608863', '评评理，六层楼比我更时尚吗？', '我最近邀请我的好朋友，新晋穿搭博主@六层楼先生  来了一场穿搭友谊赛。没想到「不务正业」的他，竟然比苦苦耕耘一生的我，更像那么回事。从现场的气氛来看，六老师明显已经成为了「穿搭靠文案」这个领域的王者，但注重视觉效果的我，还是希望广大观众可以在视频里，投出你们偏心的一票。\n\n这期节目也是作为@songmont  的品牌挚友我本人，和挚友的挚友六老师，合作为大家搭一搭他们家的包包。他们家的包包很实用，能装下女性知识分子的生产工具，也很有设计感，能装下可爱、时尚、个性。', 51506, 3693, -1, 85, 808, 253, 719, 103, '2022-12-9 11:00:00', 880, 1, '2025-8-28 09:46:06', 0, -1.12947);
INSERT INTO `videoinfo` VALUES ('BV14PNBepEY2', '113985059819646', '98608863', '反思了一下，发现我们也是「特权阶级」| 《见树又见林》读书会', '瘦子、京籍、成绩好、异性恋？你有意识到这些「特征」某种程度上也是一种特权吗？\n歧视、压迫、不平等，为什么特权永远不会反思？\n面对比自身更强大的东西，我们到底可以做什么？\n\n这次读书会，我们翻开了艾伦·G.约翰逊的《见树又见林》，这是一本社会学的入门读物，它可以让我们认识到特权从何而来？压迫为什么能被正当化？不平等为何根深蒂固？\n\n但对于我们来说，它的意义也不止如此，\n它让我们反思我们在某些领域享有「特权」。\n它提醒我们在参与社会活动当中要保持自觉，要警惕无意识。\n\n我们时常会觉得自己很渺小，作为个体，无法', 65852, 1931, -1, 292, 200, 759, 1017, 87, '2025-2-11 12:08:07', 2713, 1, '2025-8-28 09:46:06', 0.00125712, -1.00954);
INSERT INTO `videoinfo` VALUES ('BV14q4y157sx', '548605914', '1377430946', '中国对美采取新战略？解放军密集演练构成威慑，美台高度紧张', '中国空军再次的密集派出军机在相关海域进行训练，其实就是向台湾岛内的“台独”势力发出警告和威慑。台湾现状的产生本身也是东西方大国博弈的结果，而台湾海峡局势的紧张和放松或者是火药味的升降，其实也都取决于中美两国的关系。', 19299, 595, -1, 7, 34, 31, 28, 34, '2021-10-14 08:54:00', 436, 1, '2025-8-28 09:46:06', 0.012583, 0.0709863);
