INSERT INTO `videoinfo` VALUES ('BV14S4y1c7pc', '683468790', '26798384', '【柴知道】家庭热门小飞虫鉴定！手把手教你弄（nèng）死它们', '动物不分高低贵贱，让我们饱含爱意地来看看你家里的常见小飞虫，以及如何科学地弄死它们~那些趴在厕所、落在屏幕上、死在水杯里的到底是什么虫子？它们从哪里来，会危害你的健康吗？怎么科学有效地消灭它们？我们鉴定了四种常见家居小飞虫，快来欣赏一下！', 472310, 24304, -1, 3982, 1975, 7257, 5761, 981, '2022-4-22 09:50:49', 402, 1, '2025-8-28 09:46:06', 0.0408161, 2.76452);
