INSERT INTO `videoinfo` VALUES ('BV15b4y1Q71w', '629678649', '2374194', '【墨韵古筝】紅蓮華 - 鬼滅の刃OP——疯狂练习曲又来了', '喜欢了很久的一首歌，历经万难之后终于翻出来了！改编的时候光想着怎么好听，也没想到上手一练音域跨度惊人！啊——又是需要疯狂练习的一天呢……（咦？为什么要说又？\n\n整体的改编还是尽量丰富了双手的旋律，并且加入了我最喜欢的快速指序以避免过多的技法和唱段重复。如果没有伴奏，其实也是比较完整的独奏编排。但是原曲的曲风我太喜欢啦！所以特别邀请了包老师帮我扒带制作了这版伴奏，非常感谢！希望大家喜欢～\n\n原曲：《红莲华》\n古筝演奏/改编：墨韵随步摇\n伴奏制作：包达\n录音/混音：刘嘉伦\n古筝拍摄/后期：余林峰\n妆发：璐璐\n', 1252817, 113902, -1, 6524, 2693, 36102, 83950, 2398, '2021-3-19 10:00:19', 245, 1, '2025-8-28 09:46:06', 0.0741157, 5.94143);
