INSERT INTO `videoinfo` VALUES ('BV15HuqzKEbJ', '114851653361080', '2374194', 'MV「海纳百川」 | 《幻想乐园》发行一周年纪念单曲上线！', '✨ 自作曲家陈致逸的音乐专辑《幻想乐园 Fantasyland》发行以来，感谢大家一路的陪伴以及对专辑的喜爱与支持！值此一周年之际，陈致逸特别创作了一曲纪念新作 ——「海纳百川」，诚邀多位B站音乐区优秀UP主共创，并拍摄MV，作为陈致逸对众多支持他的乐迷朋友与听众朋友最诚挚的回馈。该曲已于今日7月29日上线@网易云音乐   @QQ音乐   等各大音乐平台。\n这首融合国风意境与海派韵味的作品，以开阔而细腻的音乐语言，奏响包容与梦想的旋律。诚邀你一同踏上这段回忆与未来交织的音乐旅程！\n\n==========?', 105256, 9382, -1, 360, 229, 1789, 2394, 333, '2025-7-29 07:00:00', 297, 1, '2025-8-28 09:46:06', 0.00387173, -0.760095);
