INSERT INTO `videoinfo` VALUES ('BV15S4y1R7x9', '721851045', '2374194', '【指弹纯筝】STAY 客官您看我这21弦的吉他怎么样', '好像很久没有纯古筝了，这不就来了吗！！\n \n其实我一直觉得指弹吉他非常酷，可能这个乐器本身的气质就很独特，能将一个乐队融合在一把琴六根弦里。这两年看节目和视频，也发现有不少乐手通过各种方式把古筝背在身上，看上去似乎也确实带了些吉他的酷劲儿了。在大家的启发下我也一直在想，除了形式上的突破，要如何在演奏上也酷起来呢？值此之际，正好遇到了STAY这首结构简洁，音域合适的曲子，于是果断下手。\n \n仔细研习一番之后，我觉得旋律声部的技法并不重要，最不可或缺的是Bass和打击乐的支撑。因此，两只手要消化掉主旋律，分解', 648069, 47784, -1, 4646, 806, 16898, 30641, 953, '2021-11-19 10:00:03', 147, 1, '2025-8-28 09:46:06', 0.00951187, -0.222005);
