INSERT INTO `videoinfo` VALUES ('BV1644y1j7JM', '978014857', '26798384', '【柴知道】冥想是科学还是玄学？它怎么成了时尚和生意？', '乔布斯曾说，冥想改变了他的世界观和苹果的产品设计。和他一样，许多名人都是冥想的拥趸，如今市面上也有着各种冥想课程和App，冥想已经成了中产阶级的新时尚和新生意。什么是冥想？它对你的大脑做了什么？冥想到底是一门科学，还是玄学？我们从脑神经科学的角度，来研究这些问题？', 154707, 12436, -1, 794, 743, 2478, 3760, 634, '2022-1-11 10:45:38', 367, 1, '2025-8-28 09:46:06', 0.0057261, -0.583182);
