INSERT INTO `videoinfo` VALUES ('BV16A411n7hU', '329448988', '116683', '【咬人猫】四种风格的约会❤️你会喜欢吗？summertime!', '总是想在夏天跳一次夏天味道清爽快乐的舞，但每次都抓不住夏天的尾巴～\n去年夏天喜欢上的歌和舞，准备着想在今年夏天发，结果后期到秋天，哈哈哈\n好喜欢歌曲和舞蹈中那个喝水的动作，感觉这就是夏天吨吨吨喝饮料的爽快的感觉！就是美好的夏天！\n翻了粉扑扑改编的版本，特别喜欢的一个版本！冬天学完在今年的4月底去厦门拍了这个视频，四月底五月初的厦门太阳是真的明媚又强烈呀～晒了整整一天，整个人都晒黑一圈，从清晨到日落的一次约会，这次大家能看的过瘾吗！这次也是全程日常装过了个瘾，自己也构思着想给大家看到一个从小到大，从稚嫩到成', 3414458, 147107, -1, 10748, 7879, 55053, 85834, 4353, '2020-8-29 04:30:26', 565, 1, '2025-8-28 09:46:06', 0.00516424, -0.636785);
