INSERT INTO `videoinfo` VALUES ('BV16N411f7Ld', '502955403', '138832847', '点进来之前没想到这么好看，汉子案子都有的悬疑甜宠《御赐小仵作》安利【哇妹】', '它让我看到了悬疑甜宠剧的市场，谁说两者不能兼得的呀！悬疑做得尊重智商，甜宠部分不工业糖精。\n现在大IP扑街率高，反而这种小成本网剧能杀出重围，\n大IP流量剧，明星片酬占了大比重，但投资终究有限，自然就要从其他方面减少费用，所以我们看到这些剧的质量自然也就差很多了。小成本网剧，演员不出名，但是咱们把钱花在刀刃上，找一个靠谱的编剧，在剧情的加持之下，主角们的演技也不尴尬能用，就够了，没有乱七八糟的加戏注水，有时候反而还能给人带来惊喜。', 1523285, 73158, -1, 10734, 8607, 7090, 20776, 3806, '2021-5-7 13:11:56', 761, 1, '2025-8-28 09:46:06', 0.0050649, -0.646262);
