INSERT INTO `videoinfo` VALUES ('BV16t411M7oz', '62354643', '98608863', '如何看出女生在拒绝你？听听直男之光的回答', '「绝对是个妞」是个带着女性视角看世界的媒体。我希望它能从日常生活到公共议题给更多女性带来启发，给我们每个人更多勇气，去做一个真实、独立和自由的 New Girl.\n\n这个项目的第一期视频节目，我请来直男聊了聊「性知情同意」。\n\n总会有女生在吃亏之后被人问，「是不是你的拒绝不够明确？」「是不是你给了别人什么错误的信号？」这些问题问到最后，女生也懵了。\n\n到底哪些信号代表「同意」？哪些信号代表「拒绝」？是不是男女对此的解读就不太一样？于是我们找来 3 位直男朋友，请他们给出自己的答案。', 85753, 8380, -1, 1412, 769, 1821, 4526, 332, '2019-8-5 12:12:22', 679, 1, '2025-8-28 09:46:06', 0.0115379, -0.0287157);
