INSERT INTO `videoinfo` VALUES ('BV16TfLY8ETx', '113878037959192', '2920960', '1.8斤潮州大响螺1500元一只到底是不是智商税？！', '店名：郑厨私房菜    位置：广东省潮州市湘桥区太平街道上东平路附近\n\n噱头大于实际的一家店，菜的出品味道上都还不错（但对于那么多奖，又厨师世家，各种BUFF来说，真没觉得多惊艳和与众不同），然后摆盘像20年前酒楼的审美。环境很一般，服务的话可能因为文化差异，交流起来有点费劲。。。然后响螺和红花蟹怎么说呢，味道口感到底对不对的起这个价格仁者见仁智者见智吧！我尝过后绝对不会舍得再吃第二次。\n\n推荐指数个人向：★★★\n★★★★★（如果条件允许每月都会忍不住吃一两次） \n★★★★（有第二次去的冲动，也有推荐朋友', 648816, 32269, -1, 534, 1058, 2008, 10911, 535, '2025-2-7 10:06:54', 673, 1, '2025-8-28 09:46:06', 0.00599239, -0.557777);
