INSERT INTO `videoinfo` VALUES ('BV16U4y1h7KL', '672577340', '116683', '【咬人猫】你的猫生气了！会 咬 人！❤️ Hmph！', '大家疯狂被洗脑的时候我感觉还好，万万没想到越听越上头，我也还是没有逃脱“生气”的宿命，这次的舞很乖很可爱，学舞的过程很快乐，没想到录舞的时候居然真的快生气了，哈哈哈哈，各种运气不好，第一天状态还不够好，第二天袜子又挂丝破了，最后这个舞录了三天才完成，但是最终录制完真的非常的开心，也希望大家如果看到我开心，我才会不生气了！\n舞蹈/音乐：宇宙少女CHOCOME小分队《Hmph!》', 4357058, 151679, -1, 12427, 4180, 69285, 73130, 3267, '2021-4-16 11:00:16', 202, 1, '2025-8-28 09:46:06', 0.00999583, -0.175834);
