INSERT INTO `videoinfo` VALUES ('BV16x411M7T5', '15572523', '116683', '【咬人猫】小埋体操❤干物妹小埋R！原创改编舞蹈o(*≧▽≦)ツ', '创作类型: 原创\n简介: 小埋第二季开播啦！很多人推荐，我也一听到ed就激动有了想自己编舞的想法，很长时间没有尝试过编舞，上一次编舞还是是雪月花和伪物语的时候，所以心里也很忐忑能不能编出小埋的感觉。于是接下来开始每天不停的尝试，加上ed里面有的很多原动作，自己也根据自己的理解做了部分的改变，录制时也在不停的小优化，一只一分钟的舞蹈一眨眼居然就熬过了一个通宵，最终才有了现在的版本。编舞方面我还有很多不足，只希望能通过看似简单的舞蹈传达出欢乐的感觉，就像我最初喜欢上宅舞的感觉一样，也许不复杂，但是让人很快乐，', 7929892, 79647, -1, 52391, 17431, 110988, 221394, 11274, '2017-10-20 16:35:51', 123, 1, '2025-8-28 09:46:06', 0.0111966, -0.0612763);
