INSERT INTO `videoinfo` VALUES ('BV17c411o7oo', '279985250', '98608863', '5 个妙计 1 个神器，助您抗拖延成功', '你会有拖延的时候吗？\n纠结、逃避、焦虑、内耗、放弃，然后或自我责备，或认命摆烂。\n在这个满是 P 人的「绝对是个妞」团队里，这样的循环不断上演。\n我作为，团队里唯一的 J 人，完全无法理解躺着的乐趣，无法同理「拖延」的快感。所以我在翰文提出「拖延症」这个选题又拖了一年之后，我拉着他一起强制执行，带领团队一起战拖。\n经过一个月的治疗，我们决定在今天正式推出大型纪录片，勇气弹抗拖实录，同时也为献上抗拖宝箱，其中五个锦囊妙计加一个专注神器，助您抗拖成功。', 32206, 2454, -1, 173, 291, 670, 1016, 131, '2023-12-18 10:20:00', 899, 1, '2025-8-28 09:46:06', 0.00501827, -0.650711);
