INSERT INTO `videoinfo` VALUES ('BV17d4y1b76Q', '390128983', '2374194', '【指弹古筝】无题 - 真·人均国风指弹经典', '相信陈亮老师的这首《无题》是很多指弹人的入坑之作，我自然也不可能放过这么一首国风神曲。原作最突出的是其优美动人的旋律，层次分明的情绪和恰到好处的技巧运用。在移植的过程中我也尝试一些古筝新技巧，过程属于是苦不堪言，而且最终效果有待提升。最后要感谢元子老师的教程，刚开始看第一集讲解满屏的“学成归来”，现在我做终于也偷摸发了一条！哈哈哈哈哈～\n\n原曲：无题\n古筝改编/演奏：墨韵随步摇 \n古筝录音/混音：刘嘉伦 \n统筹：雁子\n拍摄/剪辑：朱航\n拍摄助理：张婕', 464888, 29166, -1, 6685, 1373, 10811, 22708, 1049, '2022-11-18 09:05:00', 332, 1, '2025-8-28 09:46:06', 0.00836589, -0.331337);
