INSERT INTO `videoinfo` VALUES ('BV17J411N7zn', '67629271', '2374194', '【墨韵】临安小记（筝/小提琴）-《食物语》江南印象曲', '大家中秋快乐！现在大家的餐桌越发丰富，各种风味都能融合，而这次的《临安小记》中，我和骚老师一起尝试了古筝与小提琴的融合，看看有没有奇妙的化学反应呢？\n听着这首曲子，我想起曾吃过的杭州灵隐寺素面。坐在灵隐面馆的木凳上，捧着由各种蔬菜和菌菇做成的面，菜蔬的清新和面食的鲜香扑鼻而来，再喝一口汤，满口都是江南美食那种鲜美的味道啦！你的江南印象美食是什么？一起听曲回味吧！\n\n原唱：西瓜JUN\n作词：贰哲                            \n作曲：Winky诗                   ', 406593, 30388, -1, 1444, 2481, 8969, 18933, 1546, '2019-9-13 14:36:16', 240, 1, '2025-8-28 09:46:06', 0.009751, -0.199192);
