INSERT INTO `videoinfo` VALUES ('BV17s411S7dr', '2582803', '116683', '【咬人猫X咬人喵】Lamb.我的姐姐终于藏不住了！', '这次和姐妹咬人喵？给大家带来的是我喜欢了很久的LAMB.记得一年多前第一次看这支舞，我就打了鸡血一般的挖下了这个坑，然而我大概最不擅长的也是这类舞蹈，只能多尝试练习，这样一过就是一年多，因为自己能力的关系，还有很多不够好的地方，非常抱歉。服装部分参考了动漫角色自己扯了布料经过小改动做的，想尝试让两边的角色能有两种不同感觉传达出来，更多的话我会打在评论里，谢谢大家的支持\r\n编舞：sm22013530\r\n', 10193508, 51119, -1, 37572, 43721, 159120, 170319, 12502, '2015-7-16 12:47:53', 248, 1, '2025-8-28 09:46:06', 0.00603315, -0.553888);
