INSERT INTO `videoinfo` VALUES ('BV17t4y1h7qm', '982519969', '138832847', '央视出手9.4分，这部续作简直良心！纪录片《人生第二次》安利【哇妹】', '总的来说，《人生第二次》是非常真实、深刻、有笑有泪的一部纪录片。\n就像它的主题曲《推开世界的门》，推开纪录片的门，看到更多样的人物和人生\n相比起第一季《人生第一次》，第二季多了很多沉甸甸的情绪和思考\n纪录片拍下了每个人面对困境时的信念和勇气\n他们那种抗争，那种顽强，那种命运感，非常动人！有感染力\n正如导演在长评中写道：希望每个看完影片的人，都能从他们的经历里，感受到生活的信念。\n希望每个人在遇到生活的困难时，都能有不被打倒的勇气！', 814464, 24272, -1, 1747, 831, 1228, 6049, 431, '2022-6-15 11:58:19', 545, 1, '2025-8-28 09:46:06', 0.00318249, -0.825852);
