INSERT INTO `videoinfo` VALUES ('BV18F411j7Y6', '298873632', '138832847', '为什么现在单身女性越来越多了，五个女性的纪录片《炼爱》解说【哇妹】', '《炼爱》选了5个不同行业的在北京生活的女性，年龄大概是在28到40岁之间。这部挺有意思，没有大家对纪录片沉闷无聊的刻板印象，是轻松幽默的，听说很多观众在看这部电影的时候哈哈大笑，也不是那种苦大仇恨的我们女人就是恨嫁的那种，是一个相对的中立的态度，展现了现代女性的婚育现状。一个女生，有不错的工作，有了点钱，女性经济地位上升了，但是传统的社会观念依旧还是会把她们扯回来，女性都在现代和传统之间狠狠拉扯，目前来看这是一个无解的问题。', 609639, 27516, -1, 2884, 5567, 2785, 4681, 2139, '2022-5-6 08:40:28', 656, 1, '2025-8-28 09:46:06', 0.00710839, -0.451306);
