INSERT INTO `videoinfo` VALUES ('BV18k4y1k7MZ', '753100463', '2374194', '【古筝】当潮不让 - 意识流古筝rap', '原曲《当潮不让》  作曲：GAI周延\n虽然我很喜欢Gai爷，但是听到这首曲子的时候我傻了。年轻的我没有经受过风雨的洗礼，不知道这种曲风翻奏起来是这样的折磨2333 \nRap作为一种强调词和节奏的语言艺术，和古筝这种强调旋律的乐器乍看之下似乎并无交集。但好处是伴奏没有繁复配器，一个干净有力的beat可以给旋律很多发挥的空间。而重点就是要自由，要随性，要意识流！\n改编的过程非常曲折，跳出了原本的旋律之后我只能一边一边地跟着节奏即兴弹，最后把还不错的选段连在一起。业余选手空前绝后乐感大挑战！！希望大家喜欢吧～\n', 272062, 31884, -1, 1467, 1570, 7287, 17514, 1163, '2020-5-8 10:00:07', 219, 1, '2025-8-28 09:46:06', 0.00820479, -0.346706);
