INSERT INTO `videoinfo` VALUES ('BV19E411j7JC', '93182643', '98608863', '我们 50 岁时长啥样？反正不会是你以为的那样！', '你怕变老吗？我对变老虽然没有特别怕，但也确实没有很期待，直到之前看到 Jennifer Lopez 在超级碗的表演。\n亮片紧身衣、钢管舞、旋转跳跃倒挂，每个细节都完成得流畅自然，如果不是当时下面的评论提醒：「这是 50 岁吗？」、「我完全无法相信她 50 岁了！」我也无法把 JLo 和惯性思维中认定的 50 岁联系起来。\n那 50 岁有「应该」的样子吗？如果有，是谁规定的？奥普拉说 Jlo 让全世界重新认识 50 岁，那大家看完这个视频也来跟我说说，你想过 50 岁是什么样子的吗？', 46616, 3913, -1, 307, 253, 481, 1217, 129, '2020-3-2 16:22:06', 284, 1, '2025-8-28 09:46:06', 0.0040779, -0.740426);
