INSERT INTO `videoinfo` VALUES ('BV19G411H7ha', '428351896', '98608863', '堕胎之后，我的身体又完整了', '6月24日，美国最高法院推翻了罗伊诉韦德案。\n在这段时间里，很多评论和私信都在让我讲一讲罗伊诉韦德案。\n对于这个选题，我有点慎重，因为我们无法把它当做一场辩论，这涉及的是女性身体的归属，这其中的选择对个体是一生的影响。\n所以，我还是想要去讲述个体的故事，通过我和两位嘉宾的故事去理解我们为什么要堕胎。', 1799780, 105358, -1, 47332, 12690, 30486, 66589, 6551, '2022-7-11 14:43:35', 925, 1, '2025-8-28 09:46:06', 0.0220226, 0.971562);
