INSERT INTO `videoinfo` VALUES ('BV19p4y1b7pR', '972325754', '98608863', '胖女孩健身：痛苦、笨重、难看，运动会属于我？？', '对于胖女孩，不运动会被说「不上进」，可是开始运动也很难：「我动起来像只狗熊」，以及最重要的「工作已经很累了，我只想休息一下」。菲菲就是一位胖女孩，她的运动之路不是看不到尽头，而是根本看不到路在哪。我为她设计了一个体验计划，却发现其实不仅是我带着她去了解运动，她也带着我了解胖女孩面对运动时最真实的想法。\n媒体和网络总是展现女性「美丽地享受运动」的画面，但我相信「胖女孩」关于运动的真实想法也同样有意义。你觉得你是「胖女孩」吗？你有关于运动的顾虑吗？你喜欢运动吗？', 227808, 15038, -1, 1057, 4582, 3605, 10129, 858, '2021-3-30 14:19:43', 944, 1, '2025-8-28 09:46:06', 0.00960938, -0.212703);
INSERT INTO `videoinfo` VALUES ('BV19Q4y1n7sR', '705667150', '116683', '萝莉神，但是书记舞！❤️ 【咬人猫】', '没错！我也被萝莉神洗脑了，这支舞刚出来我就被吸引了，上次跳这么魔性洗脑的舞已经是上一次了！于是立马放下所有的安排，开始萝莉神的安魂曲！但是！看似很简单也很短的舞，要常速跳下来，真的比想象中难度大太多，陆陆续续练习了一个月才终于有相对满意的效果！\n\n突发奇想， 用了跳书记舞的服装跳“萝莉神”，感觉意外的很合适呢！\n\n音乐/舞蹈参考：BV1sH4y1D79p', 2693456, 168450, -1, 3419, 306, 34772, 21291, 1303, '2023-11-10 11:00:00', 16, 1, '2025-8-28 09:46:06', 0.00267249, -0.874507);
