INSERT INTO `videoinfo` VALUES ('BV1Ag411G7XP', '503415973', '98608863', '母乳自由｜乳房长在她身上，请让她自己做主', '母乳，是一件太关乎于个人身体和心理的体验，对于没有母乳经验的人来说，它太难以想象了。而母乳，又是一个公众的议题，关于社会对母职的理解，关于身体的边界，关于个体的选择，它需要一遍遍被言说。于是这次，我请来 5 位母乳妈妈，来和我一起来更详细地、更具体地来分享自己的母乳体验，和我们想要的母乳自由究竟是什么。', 79908, 7220, -1, 501, 253, 756, 1977, 227, '2021-6-4 12:30:14', 709, 1, '2025-8-28 09:46:06', 0.0116608, -0.0169883);
