INSERT INTO `videoinfo` VALUES ('BV1aN411j7Ap', '494401579', '98608863', '如果我小时候有这些绘本，我可能会更爱阅读', '我喜欢的绘本一般是三个类型，一类是美的，它们的画风会很有想象力，让你觉得就像是艺术作品，眼睛进入到了多彩的世界，身体也就跟着放松了下来。另一类是有用的，它们会呈现自然，会呈现逻辑，会呈现一种价值观，但它们都是在用一种「童趣」的方式去引导着孩子们自己的思考。还有一类是，经典作品的创新，无论是装帧设计上的创新还是互动内容的创新，都会给人一种很想要去收藏的感觉。\n\n绘本这种简单的方式反而会提醒你那些最朴素的道理，也会让孩子被温暖的爱包裹着。我希望小孩子们的阅读都可以从感受「爱」开始。', 25247, 1736, -1, 192, 74, 845, 573, 69, '2023-12-7 11:00:00', 697, 1, '2025-8-28 09:46:06', 0, -1.12947);
