INSERT INTO `videoinfo` VALUES ('BV1au4y1477B', '916500608', '116683', '【咬人猫】月白❤️ 原创单曲！ 我在等月，也在等你...', '中国的色系列的第三支单曲《月白》终于在这个中秋和大家见面啦！最早制作《月白》的时候就觉得它是很适合中秋的一首歌，于是MV版本大家看到的就是嫦娥和小玉兔的日常画面啦，这个中秋她们也来凑热闹过过节！月夜、池塘、虫鸣都在这首甜甜的《月白》里面啦～真的很喜欢夜风拂面的那种安宁又清新的感觉，仿佛全世界只剩下此刻各种奇思妙想飞到天空的我～今夜用这首歌“与你，明月传语，相遇”，千里万里都能相遇❤️《月白》的舞蹈版也在紧锣密鼓地制作中，会尽快和大家见面的～\n\n拍摄：感谢知竹工作室的全体工作人员！\n导演：小莎莎莎同学\n作曲', 1541959, 94933, -1, 2189, 564, 15666, 19868, 1595, '2023-9-29 11:00:00', 216, 1, '2025-8-28 09:46:06', 0.00443111, -0.706728);
