INSERT INTO `videoinfo` VALUES ('BV1Ax411a72W', '11022534', '116683', '【咬人猫】Love Me If You Can❤o(*≧▽≦)ツ', '这次尝试了挑战帅气性感的舞，舞蹈的部分是越练习越觉得难，越去在意细节越喜欢aty两位w,也更能发现自己的不足，总之在舞蹈上我还需要继续努力！希望可以让看视频的大家看的开心w也希望未来，自己可以更游刃有余的跳出这种类舞洒脱的感觉～\n服装是根据碧蓝航线里面很喜欢的亚利桑那的人设，根据舞蹈做过小改动然后自己去找裁缝做的～特别喜欢那顶小帽帽(⁎⁍̴̛ᴗ⁍̴̛⁎)\n参考舞蹈：sm27980070 音源：sm25892554', 7367895, 61387, -1, 24406, 16983, 89091, 157238, 10930, '2017-6-2 16:00:46', 214, 1, '2025-8-28 09:46:06', 0.00864081, -0.305108);
