INSERT INTO `videoinfo` VALUES ('BV1bb421H7VF', '1805744209', '520819684', '一口气了解新加坡经济', '新加坡可以说是全球数一数二的小国，而它的人均GDP在2022年达到了12.8万美元，全球第二。\n短短60年间，国父李光耀真的就像打游戏一样，一路过关斩将，而且更神奇的是，他的打法还有些离经叛道，一路梭哈一路赢，把一个支离破碎的国家带成了全球最有钱的国家之一。\n今天我们就来说说这个神奇的小国 -- 新加坡！', 2962953, 109901, -1, 19559, 22143, 29401, 61583, 5731, '2024-6-7 09:32:04', 1755, 1, '2025-8-28 09:46:06', 0.00493743, -0.658424);
