INSERT INTO `videoinfo` VALUES ('BV1BB4NeiEvC', '113234161963809', '2920960', '只要我不说话，就没人知道我是男的！！！', '店名：宴三里 位置：北京市朝阳区三里屯北小街附近\n \n这家餐厅我觉得如果作为商务宴请真算是有性价比的，但纯为了美食来吃的话就没啥性价比和必要了。另外鲍鱼难吃但因为拍视频+女装缘故没有要求餐厅换菜（当时只想赶紧吃完走人），看某点评这家餐厅的说法是，如果有不满意的菜可以直接要求免费换菜，这点如果能做到那也还可以了。\n\n推荐指数个人向：★★★\n★★★★★（如果条件允许每月都会忍不住吃一两次）\n★★★★（有第二次去的冲动，也有推荐朋友去吃的想法） \n★★★（还不错，但暂时没有再去的想法）√ \n★★（个人不喜欢，因', 907598, 146509, -1, 8918, 7875, 17362, 126234, 4569, '2024-10-4 10:00:00', 635, 1, '2025-8-28 09:46:06', 0.0132174, 0.131516);
