INSERT INTO `videoinfo` VALUES ('BV1bJ411X7nN', '77166462', '116683', '【咬人猫】芒种 ❤️ 一想到你我就……', '芒种这首歌刚发布就很喜欢，还没有编舞的时候就开始准备，前前后后一共学了、编了三个版本，一直在寻找最想要的感觉，要感谢白小白老师的编舞，很喜欢动作里面和歌曲契合的节奏感，我也结合自己的想法和想传递的感觉，做了一些小调整～尽可能想跳出一个仙仙柔柔的芒种，也是我对这首歌的一点自己的理解～幻想在一个如仙境一般美丽的地方，住着一个在讲述自己美丽的爱情故事的仙子～服装也是按这样的想法去制作，希望大家能够喜欢～在美丽的风景，让我们一起享受它的美好吧～\n音乐：芒种 av64186665\n编舞：白小白 av66896179', 4678114, 131656, -1, 15560, 7412, 60084, 98770, 4673, '2019-11-29 11:00:58', 222, 1, '2025-8-28 09:46:06', 0.0118684, 0.00281546);
