INSERT INTO `videoinfo` VALUES ('BV1BK411g71o', '500863368', '2374194', '【墨韵】梦·飞天——莫高窟印象曲', '本视频得到梅赛德斯-奔驰星愿基金及敦煌研究院的大力支持\n \n延人文之道，探文脉相承。\n自2019年起，梅赛德斯-奔驰星愿基金连续2年携手敦煌研究院，开启敦煌莫高窟文化遗产保护和文化教育扶贫项目，做当代“供养人”。以守护文化遗产为初衷，星愿基金重点支持莫高窟第285、428、158、323窟的保护工作；着眼 “下一代”文化传承，探索少年儿童美育，挖掘多元创新的敦煌文化及“莫高精神”。\n \n古筝演奏：墨韵随步摇\n制作人：胡多多\n导演：天浩\n作曲&编曲：包达\n录音&混音：刘嘉伦\n摄影&剪辑：余林峰 \n化妆造型：', 210017, 20438, -1, 1263, 599, 5023, 8916, 494, '2020-12-25 08:00:15', 256, 1, '2025-8-28 09:46:06', 0.00301623, -0.841713);
