INSERT INTO `videoinfo` VALUES ('BV1BP3CzfEcC', '114810213700379', '26798384', '别再问我什么是AI：10分钟速通AI黑话，让草履虫也能看懂AI新闻【柴知道】', '在最近这两年，你可能每天都被各种 AI 新闻迎面轰炸。你可能也查过这些不明觉厉的名词，但由于缺乏配套的知识体系，往往问了也似懂非懂，下次看到又不知道在说什么了～在这期视频里，我们会跟你一起，努力在头脑中建立一个能串联起常见 AI 名词的基本框架。用大约 10 分钟时间，给常见的 AI 名词找到合适的位置，帮你真的看懂 AI 新闻～', 348369, 9946, -1, 576, 619, 4770, 7115, 271, '2025-7-7 09:30:00', 787, 1, '2025-8-28 09:46:06', 0, -1.12947);
