INSERT INTO `videoinfo` VALUES ('BV1bS4y1K7xT', '682877994', '11799651', '古代中国，为何会失去对越南的统治？【世界观察】', '从秦朝开始一直到唐朝，越南都是中华帝国的一部分。然而，在宋朝时越南却独立了。除了明朝时，曾经短暂收复过22年，再剩下的九百多年里，中华帝国就再也没有重新统治越南。所以，为什么越南能独立？而它独立之后，又为什么没被重新收复？越南真的很强吗？今天，我们就来好好聊聊这个问题。', 1609553, 41534, -1, 1886, 9415, 10320, 4792, 5938, '2022-4-4 13:10:59', 936, 1, '2025-8-28 09:46:06', 0.00692169, -0.469118);
