INSERT INTO `videoinfo` VALUES ('BV1bt41187Vx', '41250792', '26798384', '为啥女生越没钱，越要买口红？', '从上世纪二三十年代开始，人们逐渐观察到这样一种现象：在经济衰退时期，一般各行各业的销售额都会下跌，但以口红为代表的个护美妆行业却能不退反进，笑傲江湖。这就是所谓的“口红效应”——人越穷，越要买口红。 那到底为什么人们对口红如此执着？其实这可能跟经济衰退时期的消费心理息息相关。\n\n视频内容更多是为了介绍“口红效应”所阐释的社会趋势，并不针对任何个体或群体。', 151478, 4095, -1, 1167, 783, 1574, 1676, 863, '2019-1-20 14:53:21', 249, 1, '2025-8-28 09:46:06', 0.00772781, -0.392212);
