INSERT INTO `videoinfo` VALUES ('BV1bV411q7qC', '416334953', '2374194', '【墨韵】《梦开元》正式版MV，想象大唐盛世的模样！', '很高兴收到了来自拜年纪的邀请，担任2021新春拜年官~\n\n这次投稿的作品《梦开元》，在2019年4月的“华服日”现场演奏并且跟团团联合投稿后，也陆续表演过很多次，不过一直没做正式版的MV。时过近一年，终于可以作为拜年官的新年礼物呈现给大家！\n\n《梦开元》的创作想法很简单，就是描绘大唐开元盛世。大唐，这个当时世界上最强盛的王朝，她文化开放包容，经济繁盛昌盛，她是生机勃勃的时代，她是人才辈出的时代，她是凝聚了无数中华儿女对于盛世的全部想象的时代。 听《梦开元》，聆听每一个炎黄子孙对于华夏民族强盛的声声期盼。\n', 482039, 40535, -1, 1924, 1399, 13543, 18826, 908, '2021-1-21 10:57:32', 321, 1, '2025-8-28 09:46:06', 0.00647354, -0.511873);
