INSERT INTO `videoinfo` VALUES ('BV1BV411t7Ln', '416178797', '26798384', '【柴知道×必胜】如何科学地洗狗？为什么洗狗频率不能过高？', '猫可以宅在家里，但狗狗需要每天出门遛，有可能沾上各种脏东西。但问题，如果天天洗澡，人受不了，狗也受不了。狗狗身上的异味是哪来的？为什么洗狗频率不能过高？除了洗澡外，还有什么更好的清洁狗狗的方法？柴知道和必胜一起，为你解答这些问题~', 96984, 8781, -1, 625, 611, 875, 1672, 443, '2021-1-19 10:00:13', 284, 1, '2025-8-28 09:46:06', 0.013379, 0.146935);
INSERT INTO `videoinfo` VALUES ('BV1BV411z7Fc', '414098990', '138832847', '《三十而已》：为什么姐姐们这么美这么好，老公还不珍惜？【哇妹】', '这部剧好的一点是，什么都会辜负你，但是工作不会，\n首先我们应该做的是，努力去工作，实现经济独立，不为别的，为自己挣一份未来的保障。\n其次，爱情不是生活的全部。在感情婚姻上的问题，可以合理自省，但是没必要过渡自我贬低。\n我们要做自己的爽剧女主。', 676308, 37737, -1, 1275, 5929, 2117, 4299, 2006, '2020-8-2 08:49:54', 710, 1, '2025-8-28 09:46:06', 0.0237199, 1.13349);
