INSERT INTO `videoinfo` VALUES ('BV1BWxse9E2G', '113225756577817', '26798384', '制霸表情包！GIF是如何成为梗图之王的？【柴知道】', '说到GIF，那可真是互联网的灵魂～有时候你甚至不需要打字，一个生动、传神的表情包，就能精准无误地瞬间传达你的意思。但你也许不知道，GIF 的诞生之初只是为了方便压缩图片，之后却凭借它独特的多帧动画功能，剑走偏锋，坐着互联网的顺风车，成为了梗图之王。这背后有哪些不为人知的商业故事？从图片压缩到梗图之王，GIF 是如何被玩坏的？', 532277, 23110, -1, 267, 613, 6421, 2847, 533, '2024-10-9 09:30:00', 496, 1, '2025-8-28 09:46:06', 0.00413215, -0.73525);
INSERT INTO `videoinfo` VALUES ('BV1bx411F7Mb', '343479', '116683', '【咬人猫×③】幻想嘉年华OP★量产喵的第十三作舞蹈~喵', '原创 构思了很久的一作，想尝试一点有趣的风格，事实证明完全没有估计到两个球的惯性~所以根本没有同步率可言了%>_<%完全没有肉肉元气的感觉。大家能欢乐的看看就好啦。迟到的七夕祝福还没有脱团的大家明年的今天一定能搂着最爱的基友幸福的生活！ 感谢chiroro的编舞和在大洋彼岸都要被喵酱折磨到凌晨在电脑前睡着的晗小喵同学的后期和压制。 微博传送门： 喵酱：http://weibo.com/momonecat', 377938, 1823, -1, 964, 1869, 2478, 1632, 953, '2012-8-24 04:23:54', 109, 1, '2025-8-28 09:46:06', 0.00975662, -0.198656);
