INSERT INTO `videoinfo` VALUES ('BV1bx411K7a9', '1515377', '116683', '【咬人猫X小缘喵】神的随波逐流❤更新P2啦(*≧▽≦)ツ', '看到弹幕，也好奇去听了小缘的翻唱~觉得真的好棒！于是没有理由不合体呢？小缘也马上爽快的答应~好开心！于是愉快的更新P2啦~这支舞是想到即将要去日本旅行，决定要找到一个合适的景完成这只舞。想象中的背景是要有鸟居的，就去了稻荷神社。当天长途跋涉，体力有限，刘海也湿透了，顶着假刘海录完整只舞，不足之处请多包涵。谢谢陪着我一起找景的小伙伴们。振付本家:sm23638553 音源本家:sm22831329。', 3670750, 19928, -1, 17538, 16114, 51557, 29381, 2683, '2014-9-9 03:56:07', 518, 1, '2025-8-28 09:46:06', 0.00402093, -0.745861);
