INSERT INTO `videoinfo` VALUES ('BV1Bx411s7bo', '14494920', '2374194', '【古筝】九九八十一  墨韵随步摇 ft. 闫东炜', '本家av3905462，原曲卡司内详。这次有幸邀到闫东炜做了一版“魔改伴奏”，而引子依旧保留了原曲打击乐（实录：司鼓君）。看了团团子的琵琶版（av6217685）之后，觉得这曲子之于民乐改编来说潜力无限，因此尽管众多珠玉在前，还是想出一个“墨韵第三号练习曲”。为了有别于权御的框架，我从去年秋就开始琢磨改编，并加入了左手轮指、单手泛音等前作中没有的指法，以及一段没有逻辑的快速指序。感谢与我有深厚革命友谊的Katze和我一起做脸谱面具，一魔一佛，齐天大圣，地上行者。另，这次的筝是向陶嘚嘚借的，牌子是中州。', 3615362, 93477, -1, 34675, 38891, 96954, 227556, 20804, '2017-9-15 17:31:21', 300, 1, '2025-8-28 09:46:06', 0.00936064, -0.236434);
