INSERT INTO `videoinfo` VALUES ('BV1bZ4y1o7Us', '381334781', '11799651', '中国为什么总是产能过剩？【中国观察】', '几乎所有人在说到中国的产能过剩问题时，第一反应都是去产能。好像我们只要把低端工厂都给关了，那工人就会自动找到条件更好的岗位，释放的资金就能自动去做产业升级，而积累的技术就能自动互联网化。真是异想天开！哪来那么多好岗位？谁有钱了会去投实体？连人都没了，积累的技术就不会消失吗？', 927270, 32466, -1, 927, 2833, 6130, 3149, 2160, '2022-2-6 09:30:07', 522, 1, '2025-8-28 09:46:06', 0.00769349, -0.395485);
