INSERT INTO `videoinfo` VALUES ('BV1C44y1v7Ru', '976267416', '11799651', '为了一口饱饭，我们跟蝗虫斗争了上千年【中国观察】', '三国时代，可能是中国人最熟悉的时代之一了。然而，从某种意义上来说，打开三国时代的那个敲门砖，却是蝗灾。我们为了一口饱饭，跟蝗虫斗争了上千年。而看视频的各位，在你从小到大的记忆中，亲历过大型蝗灾吗？', 388016, 20663, -1, 437, 2081, 3061, 3786, 621, '2021-10-26 10:00:13', 953, 1, '2025-8-28 09:46:06', 0.0169833, 0.490799);
