INSERT INTO `videoinfo` VALUES ('BV1cB4y1W7Uf', '600388752', '98608863', '仙女变拽姐，酷妹变宝妈｜和姐妹一起想当年', '这个月，很多毕业生都要准备进入社会，面对职场和生活中「风起云涌」的变化，我们多少有些忐忑。\n\n我邀请了我的两位好朋友﻿@蒯仔kkweekly﻿ ﻿@王小猴小猴﻿ ，一起来聊一聊毕业十几年之后，看看我们究竟发生了哪些变化。你会发现我们失过业、当了妈、被潮流洗过脑，也被现实教过做人。但我们没有「被生活磨平棱角」，也没有失去「最初的梦想」，我们还是当初那个被自己喜欢的人。\n\n以不变应万变，就是我们对待变化的态度。', 70832, 3952, -1, 117, 317, 349, 1016, 62, '2022-6-30 10:00:22', 893, 1, '2025-8-28 09:46:06', 0.0100527, -0.170407);
