INSERT INTO `videoinfo` VALUES ('BV1CQ5QzzEU3', '114381002121138', '98608863', '我一定要原谅父母嘛？', '“你不一定要原谅他们，但你可以选择照顾你自己。”\n\n最近，我采访了在斯坦福大学MBA教授宇宙名课《深度关系》的Ling，林轶凌老师。\n在这期节目里面，我想邀请你一起来抱抱那个「小小的自己」。\n\n原生家庭带来的不是永恒的枷锁，而是一种理解的入口。理解为何我们总是流泪、为何总是想逃、为何亲密关系总在相互拉扯中崩解。\n疗愈意味着，你终于可以在当下，对那个从未被保护过的自己，说一句：“我在，我懂你，我会来爱你。”\n我们并不是在寻找一种和解，而是试着打开另一个可能—— 不再用“压抑”来生存，而是慢慢学会，与那个一直', 23969, 1143, -1, 185, 40, 536, 364, 27, '2025-4-22 11:25:54', 919, 1, '2025-8-28 09:46:06', 0, -1.12947);
