INSERT INTO `videoinfo` VALUES ('BV1cS4y117GJ', '723724788', '2374194', '【墨韵X南一】除夕在CCTV-1《古韵新春》演出《高山流水》', '很荣幸收到《古韵新春》节目组的邀请 ！在除夕这天下午的CCTV-1播出我和南一先生、罗昱文老师（北京歌剧舞剧院） 共同带来的创意演出《高山流水》。\n说来也有意思，能够得来这次机会，是因为之前在各大平台发布的《知音》（改编自《流水知音》）的视频被细心的节目组导演看到了，觉得很适合这次古韵的主题于是联系了我们。当时是在节目录制前一周，时间很紧张。所以在当晚我们就迅速商议和调整演出方案。尽管准备的时间不多，但节目组导演们对这个节目的每个细节都严格把控，大家都希望在除夕这天给电视机前广大的观众带来一场好的演出，传', 252488, 18782, -1, 1364, 416, 3964, 4383, 559, '2022-1-31 15:02:59', 202, 1, '2025-8-28 09:46:06', 0.00508612, -0.644238);
