INSERT INTO `videoinfo` VALUES ('BV1Cx411e7kZ', '10501369', '116683', '【咬人猫】虫奉行❤明年也一起去看樱花吧o(*≧▽≦)ツ', '一直想有机会可以在樱花季穿着振袖和服在樱吹雪里跳舞！，这支舞也计划了好几年的时间，终于在今年的樱花季能如愿以偿，很幸运的抓住了今年满开花期仅有的两日晴天，换了两套振袖，穿梭于两个城市，想尽可能取到更多的景色，更希望将眼前的美景通过舞蹈一并带给大家，剪辑也想用倒叙的感觉，从夜晚到清晨再到阳光的午后变化，想带给大家一个越来越明亮的心境，特别喜欢爱川这支舞配合服装带来的感觉，也希望也许并不复杂的舞蹈也能传递给大家一份开心！\n音乐：ハルウララ・モモラルラ\n参考舞蹈 爱川梢 nico：1368437279', 2344682, 15677, -1, 16219, 14605, 45868, 111780, 7869, '2017-5-12 10:02:11', 775, 1, '2025-8-28 09:46:06', 0.00503678, -0.648946);
