INSERT INTO `videoinfo` VALUES ('BV1d6XVYqEm4', '114182359882197', '98608863', '我是不是一个不太好玩的人', '想做一个恣意洒脱的人，行动背后不是目标，而是体验；想成为一个欢脱跳跃的人，人生价值不是量化的评价，而是尊重内心。还无法做到松弛地面对这个世界，但我可以「用力」地去打破游戏规则。还没有办法胡闹地游戏人间，但我可以「认真」地去创造我的游戏\n\n感谢观夏每年三月通过文学、艺术和香气，和更多的女性创作者站在一起，呈现给我们多元的、自由、开阔的想象。让我们在这一刻放松下来，和这么多“好玩儿”的她们一起，从“一生用功”的规训里抽离出来，探讨玩的无数种可能性。', 25008, 890, -1, 11, 28, 166, 167, 23, '2025-3-18 12:40:00', 516, 1, '2025-8-28 09:46:06', 0.0101877, -0.157529);
