INSERT INTO `videoinfo` VALUES ('BV1d74y127GP', '1006661143', '26798384', '“真实续航”=“标称续航”打5折？新能源车为什么总是“续航虚标”？【柴知道：车圈化简】', '每位司机都知道，一辆车的“标称续航”，跟它真正能跑多远，根本就不是一回事儿：标着1000km续航的车，真正跑起来，实际续航可能就只有500km。为什么新能源车的“标称续航”跟“真实续航”差出这么多？所谓“标称续航”到底是怎么测出来的？你经常在汽车广告里看到的WLTC、CLTC、NEDC，又都是什么意思？', 335303, 11848, -1, 566, 876, 1853, 2622, 1003, '2024-8-23 09:30:00', 562, 1, '2025-8-28 09:46:06', 0.00206829, -0.93215);
