INSERT INTO `videoinfo` VALUES ('BV1Ds411y7gV', '5345718', '26798384', '如何科学看待抗生素？', '我们常见的阿莫西林、头孢、青霉素，等等这些药物，有一个共同的名字：抗生素。抗生素对细菌等微生物引起的疾病有奇效；但同时，它也有两个不能忽视的弊端——这都和抗生素的作用机制有关：', 36399, 565, -1, 449, 384, 648, 764, 95, '2016-7-15 10:31:55', 330, 1, '2025-8-28 09:46:06', 0.0130375, 0.114347);
INSERT INTO `videoinfo` VALUES ('BV1Ds411y7M2', '5345730', '26798384', '什么是热力学第二定律？', '一滴墨水滴进水里，为什么会迅速散开，再也不能变回原来的墨水滴？一热一冷的两个铁块贴在一起，为什么最后会温度相同？这些看似理所应当的现象背后，其实隐藏着这个世界最基本的规律——热力学第二定律。', 118877, 2498, -1, 878, 634, 2046, 1326, 210, '2016-7-15 10:32:37', 253, 1, '2025-8-28 09:46:06', 0.00247617, -0.893236);
INSERT INTO `videoinfo` VALUES ('BV1Ds411y7M8', '5345746', '26798384', '英国为什么分为英格兰，苏格兰，威尔士和北爱尔兰？', '很多足球赛中，都有英格兰队、苏格兰队、威尔士队和北爱尔兰队。为什么这四个地区，明明都是英国的一部分，但却总以相对独立的形象出现呢？这就要从公元前的凯尔特人说起：', 160931, 3130, -1, 1162, 955, 3694, 2028, 434, '2016-7-15 10:34:03', 309, 1, '2025-8-28 09:46:06', 0.00295047, -0.847986);
INSERT INTO `videoinfo` VALUES ('BV1Ds411y7nK', '5346161', '26798384', '美国总统选举的规则是什么？', '2016年7月底开始，美国共和党和民 主党将正式提名各自的总统候选人（其实就是特朗普和希拉 里），拉开“总决选”的帷幕。对于这场影响世界的选举， 很多人以为就是一人一票，多者取胜。但其实，它的规则没有这么简单：\n', 156189, 4530, -1, 1635, 501, 2515, 2148, 251, '2016-7-15 11:04:41', 271, 1, '2025-8-28 09:46:06', 0.00151174, -0.985247);
INSERT INTO `videoinfo` VALUES ('BV1Ds411y7uY', '5345693', '26798384', '二维码是什么原理？', '不知道从什么时候开始，我们的生活突然之间就充满了二维码。那么你有没有想过，这个长得很奇怪的东西，到底是怎么来的？其实，二维码就是通过二进制编码，把数字、字母、汉字等字符，转换成了黑白小方块的图案。', 873244, 5613, -1, 4294, 4084, 22558, 11635, 1984, '2016-7-15 10:30:17', 179, 1, '2025-8-28 09:46:06', 0.00692847, -0.468472);
