INSERT INTO `videoinfo` VALUES ('BV1dV4y1T78J', '858004574', '98608863', '请欣赏：最不适合我的穿搭风格', '我，纵横时尚界 20 年，敢买敢穿，敢搭敢露，但有些衣服，我是真的不敢了。\n\n它们在衣柜里尘封多年。是我不敢提起的伤痛，是我不愿面对的耻辱，是我午夜梦回的噩梦。\n\n但今天就要勇敢面对，叫姐妹来和我一起在衣柜里抓「鬼」，把那些奇奇怪怪的衣服通通拉出来罚站，当场决定去留。\n\n虽然我 hold 不住，但我想总有一个人有勇有谋，能搭配出另一片天。我准备了 10 个盲盒，要把它们送给每个平台的热心观众，具体评选规则，去看视频。\n\n这期节目是我的新坑，「不带脑子」系列，咱就是下个饭，图一乐，祝您天天开心。', 86862, 5123, -1, 148, 891, 335, 1042, 367, '2022-9-15 13:13:57', 735, 1, '2025-8-28 09:46:06', 0.0023565, -0.904654);
