INSERT INTO `videoinfo` VALUES ('BV1dX4y1V72a', '714583386', '98608863', '100名女子群像：我最想拥有的超能力', '要瘦，要美，要有少女感，要能赚钱，要当个好妈妈……这社会给女性提出无数的要求，就像要求女性拥有超能力。\n\n那，如果真的可以拥有超能力，女性最想要的是什么呢？\n\n我们采访了 100 位女性，从小学生到老奶奶，从出煎饼摊的阿姨到待产的妈妈，问她们同一个问题：「你最想拥有什么超能力？」她们的回答勾勒出这个时代女性的焦虑和渴望，也还原出一个多元又立体的女性群像。\n\n留言告诉我你想要拥有的超能力，祝你妇女节快乐、坚定、满足。', 60221, 8486, -1, 446, 678, 921, 2452, 383, '2021-3-8 08:38:16', 209, 1, '2025-8-28 09:46:06', 0.00542275, -0.612122);
