INSERT INTO `videoinfo` VALUES ('BV1dz4y1V7au', '576411828', '11799651', '带AI大模型自驾西北1000公里，你能想象吗？', '前几天我又去了一趟青海自驾，上次走的是从成都-玉树-格尔木-茫崖，走的是南线；这次是从敦煌出发，从茫崖到德令哈再到青海湖，走北线。这次虽然是我一个人，不过也带了一个“神秘伙伴”。来一起看看这次奇特的自驾之旅吧～', 335661, 3948, -1, 109, 220, 409, 183, 68, '2023-9-26 11:00:00', 669, 1, '2025-8-28 09:46:06', 0.00547424, -0.60721);
INSERT INTO `videoinfo` VALUES ('BV1Dz4y1W7xr', '574151637', '11799651', '美国为何如此重视这里？【中国城市观察37】', '2015年美国解密了一份报告，详细列举了一旦发生战争，美国将用核弹轰炸的目标，中国有117个城市在名单里。而云南的边境小城--个旧，居然也分到了两颗核弹。个旧何德何能，美国为何如此重视它？', 716874, 20850, -1, 1681, 3856, 4274, 1530, 1812, '2023-7-31 10:45:00', 804, 1, '2025-8-28 09:46:06', 0.00830838, -0.336823);
INSERT INTO `videoinfo` VALUES ('BV1dZ63YPEbX', '113740515123000', '26798384', '“尾货”里有多少假货，到底能不能买？一线从业者讲尾货的秘密【柴知道】', '购物时总能看到一些“尾货”：那些看似全新的商品，价格却低得惊人，只有正价品的几分之一。这些尾货的来源究竟是什么，和正品价商又有什么区别？到底是物超所值还是买了假货？为了把这一切搞清楚，我们采访了在尾货行业各阶段工作的朋友们，得到了这样的解答……', 424381, 17492, -1, 981, 748, 5936, 4686, 579, '2024-12-30 09:30:00', 657, 1, '2025-8-28 09:46:06', 0.00230084, -0.909963);
