INSERT INTO `videoinfo` VALUES ('BV1e14y1e7mr', '772919643', '11799651', '10年统一六国！秦朝强盛至此，为什么14年就崩溃了？【中国观察】', '历史课本上对秦朝的灭亡写得比较笼统，简单来说就是暴政。然而秦国的“暴政”，并不是统一之后才出现的，甚至，正是因为延续百余年的“暴政”，才让秦国一统天下。那么，这种“暴政”到底是什么？秦迅速灭亡的根本原因，又是什么？今天这期视频，我们结合《秦制两千年》这本书，来从另一个视角，解读一下秦朝的灭亡真相。', 1181978, 33937, -1, 1661, 5434, 9247, 3262, 1746, '2022-9-13 10:00:00', 678, 1, '2025-8-28 09:46:06', 0.00607484, -0.549911);
