INSERT INTO `videoinfo` VALUES ('BV1EF411b7fA', '296952334', '356010767', '这就是所谓“申还原”的小姨吗？', '这套片一个月前就拍了，但是后期卡了很久，原因是前期场景太不合适，凌乱加火热的颜色不适合冰系角色，无奈旅拍也没别的办法，只好后期火葬场了，在设计这一步每张我都绞尽脑汁，目前这是我想出来能体现中式华丽+孤独感+结合原片光影能实现的最佳方案了。', 299593, 28317, -1, 1099, 63, 10884, 1682, 287, '2022-3-3 12:57:13', 22, 1, '2025-8-28 09:46:06', 0.0145651, 0.260088);
