INSERT INTO `videoinfo` VALUES ('BV1EF4m1F7WH', '1202076360', '26798384', '玩黑胶到底在玩什么？黑胶里的音乐真的更特别吗？【柴知道】', '在流媒体音乐成为主流的今天，为什么还会有人花上千，甚至上万元买唱片机听黑胶唱片？玩黑胶的人到底在玩什么？它真的像发烧友们说的那么神奇吗？这期视频，我们不光会讲解黑胶的原理，还扛着相机跑到了一位发烧友的家里，听听他的收藏，看看黑胶唱片还有哪些好玩儿的～', 787531, 30289, -1, 1907, 3195, 12121, 5967, 1622, '2024-3-21 09:28:52', 703, 1, '2025-8-28 09:46:06', 0.00410004, -0.738313);
INSERT INTO `videoinfo` VALUES ('BV1Ef4y117AD', '286135532', '2374194', '【古筝】Only My Railgun —— B站十一周年快乐！', '在哔哩哔哩十一周年之际，终于翻奏了bilibili本尊的OP哈哈哈！过激黑子厨在线cos黑子演奏炮姐神曲！\n这次的视频终于回到了梦开始的地方——我的母校拍了这个视频。不得不说校园的青春氛围容易让人中二，在演奏之外忍不住临时加上了很多拙劣的表演哈哈哈哈哈！但是有一说一，我都扎双马尾出门了，还有什么事能比这更羞耻呢（幸好放假了学校没人不然我尬飞！！虽然是cos黑子，但是炮姐神曲怎么可以没有电磁炮，所以最后也通过五毛特效让黑炮合体了！！希望大家喜欢！！\n\n古筝演奏/改编：墨韵随步摇\n录音/混音：刘嘉伦\n古筝拍摄', 1023560, 107668, -1, 4471, 4061, 30494, 70628, 2184, '2020-6-26 09:20:28', 197, 1, '2025-8-28 09:46:06', 0.00858946, -0.310007);
