INSERT INTO `videoinfo` VALUES ('BV1Eh411B7Xb', '207277057', '98608863', '「秀恩爱博主」真的了解彼此吗？Couple Quiz', '在一起9年，他了解我多少？我对他呢？什么样的情侣才算得上真正彼此了解呢？今年七夕，我让阿姐夫和我一起做一套情侣测试 couples quiz，通过答题来赢取我给他准备的七夕礼物。但出乎我意料的是，有些题目连我同事都知道答案，阿姐夫却完全说不出来。难道我的礼物要送不出去了吗？那你了解你的「枕边人」吗，这个quiz你们也可以试一下。', 99605, 7279, -1, 319, 755, 475, 1514, 249, '2021-8-12 10:00:10', 559, 1, '2025-8-28 09:46:06', 0.00263823, -0.877775);
