INSERT INTO `videoinfo` VALUES ('BV1ET421C74e', '1703758838', '98608863', '直面痛苦，是女性的超能力 | 【国际月经简报 ep·24】', '欢迎来到 4 月份的 #国际月经简报#。这个月我们为你准备了 4 条消息，他们来自两次审判，一次尴尬的处境和一群女性无法逃脱的命运。\n\n「性别视角」现在已经成为了一个大众词汇，但有人污名化它，认为这是一种偏执的政治正确，有人不敢拥抱它，担心既得利益被拿走，但国际月经简报和我们一直在一起的各位，始终是在带着女性视角去看待周遭的一切，我们会发现女人的失去，失去自己的语言，失去自己的舞台，甚至失去自己的身体，但我们也会看到，女人在拿回，拿回自己的表达，拿回可以保护生命的法律、拿回被看见的权利。', 71800, 12366, -1, 644, 311, 2095, 7209, 144, '2024-4-29 10:20:00', 782, 1, '2025-8-28 09:46:06', 0.00145651, -0.990515);
INSERT INTO `videoinfo` VALUES ('BV1Et4y117Ve', '625630800', '138832847', '抄袭新西游记，分析《极限挑战6》是如何把口碑作没的【哇妹】', '《极限挑战》被作成现在这副样子，实在令人唏嘘。\n主要是因为平台不懂得及时止损。\n舍不得这个赚钱又国民度高的系列IP。\n主创团队大变动，还要硬着头皮继续做，压榨IP的剩余价值。\n失去了原来的核心优势，又不像罗PD的团队一样有源源不断的创作力，形成系列综艺宇宙。干脆就无底线地抄袭。\n哎，这也是目前国内许多系列综艺面临的瓶颈。', 1448714, 55079, -1, 1923, 9792, 2935, 7387, 4356, '2020-5-16 04:00:36', 467, 1, '2025-8-28 09:46:06', 0.00753962, -0.410166);
