INSERT INTO `videoinfo` VALUES ('BV1Et4y197ws', '626109855', '98608863', '做得了「单身爸爸」是平等育儿的最高境界！｜生育亲测vol.5', '阿姐夫的第一个父亲节，我们俩好好讨论了育儿分工问题。\n说起来惭愧，作为一个支持性别平等的家庭，我们家在育儿分工方面，到目前为止做得还太不够了......于是我们尝试让他多为菜卷做点事情，让他去学了一个针对新手爸爸的育儿课，既是改变他的育儿观念和参与程度，更是让菜卷知道妈妈爸爸对他的付出是一样的。\n为什么社会会普遍理所当然的认为育儿责任就是直接指向妈妈的？如果爸爸们更主动去学习，如果育儿课和育儿书能把「爸爸」也囊括进受众主体，不只是「妈妈」，平等育儿才有实现的条件和基础吧！', 95411, 6719, -1, 912, 686, 828, 1896, 250, '2020-6-22 11:01:53', 560, 1, '2025-8-28 09:46:06', 0.00417557, -0.731108);
