INSERT INTO `videoinfo` VALUES ('BV1EW411d7cQ', '31201807', '26798384', '发烧会把人烧傻吗？不会', '发烧是人体应对疾病的方式之一，目前并没有证据表明，单纯的发烧会对人体造成什么伤害，至于“烧傻”等情况，罪魁祸首其实是脑炎等疾病。不过，如果发烧让人难受，无法好好休息，那也不利于身体的恢复，这时就可以采取一些方法来进行退烧。', 74731, 1955, -1, 423, 142, 471, 553, 322, '2018-9-6 08:31:45', 157, 1, '2025-8-28 09:46:06', 0.0167795, 0.471353);
