INSERT INTO `videoinfo` VALUES ('BV1F54y1x7nC', '843808769', '98608863', '这封信写给你，我的小孩', '我的妈妈很爱我，虽然她不是很会表达感情。她从没给我讲过在我第一次对她笑、第一次拥抱她时，她有着什么样的感受，但我想，那一定很像我现在所体会到的一切。所以，菜卷，我想给你写一封信，把这些都告诉你。\n\n这些文字和影像中不光有妈妈的爱，还有你干妈 Kiva 对你的母爱。妈妈和她要感谢兰蔻给我们一次拷问和表达自己的机会，让这些隐秘的情感不只留在深夜的喃喃自语，而是真实而骄傲地暴露给你。', 50604, 5595, -1, 230, 155, 680, 1823, 148, '2021-1-21 13:51:00', 243, 1, '2025-8-28 09:46:06', 0.00393402, -0.754153);
