INSERT INTO `videoinfo` VALUES ('BV1Fa411Z7wM', '259427319', '11799651', '从东方第一大港，到福建GDP第一，它撑起了中国体育品牌的半壁江山【中国城市观察X】', '古代的泉州，是海上丝绸之路的起点，是宋元时期的世界海洋贸易中心；改革开放后的泉州，屡次创造经济腾飞的奇迹，连续20多年都是福建的GDP第一。而它最接近我们消费者的标签，应该是“鞋都”。\n全球每生产五双运动鞋，就有一双是来自泉州。我们叫得出名字的国产体育品牌，也基本上都来自这里。从东方第一大港，到福建GDP第一，泉州如何撑起了中国体育品牌的半壁江山？今天这期视频，我们来聊聊泉州，也来聊聊泉州体育品牌的扛把子--安踏。', 534687, 20077, -1, 1864, 2108, 3617, 2750, 1821, '2022-8-11 11:14:49', 1002, 1, '2025-8-28 09:46:06', 0.00251581, -0.889455);
