INSERT INTO `videoinfo` VALUES ('BV1fC411x72N', '1950395928', '98608863', '好姐妹要结婚了，我该劝她吗？', '当你听到你的朋友要结婚了，你会做什么吗？\n\n一般来说，在听到这样的消息的时候，我们都会恭喜祝福。但奇怪的是，最近在我的两位好姐妹宣布要结婚的时候，作为「过来人」竟然生出了要劝她一劝的冲动。是婚姻制度太好了吗？还是男人太可靠了？为什么咱们非要结婚。\n\n这期节目我把要结婚的两对 Couple 请来上节目，决定做一做多管闲事的好事之徒，看看她们和伴侣之间的默契程度，也看看这婚姻的联盟关系是否牢固。', 103381, 5195, -1, 1131, 1008, 1033, 1386, 635, '2024-2-5 10:28:51', 883, 1, '2025-8-28 09:46:06', 0.00376304, -0.770465);
INSERT INTO `videoinfo` VALUES ('BV1Fc411x733', '284064346', '98608863', '从小甜甜到疯女人，一部公众对女性的审判实录', '今天想给你讲的是布兰妮·斯皮尔斯的故事。\n\n我们将和你一起，从布兰妮的视角去了解她，去看到一个女儿对爱的渴求，看到一个女孩的梦想，一个艺术家的灵气与才华，也看到一个女明星名利与闪光灯之下的无助与彷徨。\n我们也将为你分析，娱乐、资本、以及无处不在的厌女情绪，是如何逼迫一个女人不断的自证，最终制造了她的“堕落”。\n\n在这个故事的版本里，她不再是小甜甜布兰妮，只是她自己——布兰妮·斯皮尔斯。', 192795, 23915, -1, 1497, 978, 6131, 8487, 476, '2024-1-22 13:16:50', 1160, 1, '2025-8-28 09:46:06', 0.00779095, -0.386188);
