INSERT INTO `videoinfo` VALUES ('BV1ff4y1k73m', '288825555', '138832847', '9.4分，孔笙牛X！没想到这部扶贫剧居然这么好看！《山海情》安利【哇妹】', '这部剧的成功的地方就在于，主创团队们做好了功课，他们基于真实事件改编，\n所以说跟题材无关，说白了就是你不会写。\n主旋律是可以拍好的，可以不刻板不无趣，最重要的是接地气，要有落地的人物。\n希望之后会更多像《山海情》这样的扶贫剧，\n让更多的观众了解到，中国各地的风土人情，人民老百姓的不易，以及扶贫工作的不易。', 834454, 48372, -1, 4067, 4591, 3346, 11871, 2289, '2021-1-21 09:55:56', 642, 1, '2025-8-28 09:46:06', 0.006778, -0.482827);
