INSERT INTO `videoinfo` VALUES ('BV1FG37zbE19', '114794325742711', '98608863', '瘦≠美，难≠命，别再用偏见定义我们', '这个月的【国际月经简报】聊四个看似无关、却都和女性身体紧密相关的议题：\n极瘦审美的回潮、生育的生死冒险、赛道上的性别壁垒、女性运动员的身体极限突破。\n\n1｜瘦是一种审美，但必须瘦，就是一种规训。\nTikTok最近屏蔽了#skinny tok的标签，在此之前，这个词条几乎让「瘦成纸片人」重新成为青少年、年轻人心目中的审美标杆。\n明明前两年，我们还在写body positive运动的积极面，为什么「纸片人」作为审美潮流又卷土重来？为什么又有一种「完美」的身材标准在将女性推向极端？\n\n2｜这辆印满唇印的赛车在宣', 31788, 5554, -1, 303, 158, 1177, 4768, 157, '2025-7-4 09:56:56', 909, 1, '2025-8-28 09:46:06', 0.0101679, -0.159421);
