INSERT INTO `videoinfo` VALUES ('BV1fH7BzYESi', '114623751657068', '98608863', '被这么一顿猛夸，我心虚了吗？', '还记得我们曾经开了一个 7 个小时，只说对方缺点，只提意见的反馈大会吗？\n当时真的是眼泪、委屈、和解齐飞。\n\n但挨批评哪有受表扬开心。\n所以我们决定反其道而行，开一个夸夸大会。\n\n每个人都要接受其他人真诚的夸奖。\n夸夸这件事情，不在于「我」夸得好不好，而在于被夸的人有没有真的感到开心。\n\n欢迎你在评论区夸夸我们，或者求夸夸，\n让我一起攒够面对世界的内心能量。', 8998, 573, -1, 16, 29, 101, 184, 18, '2025-6-4 09:00:00', 5518, 1, '2025-8-28 09:46:06', 0, -1.12947);
