INSERT INTO `videoinfo` VALUES ('BV1FQ4y117Ds', '717551177', '98608863', '性欲低下的男人真的存在吗？| 欲望 ICU vol.2', '「欲望 ICU」的新一期节目，这个系列中我们尝试了解「一切都很好，就是没有性」的亲密关系。这一期的主题是就是，男性伴侣性需求比我低怎么办？\n上野千鹤子的《厌女》告诉我们，父权社会把性看作是单向的：男性主动女性被动、男性支配女性服从、男性得益女性奉献。这不单抹杀了女性在性方面的主体性、忽略了女性的性愉悦，更重要的是将性变作权力的象征。因此一个男人如果对性不感兴趣或者在性方面不强势，他就变得「不够男人」。这么想想男人也挺惨的，被有毒的男性气质绑架了，从此「男人不能说不行」。', 66672, 7082, -1, 885, 911, 1093, 3745, 243, '2021-8-24 11:23:58', 542, 1, '2025-8-28 09:46:06', 0.0174002, 0.530568);
