INSERT INTO `videoinfo` VALUES ('BV1FTUKYVEEc', '113474160038358', '2920960', '粉丝竟然给我安排劳斯莱斯接机，半岛、宝格丽、西郊三大酒店沉浸体验，这次真是过足了瘾！！', '价格大侦探全国篇制作流程是，一个城市去五天四晚，连续探店结束后回家剪辑后期10天左右继续换下一个城市，所以并不是像大家以为的，在外面一住就是半个月，这么整搁谁都顶不住0.0\n这次上海篇个人觉得相当精彩噢！敬请期待吧！另外下个城市去哪，吃什么？欢迎大家评论或私信哦！', 538846, 23550, -1, 1254, 2597, 1857, 4899, 911, '2024-11-13 10:00:00', 1071, 1, '2025-8-28 09:46:06', 0.00459907, -0.690705);
