INSERT INTO `videoinfo` VALUES ('BV1FY4y1g78z', '645078387', '26798384', '低价雪糕为什么赢了人心，输了市场？雪糕会贵到吃不起吗？【柴知道】', '小时候的雪糕，均价不到1块；现在柴司楼下的便利店，10多块的雪糕比比皆是，贵得不敢下口。那如果柴司开始生产1元低价雪糕，能大卖一把，逆势翻身吗？顺着这个问题出发，我们研究了低价雪糕难卖的问题：为什么雪糕越来越贵了？低价雪糕在市场上面临了哪些困境？它们还有出路吗？', 284249, 15941, -1, 405, 1414, 1760, 4011, 837, '2022-9-1 11:11:17', 429, 1, '2025-8-28 09:46:06', 0.00217726, -0.921754);
