INSERT INTO `videoinfo` VALUES ('BV1FZ421M7Mj', '1156297115', '26798384', '真心话：你真的需要智驾吗？5年后，你的智驾还能用吗?【柴知道：车圈化简】', '智能驾驶的营销，我们都看了不少了。在车企老板和博主们的视频里，智驾已经相当成熟，但在现实里，有多少人真的在用智驾？真的好用吗？如果智驾现在还不成熟，那5年之后，你车上的智驾会成熟吗？为了回答这些问题，我们采访了两位车主，和车圈大V@韩路大叔  老师，跟他们聊了点真心话～', 369651, 8943, -1, 783, 990, 1480, 1705, 823, '2024-8-8 09:30:00', 788, 1, '2025-8-28 09:46:06', 0.00320258, -0.823935);
