INSERT INTO `videoinfo` VALUES ('BV1G34y1J7Yz', '813483461', '26798384', '【柴知道】买NFT的人是傻吗？我们自己做了一个NFT讲给你听', '2021 年，全球 NFT 交易规模达到 140 亿美元，比 2019 年全球艺术品拍卖总额还高，因此被称为「NFT 元年」。但问题是，NFT 到底是啥？花高价买 NFT 的人，最终买到了什么？我右键直接保存个文件下来，就是跟 NFT 一模一样啊？NFT 到底是什么？为什么有人花高价买一张电子图片？为了讲清这些问题，我们自己做了一个 NFT，讲给你听~', 627812, 26894, -1, 3286, 1684, 6027, 7788, 1238, '2022-7-15 09:47:44', 476, 1, '2025-8-28 09:46:06', 0.00789938, -0.375843);
INSERT INTO `videoinfo` VALUES ('BV1g441157rB', '55749558', '26798384', '为什么牛肉叫 beef 而不是 cowmeat？', '在英文中，鸡和鸡肉都叫 chicken，鱼和鱼肉都叫 fish，但为什么牛（cow）和牛肉（beef）采取了不同的表达方式呢？这是一个语言学问题，也是一个历史问题，还是一个阶级问题。', 121906, 6282, -1, 304, 473, 1409, 3283, 555, '2019-6-16 03:59:28', 236, 1, '2025-8-28 09:46:06', 0.011423, -0.0396781);
