INSERT INTO `videoinfo` VALUES ('BV1G44y1J7B3', '977461966', '98608863', '你可以不喜欢自己，但我很喜欢你', '你最不喜欢自己的地方是哪里？\n\n我们每个人都会有自我怀疑和自我厌弃的地方。如果一直憋在心里，它很可能会形成恶性循环。所以我们鼓励大家跟朋友聊一下你所认为的缺点，去听听 TA 是怎么看待你的。而作为朋友，我们需要真诚、具体地去夸赞别人，因为你的笃定，对正在迷茫的朋友来说会是强有力的认可，会让 TA 发现看待自己的新角度。\n\n就像OPPO Find N 折叠屏一样，每一种打开的角度，都可以看到世界的不同面向。\n\n如果你也有不喜欢的地方，你可以在评论区分享给我们，接受来自大家的夸赞吧！', 153584, 8240, -1, 929, 477, 1833, 3454, 413, '2021-12-21 11:00:05', 847, 1, '2025-8-28 09:46:06', 0.00745706, -0.418042);
