INSERT INTO `videoinfo` VALUES ('BV1G5411q7Uf', '453257940', '98608863', '我当面质问了女装品牌，为什么你家衣服那么小？？', '菲菲﻿@是是菲菲啊  ﻿ 每次有看中的衣服就会第一时间点进店铺详情页，然后划到尺码详情表里，等待腰围、臀围那些数字开口，然后告诉她，看吧，这些衣服你穿不上。\n\n码子不够齐、衣服不够美，大码女生购物的过程中，总是有一种委屈感和不配得感。「这不公平」「加大一个码就那么难吗？」「大码女生不配穿漂亮衣服吗？」「大码的生意不值得做吗？「多拍一个大码模特会影响销量吗？」我们觉得把这些问题直接「怼」到商家脸上，让他们来告诉我们，在做衣服的时候，究竟把大码女生放在什么位置？', 106209, 6833, -1, 343, 669, 1052, 3207, 668, '2024-1-4 14:20:00', 896, 1, '2025-8-28 09:46:06', 0.00974626, -0.199644);
