INSERT INTO `videoinfo` VALUES ('BV1g64y1q7MF', '759807859', '1377430946', '中美关系重回正轨？秦刚见舍曼传积极信号，美国调整对华政策', '中国驻美大使秦刚12日会见美国常务副国务卿舍曼，秦刚表示，当前中美关系站在“新的十字路口”，他将按照两国元首今年除夕通话的精神，加强同美方的及时沟通对话，努力推动“理性、稳定可控、建设性的中美关系”。', 10882, 265, -1, 5, 36, 26, 19, 49, '2021-8-14 09:12:57', 588, 1, '2025-8-28 09:46:06', 0.0126502, 0.0774035);
INSERT INTO `videoinfo` VALUES ('BV1g64y1S79r', '757463923', '138832847', '18年前这部女性群像也太超前了吧！童年经典《粉红女郎》安利【哇妹】', '我希望以后凡是打着女性题材旗号的电视剧都不要挂羊头卖狗肉\n起码像这部18年前的电视剧一样真真切切地做到给女性带来有意义的思考，而不是规训！', 658521, 33730, -1, 819, 3209, 2769, 6047, 1149, '2021-4-2 07:54:10', 664, 1, '2025-8-28 09:46:06', 0.0145905, 0.262516);
INSERT INTO `videoinfo` VALUES ('BV1g7411h7ju', '87040522', '98608863', '你今天还好吗 04 | 我们每个人都只是幸运一点的武汉人而已', '#你今天还好吗？#\n每日打 Call 第 4 天，接电话的是@Kiva。我们这次聊天好像比平时严肃了一点。Kiva 说她「哪怕在晒太阳都有种罪恶感」，不过看新闻看的难受的时候，也会提醒自己记住今天的感受。她最近买了本书，加缪的《鼠疫》，推荐给大家。\n最后我问她，你想问下一个打 Call 的人什么问题。她说是「疫情结束了想做的第一件事是什么」。这倒是让我们想到了一个新的问题——怎么定义疫情结束？什么时候你觉得自己能自由的出门？很好奇大家是怎么想的，你们也来说说吧。', 11638, 722, -1, 79, 62, 47, 191, 45, '2020-2-6 04:31:02', 598, 1, '2025-8-28 09:46:06', 0, -1.12947);
INSERT INTO `videoinfo` VALUES ('BV1g7411r7ha', '85359480', '116683', '【寄明月】咬人猫/有咩酱/赤九玖❤️155小分队!合体啦!', '155小分队终于重聚啦！《寄明月》是我们约了很久的一支舞，因为我们的时间和距离的关系一直没能成功录制，而后又经历了10月在日本录制的失败！这次12月底又聚在成都终于完成啦！结束的时候我们真的是开心到要飞起来！希望我们的这份快乐可以带给大家！也希望我们可以有更多合舞带给大家！\n99：祝大家2020身体健康！\n咩咩：155好久不见的新视频~希望大家看的开森~也希望世界和平，国泰民安\n感谢后勤：白菜、岚咧\n音乐舞蹈原版SING女团：av15243043\n参考紫嘉儿兔总裁张艺颖版本：av17782558', 3762371, 162709, -1, 14760, 6322, 64705, 102093, 4871, '2020-1-28 08:00:53', 159, 1, '2025-8-28 09:46:06', 0.00593765, -0.562999);
