INSERT INTO `videoinfo` VALUES ('BV1gA411A79r', '334942939', '2374194', '【古筝】琴女在4500米高原峡谷演奏「开天」- 英雄联盟十周年！', '大家好，我是2017最差新人玩家，2018最云LOL赛事观众，2019最云LOL赛事观众第二名，2020最英雄勺大乱斗玩家，2021最高海拔翻奏英雄联盟音乐UP主，峡谷青铜守门员，团团子的老公，墨韵Moyun！！\n这次为了最高还原游戏场景，展现最恢弘的意境，特意选了真的峡谷——海拔4500米，气温只有5度的四川阿坝州莲宝叶则石头山景区，去翻奏了闫东炜老师创作的《开天》。作为为数不多和民乐沾边的英雄联盟相关曲目，初次听到的时候就很喜欢，后来在联盟赛事的重播洗脑下，我更是对这个曲子记忆深刻。值此十周年之际，也', 403637, 30963, -1, 1753, 1191, 8155, 20383, 878, '2021-8-20 10:00:09', 220, 1, '2025-8-28 09:46:06', 0.00587477, -0.568998);
