INSERT INTO `videoinfo` VALUES ('BV1gA411F7kY', '335405529', '11799651', '万字长文叙述中国运营商争霸史:“一家独大”的中国移动【中国行业观察】', '这是中国运营商简史的最后一期了，我们终于来到了4G、5G时代，在这个时代，三大运营商的商业格局基本落定，再难以突破了。所以，这是最好的时代，吗？', 324291, 14160, -1, 1108, 4803, 2896, 4521, 1031, '2021-9-12 04:30:03', 1038, 1, '2025-8-28 09:46:06', 0.00498397, -0.653984);
