INSERT INTO `videoinfo` VALUES ('BV1Ga411t78B', '212424788', '98608863', '现在男女平等吗？大爷说：当然不平等，都阴盛阳衰了', '你觉得男女平等吗？\n\n在我们频道的观众看来，或许这个问题的答案或许显而易见。\n\n今天，「绝对是个妞」上街去，采访了不同年龄、不同性别的人，对这个问题的看法。\n\n我们获得了很多有趣的发现，接受采访的人中，认为平等和不平等的人几乎各占一半。职场女性更倾向于认为当前男女不平等，而学生身份的女性则更倾向于认为平等。在认为当前社会性别不平等男性中，部分男性认为女性的地位高于男性，呈现出一种“阴盛阳衰”的状态。\n\n也欢迎你们留言告诉我对这个问题的看法，以及在接下来的节目中，希望我们问路人什么问题呢？', 271284, 15503, -1, 1810, 5899, 2515, 5057, 4230, '2022-3-21 11:15:36', 496, 1, '2025-8-28 09:46:06', 0.0120949, 0.0244246);
