INSERT INTO `videoinfo` VALUES ('BV1Gs411k7Kh', '5918409', '26798384', '三色条纹国旗的有趣历史', '你有没有发现，很多国家的国旗，都是三种颜色的条纹旗，而荷兰、俄罗斯、法国的国旗，甚至连颜色都一样，实在是很难区分。其实，这些国旗的微小区别，背后都有非常有趣的历史渊源', 277564, 1187, -1, 684, 3717, 10043, 2623, 1759, '2016-8-20 08:58:54', 301, 1, '2025-8-28 09:46:06', 0.00771883, -0.393068);
INSERT INTO `videoinfo` VALUES ('BV1Gs411k7u3', '5918326', '26798384', '如何科学认识亚硝酸盐？', '新闻里常说：腌菜、腌肉、剩菜中的亚硝酸盐浓度，远高于新鲜食物，容易引起中毒。但其实，这种抛开剂量谈毒性的说法，并不科学。这个科普视频将告诉你：亚硝酸盐到底是什么，以及它对人体的作用机制', 76494, 1662, -1, 1016, 345, 1226, 1000, 142, '2016-8-20 08:54:20', 273, 1, '2025-8-28 09:46:06', 0.00681202, -0.479581);
INSERT INTO `videoinfo` VALUES ('BV1Gs411k7wB', '5918186', '26798384', '“闰秒”是怎么回事？', '今年年底，国际标准时间需要额外加一秒，这多出来的一秒就是“闰秒”。这是因为，人类发明的时间尺上的一天，跟地球自转所确定的一天，其实有一些小小错位，需要靠闰秒来弥补。', 46297, 348, -1, 222, 117, 604, 298, 47, '2016-8-20 08:47:31', 184, 1, '2025-8-28 09:46:06', 0.00283575, -0.858931);
INSERT INTO `videoinfo` VALUES ('BV1Gs411k7wj', '5918151', '26798384', '地震预报是什么原理？', '人类现有技术虽然不能准确预测地震，但可以在破坏性强的那波地震抵达之前，提前几秒到几十秒发出预警。2011年日本那场9级大地震中，东京就提前60秒收到了紧急预警。那么，这种地震预警，是什么原理呢？（囧知微信公众号：jiongzhii——囧知的全拼，后面两个i）', 24027, 249, -1, 141, 200, 260, 316, 122, '2016-8-20 08:45:35', 251, 1, '2025-8-28 09:46:06', 0.00119355, -1.0156);
