INSERT INTO `videoinfo` VALUES ('BV1gs411R77w', '3533015', '2374194', '【古筝】从前有座灵剑山 BGM/OP', '自制 新年快乐！本来准备的元旦贺，结果拖到现在【蛋花泪~】不过幸好赶在上映前了。《灵剑山》1月8号就播啦，期待！这部良心国漫一直有关注，看了宣传片的我觉得制作还是很用心的~ 虽然00集里一堆弹幕在关注配音，我唯一的残念的是之前期待的中国风OP为什么完全是日系啊！ 因此这里翻奏一发，希望民乐也能在二次元走出国门，亦表对国漫的支持。由于1分半的OP实在太短了，所以带上了从宣传片里抠出来的棒棒哒的BGM，所有素材均有授权。第一次尝试与二次元合影，希望大家喜欢这次DuangDuang的作品~', 2120134, 10858, -1, 4731, 23593, 26023, 102884, 12080, '2016-1-7 08:21:22', 173, 1, '2025-8-28 09:46:06', 0.00528972, -0.624814);
