INSERT INTO `videoinfo` VALUES ('BV1Gs411Z7bZ', '975707', '116683', '【咬人猫】旋转吧！雪月花❤原创舞蹈o(*≧▽≦)ツ', '自制 这次带来了自己的原创编舞。很喜欢机巧少女里的夜夜，第一次听完ED整个人都激动了~于是没有考虑太多就挖下了这个坑，经过一段时间完成初版的编舞，第一次录制时没有考虑到袖子会干扰动作，效果并不满意，接下来几天努力改编新动作，终于填上了这个坑~虽然过程挺曲折，但是能完成这支舞我真的很开心，由于能力和时间的限制，动作有不够好的地方请多多包涵！【由于舞蹈动作的关系，在服装上做了些许改动，不原版也请大家见谅！', 3723662, 11410, -1, 4326, 20331, 37351, 19633, 3271, '2014-2-20 16:03:00', 101, 1, '2025-8-28 09:46:06', 0.014594, 0.262849);
