INSERT INTO `videoinfo` VALUES ('BV1GS421d7Wh', '1505781199', '98608863', '做一个普通的女性就是最不普通的事情【国际月经简报 ep·26】', '欢迎来到 6 月底，和生理期一样规律的是什么？当然是你们最期待的国际月经简报。\n这期月经简报有冰冷的海水，但它掀起的浪会激起你内心的勇气；有普通的女性故事，那是我们用困境和出走撰写的Herstory。有在大量的性别偏见中积累出来的「错误数据」。\n\n看了《泳者之心》，我哭着走出了电影院，Trudy 横渡的不只是英吉利海峡，更是历史中，女性与体育运动之间的鸿沟。\n老年女性性少数群体，是如何走过那个偏见的年代，她们的故事是什么？Arden奶奶收集了超过 800 名 70 岁以上的女性 性少数群体的口述历史，她说', 35573, 6389, -1, 501, 239, 1224, 4983, 136, '2024-6-27 09:37:27', 713, 1, '2025-8-28 09:46:06', 0.00252459, -0.888617);
