INSERT INTO `videoinfo` VALUES ('BV1Gs4y1R7Ud', '995541871', '2374194', '【指弹古筝】Sunflower - 古筝当吉他用？', '这次用到一把可爱的熊猫小筝！\n亲爱的观众朋友们，我在夺舍吉他手的漫漫长路上又迈出了坚实的一步！特地挑选了一个熊猫花纹的背带，还麻烦敦煌乐器的老师专门给我钉钉在了古筝上，于是终于解放了需要抱着琴的左手哈哈哈哈！虽然能弹到的弦还是只有低音的部分，但对于太阳花这首让许多人入坑指弹的神曲来说还是很契合的。\n当然，开头是纯整活儿哈，大家不要期待我这样弹完一整首qwq……自从开始翻奏指弹，孙培博老师的这首Sunflower一直在评论和私信里被提及，而我也非常喜欢它的旋律，所以当然不会轻易放过！直接痛下毒手！\n主要的挑', 231621, 17428, -1, 2470, 524, 4375, 8184, 581, '2023-4-28 04:05:00', 224, 1, '2025-8-28 09:46:06', 0.0164304, 0.438042);
