INSERT INTO `videoinfo` VALUES ('BV1gU4y1E726', '674857274', '26798384', '【柴知道】蓝牙怎么这么多毛病？还依然长盛不衰？', '蓝牙技术已经诞生20多年了，但它的毛病仍然不少：延迟高、时常断流、传输慢、音质差......蓝牙为什么经常卡顿？几千块钱的蓝牙耳机，怎么还是不能听无损音乐？蓝牙这么多问题，为什么依旧长盛不衰？我们从蓝牙的技术原理出发，试图解答这些问题~', 582076, 36499, -1, 703, 1948, 4808, 5882, 1934, '2021-8-13 10:22:54', 345, 1, '2025-8-28 09:46:06', 0.00374361, -0.772319);
INSERT INTO `videoinfo` VALUES ('BV1Gu4y1K7aa', '922498670', '26798384', '无损音乐是智商税吗？音乐app上的是真·无损吗？【柴知道】', '自从流量和硬盘越来越不值钱，音乐软件们就开始提供“无损音质”，甚至还有比无损更高的音质选项。不过，除了耗费更多流量外，你真的能听出它跟普通mp3的区别吗？无损音乐是不是智商税？为什么还有比无损更无损的音质选项？音乐app上的无损，真的是无损音质吗？为了解答这些问题，我们不光翻了资料，还采访了两位专业人士～', 1255317, 54040, -1, 3088, 5275, 18538, 21303, 3871, '2023-12-18 09:28:54', 902, 1, '2025-8-28 09:46:06', 0.00293508, -0.849455);
INSERT INTO `videoinfo` VALUES ('BV1GU4y1s7bL', '671845884', '138832847', '亲身经历创4录制！揭秘从如坐针毡到嗑死我了的全过程！【哇妹】【创造营2021】', '本期结合正片跟大家聊聊一些录制幕后的故事！\n刚开播的创4，从爱豆选秀角度来说，它未必成功。\n但从爆款综艺角度来说，它显然掌握了套路。\n槽点、笑点、嗑点皆有，观看门槛低，话题度满满！\n但噱头终究是一时的，最终能否留住观众，还是要看后续舞台。', 1241143, 44376, -1, 1935, 9171, 3870, 4426, 2219, '2021-2-24 02:46:09', 587, 1, '2025-8-28 09:46:06', 0.00717715, -0.444746);
