INSERT INTO `videoinfo` VALUES ('BV1HP411179h', '313370401', '116683', '是谁的DNA动了! 极乐净土❤️竖屏【咬人猫】', '之前出约尔蹦迪竖屏的时候，就有很多小鱼干在问极乐净土的竖屏版，后来竖屏版准备好了却一直在准备新舞没有时间发，看到Maria参加浪姐表演极乐净土，真的特别激动！也记起了我的竖屏版！噗！极乐净土对我来说是很特别很有意义的一支舞蹈，学过之后，无论站在舞台上多久，学过再多的舞蹈，永远也忘记不了极乐净土怎么跳！带给过我快乐的宅舞永远是我内心最宝藏和热爱的存在！\n编舞：Miume\n舞蹈参考：sm28709238 BV1us41137Fd\n乐曲：极乐净土（極楽浄土）/GARNiDELiA', 1964756, 153396, -1, 4697, 929, 36114, 31943, 1779, '2023-5-6 11:58:26', 158, 1, '2025-8-28 09:46:06', 0.00652694, -0.506778);
