INSERT INTO `videoinfo` VALUES ('BV1Ht411V7Ke', '59076594', '138832847', '豆瓣4.8飙到6.5，《陈情令》为什么真香了呢？【哇妹】', '大家表达意见的时候呢，尽量不要上升到人身攻击。\n其实大家说得都有道理，批评和赞美都是有意义的，我们把眼光放得长远一点。\n我们应该想的是，如何学习《陈情令》成功的经验，吸取他失败地方的教训，这对以后小说改编特别是耽改都有极大的参考意义。', 1255025, 61081, -1, 8846, 30246, 16471, 30601, 5926, '2019-7-13 17:34:58', 694, 1, '2025-8-28 09:46:06', 0.0114025, -0.0416365);
