INSERT INTO `videoinfo` VALUES ('BV1HU4y1G74p', '673722821', '98608863', '大胸小胸评测无痕bra：走真空都没那么香了！', '今天我邀请了几个朋友和我聊内衣体验。本来想让大家聊一聊自己今天穿的bra，没想到加上我有5个人都没穿内衣！因为内衣真的有很多烦恼，塑形功能让我们的胸不舒服等等。\n但是生活中总是有时候需要穿bra，比如需要修饰胸型，或者就是需要安全感。于是我给她们介绍了爱慕新款的NONOBRA。这是一款在文胸和背心中间的「跨界新物种」，整体非常柔软亲肤，同时又有一定的包裹性，还百经洗涤而不变形。朋友说这款让自己重新认识了自己的胸部！\n视频中专利「反定杯」技术实用新型专利号：ZL 2017 2 1412023.9', 107645, 5932, -1, 403, 513, 720, 958, 357, '2021-6-15 10:00:15', 604, 1, '2025-8-28 09:46:06', 0.0222401, 0.992314);
