INSERT INTO `videoinfo` VALUES ('BV1i3411g7KG', '427448143', '2374194', '全程高能！跟着视频，跨越千年神秘古蜀！【月伴三星堆】', '筝埙和鸣！华子携手百万up主为您带来《伴月三星堆》，听年轻人用自己的方式诠释神秘又辉煌的三星堆文明。13日，三星堆又上新啦！“国风”音乐爱好者，B站古筝教主墨韵x民乐制作人胡多多围绕三星堆文化再创作，原创民乐曲运用了古筝、陶埙、笛子、磬等音乐元素，借鉴四川民歌音阶与川江号子的节奏，有浓郁的蜀地音乐风格。近年来，汉服、古装剧、国风歌曲在中国甚至全球青年人圈层刮起一阵热潮。在国家实力背书的前提下，国风作品热潮展现了当代年轻人寻找自我、充分文化自信审美态度。\n \n古筝演奏：墨韵随步摇\n竹笛/埙演奏：徐硕\n作曲/', 168664, 19296, -1, 745, 257, 3173, 2760, 260, '2022-6-13 10:05:00', 210, 1, '2025-8-28 09:46:06', 0.00363215, -0.782952);
