INSERT INTO `videoinfo` VALUES ('BV1i4411P7bL', '55454536', '6087825', '泰国自由行VLOG，每天睡到自然醒的度假式旅行~曼谷/芭提雅，美食种草，景点踩雷，退税干货。', '设备：佳能G7X2 \n剪辑软件：Adobe Premiere Pro/FCPX \n微博：https://weibo.com/u/6036216308\n东南亚雨季马上来临了，制定旅行计划要看到天气预报喔！\n曼谷最不值得去的地方是大皇宫，能热死在人堆中！ 不如腾出时间来逛逛边上的冷门景点，都是美翻天的！\n个人认为最值得打卡的是 \n三头象博物馆，papaya木瓜复古商店，室内水上市场，芭提雅的悬崖餐厅，还有还有 视频里告诉泥萌。\n曼谷不适合购买化妆品，多数没国内便宜，如果买了可以片尾干货', 238924, 4032, -1, 353, 842, 1299, 980, 228, '2019-6-13 12:00:41', 1021, 1, '2025-8-28 09:46:06', 0.00353826, -0.791909);
INSERT INTO `videoinfo` VALUES ('BV1i4411Q7Q2', '63378182', '98608863', '为什么我们无法接受女性的体毛？', '美国有一个奇怪的女用剃毛产品品牌，它们虽然是卖剃毛刀架的，但却在每条广告里跟女性说：“有毛也没关系！” 它让我意识到自已一直以来对于体毛的纠结：除毛或不除毛，真的是我自己的选择吗？觉得毛发丑陋或不丑陋，是我自己的审美吗？很多时候，我们看似是主动选择了自己想要的东西，实际上其他选项早就被剥夺了。', 197445, 12460, -1, 1160, 624, 2334, 3308, 1464, '2019-8-12 12:54:31', 275, 1, '2025-8-28 09:46:06', 0.0262423, 1.37414);
