INSERT INTO `videoinfo` VALUES ('BV1iT421Q7Be', '1704326804', '2920960', '【祥食记】北京王府井一家涮肉，吃完知道价格后惊呆了！！', '这家餐厅的用餐环境和服务质量是主要加分项，感觉档次可以对标大董新荣记这种餐厅，所以在看到菜单价格前，我一度认为这是一个非常贵的餐厅，如此看来非常适合商务宴请。在这种环境服务下甚至让我觉得餐食吃起来都更高级更美味了，不过作为北京涮肉来说确实也还不错，没有雷点。特别注意的是这顿之所以便宜是因为点的双人餐，这家餐厅还有4人餐和8人餐，如果单点的话价格要贵将近一倍（不推荐单点）。因为是试营业期间包间免费且没有服务费，未来好像是300元的包间费。这家餐厅是唯一让我写这么多的字的，真不是推广！！但很感慨！！', 913844, 37350, -1, 2860, 3660, 3044, 9712, 858, '2024-5-10 10:00:00', 789, 1, '2025-8-28 09:46:06', 0.00626107, -0.532144);
INSERT INTO `videoinfo` VALUES ('BV1iT4y197Lu', '934113936', '98608863', '张腿不爽、未婚无奈，我们经历的妇科检查', '妇科检查都是在检查什么？用什么方式？会有什么样的体验？妇科体检当中的「未婚勿查」是在防什么，未婚就不能查吗？体检方能不能不要只考虑阴道瓣（处女膜），给我更专业的医学建议？我可以给医生提要求吗？如果不知道怎么提要求怎么办？\n\n我们带着疑问去进行了这次妇科体检，还请来万千「少/妇女」的妇科问题老棉裤 @六层楼先生   把这些问题统统问了清楚，结论就在视频里面！如果你们对妇科体检有什么经验和体会，欢迎在评论里和姐妹们分享！', 313220, 18965, -1, 2675, 1462, 3122, 4373, 1196, '2021-11-8 12:45:12', 706, 1, '2025-8-28 09:46:06', 0.0111263, -0.0679845);
