INSERT INTO `videoinfo` VALUES ('BV1ix411e7W5', '10502963', '26798384', '科普: “音色”的本质是什么? 为什么二胡拉欢乐颂都那么丧', '发声体振动的幅度决定了声音的音量。振动的频率决定了声音的音调。而哪怕是两个乐器用同样的音量和音调演奏同样的旋律，我们依旧可以把它们区分开来。这是因为，不同的乐器有着不同的音色。', 51167, 457, -1, 168, 316, 1051, 389, 243, '2017-5-12 10:50:48', 132, 1, '2025-8-28 09:46:06', 0.00982582, -0.192054);
INSERT INTO `videoinfo` VALUES ('BV1ix411F7vK', '368621', '116683', '【咬人猫】沙漠喵★罗密欧与灰姑娘~①周年的第十四作舞蹈~', '原创 希望在B站投稿一周年之际~能在沙漠中完成这支超喜欢的和以往风格大不相同的舞蹈，结果因为眼睛很弱光，在强光下几乎流泪疼痛到快睁不开眼。于是本来是一个稍妩媚俏皮的舞蹈，却没能很好的表达。 总之这一年能通过宅舞认识大家实在是太开心了，我的面瘫虽然在这作没有好转，但是内心却是越来越充实和欢乐。总之谢谢大家一年来的支持，小喵会继续努力的！ 喵酱微博传送门：http://weibo.com/momonecat', 542366, 1400, -1, 558, 6037, 2541, 2385, 924, '2012-10-4 16:08:52', 292, 1, '2025-8-28 09:46:06', 0.0077569, -0.389437);
