INSERT INTO `videoinfo` VALUES ('BV1j54y1j7MM', '845257731', '122879', '我在B站的这10年', '不知不觉在B站已经10年了，从”敖厂长发癫之作眩瞎你狗眼“开始，到如今的372个投稿，视频制作生涯中我犯下不少过失，也收获很多荣誉，你们见证我的成长，我也感谢你们的陪伴。为什么要创作视频当UP主？我的视频风格如何形成的？我犯下的那几个错误？我之前没回答的事，在这个视频都能找到答案。此视频纪念我的10年，也纪念你们的10年，送给我，也送给你们！\n================================\n引用其它视频画面包括\n毕导：BV1vV411f78y\n玩大的博物馆：BV1LW411Z75a\n黑桐', 994711, 114556, -1, 1424, 4301, 16397, 66885, 3997, '2021-4-30 09:12:01', 601, 1, '2025-8-28 09:46:06', 0.00634506, -0.52413);
