INSERT INTO `videoinfo` VALUES ('BV1J5AWeaEbw', '114036180000389', '2920960', '感觉在北京吃粤菜飞机票都包含在餐费里了！！', '店名：肥福排挡（北京总店）    位置：北京市朝阳区新东街4号附近\n\n稍加改良创新的广东味，价格就算是在北京感觉也有些偏高。味道确实还可以，不比在广东本土吃的类似菜品差。我觉得可能是大霸子点菜点的不是很符合我的审美，加上价格，对于我个人而言这次用餐整体只能给3星。\n\n推荐指数个人向：★★★ √\n★★★★★（如果条件允许每月都会忍不住吃一两次） \n★★★★（有第二次去的冲动，也有推荐朋友去吃的想法）\n★★★（还不错，但暂时没有再去的想法） \n★★（个人不喜欢，因人而异） \n★（太拉了，什么鬼？？？） \n\n淘', 682158, 30789, -1, 559, 2176, 1983, 10720, 690, '2025-2-21 10:00:00', 684, 1, '2025-8-28 09:46:06', 0.0100684, -0.168915);
