INSERT INTO `videoinfo` VALUES ('BV1J64y1h7yM', '762894377', '98608863', '私藏分享三位女神，教我穿衣教我做人', '过去的一整个夏天，我都穿得像个运动员！因为我出行的时候喜欢骑自行车，我总是穿的简单又凉快；带菜卷出门的时候，又必须让自己穿的耐脏又利落。终于秋天来了，我也总是很喜欢在这个最适合混搭的季节，认真打扮一下自己，找到更多属于我的风格穿搭。受三位我非常向往的女士的启发，我模仿她们的穿衣风格，给自己也搭配了几套look。这三位女士分别是，模特Ines，某著名歌手（此处不剧透），以及作家Adichie。制作这期视频的过程，让我意识到，我向往的这些女性，她们是如此的多变，并且勇敢地「成为自己」、「忠于自己」。', 101021, 10004, -1, 195, 371, 1773, 4341, 155, '2021-9-9 11:09:20', 436, 1, '2025-8-28 09:46:06', 0.00272735, -0.869273);
