INSERT INTO `videoinfo` VALUES ('BV1JcsQehEAP', '113186615336709', '98608863', '国际月经简报 SP1 | 到底什么能把我们「劝」进婚姻里', '久等了，这期国际月经简报，真是花了大功夫，但我们没有鸽。\n\n1. 《婚姻登记条例（修订案））》公布，结婚不要户口本，离婚可以再反悔，它能把我们劝进婚姻里吗？\n2. 特朗普竞选搭档 JD Vance，说没有孩子的人是疯狂的猫女，那么养着三只猫的泰勒·斯威夫特怎么看？\n3. 印度加尔各答奸杀医生案件震惊全球？为什么这个国家【对女人那么危险】？\n\n另外，一个重要的消息，本期国际月经简报只在 B 站充电观看，请大家奔走相告。', 67353, 5355, -1, 104, 64, 718, 2819, 52, '2024-9-23 11:45:59', 970, 1, '2025-8-28 09:46:06', 0.0085171, -0.316911);
