INSERT INTO `videoinfo` VALUES ('BV1JN411n7bw', '491473325', '98608863', '什么时候「这是性骚扰」才能成为常识', '究竟什么是性骚扰？\n在我看来这个答案其实很简单，如果对方那行动、言辞、甚至是眼神中让你感受到了带有性意味的不适，都是性骚扰。\n我们想用这期片子再去厘清什么是性骚扰，在面对性骚扰时，受害人、旁观者和加害者都可以做什么，希望有一天，这些内容可以成为不用再去科普的常识。\n#欧莱雅她守护#她守护36计#骚扰无小事#山一女性力量', 82076, 4165, -1, 466, 60, 684, 2187, 164, '2023-9-26 09:00:00', 510, 1, '2025-8-28 09:46:06', 0.00276493, -0.865688);
