INSERT INTO `videoinfo` VALUES ('BV1Jp4y1k7hV', '970039158', '26798384', '【柴知道】器官移植究竟难在哪里？中国的人体器官从哪里来？', '你身体里的两颗肾、一个胰腺、两块肝段、两片肺和一个心脏，都可以拯救另一个生命。但每个能成功完成器官移植手术的患者，都是几十分之一的幸运儿。为什么只有少数幸运儿能获得合适的器官？如何争分夺秒地把鲜活的器官移植到另一具身体里？救命的器官来自哪里？我们翻查了文献和文件，制作了这支视频~', 197623, 13020, -1, 1040, 689, 2131, 3929, 739, '2020-10-29 10:17:05', 384, 1, '2025-8-28 09:46:06', 0.0109329, -0.0864355);
