INSERT INTO `videoinfo` VALUES ('BV1jQ4y1m7qk', '717435546', '2920960', '百万粉丝UP主为何疯狂扇自己大嘴巴子？', '原本的视频食材没到，临时改成整活儿视频！\n\n详细游戏规则如下：\n\n规则1. 由大袜子出人名，祥哥需要在限定的问题次数内\n猜出人名，摄影小哥只能回答是或否\n\n规则2. 一共三局两胜\n第一局范围是《原神》游戏内的人物（10个问题）\n第二局是动漫人物（15个问题）\n若前两局打平再决定第三局范围\n\n附加规则：在游戏过程中双方都不能说“你”“我”“他/她/它”\n说了的人需要吃一口芥末（未被对方发现不算）\n\n奖惩：大袜子赢了，祥哥直播给粉丝发2000元福利\n祥哥赢了，大袜子给祥哥开提督', 1125263, 119549, -1, 680, 2592, 3412, 18298, 982, '2021-8-20 10:00:09', 361, 1, '2025-8-28 09:46:06', 0.0159425, 0.391496);
