INSERT INTO `videoinfo` VALUES ('BV1jqR2YiEE8', '114295975188050', '98608863', '批评套娃 ｜ 我为自己的低自尊又低自尊了', '你有没有经常责备自己，觉得哪里都不够好？\n有没有做什么事情都在悄悄比较，给自己打分？\n会不会人际交往的过程中无法提出自己的需求\n面对批评的时候，不知道如何应对？\n\n如果有，那么很有可能你是着了低自尊的道。\n\n我们最近在读《自尊》，我们发现低自尊的根，不是懒惰，不是能力问题，而是我们怎么看自己。是那个内在批评者总是在用完美的标准要求自己。\n\n这期读书会，我们把《自尊》这本书和暂停实验室的行动营结合起来，拆解我们的问题，然后通过暂停实验室情绪ebp 行动营找到应对的方法。', 14693, 610, -1, 54, 67, 259, 166, 20, '2025-4-7 09:37:11', 3881, 1, '2025-8-28 09:46:06', 0, -1.12947);
