INSERT INTO `videoinfo` VALUES ('BV1js411Y7Mh', '7808885', '116683', '【咬人猫】盛夏的Letter Rainbow❤o(*≧▽≦)ツ', '很喜欢“盛夏”这只舞蹈欢乐温暖的感觉于是选择了在“冬日”里发布~也很想在新的一年开始带给大家带来一份开心和欢乐就好，虽然这个版本较简短，但足太的编舞对我一直都是很大的挑战，录制期间调整了一些细节从晚上8点一直录到凌晨2点，但依然有很多不足，请大家多多包涵，我也会继续努力的！一转眼2017年了，依然想要感谢一直以来支持我鼓励我的大家！祝大家新年快乐！新的一年也要一起加油哟！编舞：sm25892236', 1436363, 5442, -1, 2069, 7100, 12910, 46071, 5163, '2017-1-1 14:04:02', 120, 1, '2025-8-28 09:46:06', 0.0111327, -0.0673682);
