INSERT INTO `videoinfo` VALUES ('BV1Jt411h7Dj', '41411565', '98608863', '爸：你讨厌过我吗？', '我们都知道我们的沟通有问题，但谁也不想主动做出改变。我觉得我无法得到我爸的理解，实际上我也不愿意去理解他。我埋怨他从来听不进去我讲的话，埋怨他思维僵化、总以为自己是对的；但其实我也从来没好好听过他想说什么，总是默认他一定是错。我不想成为我的父亲，但又在很多行为上重复他。\n\n回避与父母沟通或许是更容易的做法，但如果你试图去和父母说话，也许会了解他们也能更看清自己。在视频的最后我附上了我们对话使用的 13 个问题。今年回家的时候，你也可以和你的父母尝试聊一聊。', 456598, 16455, -1, 2361, 2257, 4645, 5216, 2590, '2019-1-22 12:48:19', 415, 1, '2025-8-28 09:46:06', 0.0105566, -0.122332);
