INSERT INTO `videoinfo` VALUES ('BV1jT421D7Wd', '1704562623', '520819684', '大战一触即发，到底什么是真正的“AI手机”？', '有传闻苹果下一代系统要上AI功能，其实不光是苹果，AI手机对于整个手机行业来说，肯定也是新的爆点。各大厂商都在扎堆儿喊口号、秀实力，那到底什么才是真正的\"AI手机\"呢?\n今天，咱们就抛开现在能看到的AI手机功能，从我们最最基本的需求出发来聊聊，你希望AI手机是什么样的？', 1171284, 37996, -1, 4102, 3560, 6160, 7443, 1536, '2024-5-15 10:00:00', 676, 1, '2025-8-28 09:46:06', 0.00472445, -0.678743);
