INSERT INTO `videoinfo` VALUES ('BV1JtGuzuEuT', '114827846556334', '26798384', '全球第1运力 ！中国铁路凭什么领跑全球？【柴知道】', '2025 年春运，在短短 40 天时间里，中国铁路运送了 5 亿人次的旅客，平均每天有上百万人坐火车出行。实际上，无论是客运还是货运，我国铁路的运力都早已遥遥领先。从筚路褴褛到领跑全球，中国的铁路是如何发展起来的？除了高速列车和遍布全国的铁路网外，还有哪些不为人知的努力？', 735612, 22976, -1, 582, 2108, 3957, 2422, 2385, '2025-7-10 08:16:22', 453, 1, '2025-8-28 09:46:06', 0.00224551, -0.915242);
