INSERT INTO `videoinfo` VALUES ('BV1jz4y1U76s', '586551453', '2374194', '【墨韵】极 乐 禁 忌 の 宝 岛', '只要我自己鬼畜得够狠，就没有人能鬼畜我！值此新春佳节，我终于对这几首神曲下手了！整了一个微小的活，给大家拜个早年！ \n当我意识到要边跳《极乐净土》边弹琴的时候，作为一个不协调的古筝乐手，我浑身的细胞都在大喊：我！不！行！但是没关系，只要我不尴尬，尴尬的就是别人。兄弟们把“尽兴”打在公屏上谢谢！\n\n感谢大家看来看我的视频，祝大家新的一年想啥有啥。而我只有一个请求：尽量笑的小声一点。谢谢朋友们～\n\n原曲：《极乐净土》《禁忌的边界线》《新宝岛》\n古筝演奏/改编：墨韵随步摇\n改编编曲/混音：Nikko\n录音：刘嘉', 855156, 85344, -1, 3330, 8304, 19139, 56295, 1854, '2021-2-9 04:00:05', 258, 1, '2025-8-28 09:46:06', 0.0121363, 0.0283729);
