INSERT INTO `videoinfo` VALUES ('BV1kr4y1x774', '769603163', '2374194', '【指弹古筝】Thunderstruck - AC/DC “鼓筝”究极进化完成！', '这次的翻奏是基于Luca Stricagnoli改编的吉他版Thunderstruck做的古筝移植，弹完只想说Luca大神的麒麟臂+无情铁手果然不是我能轻易碰瓷的…反正我觉得我的左手已经要断了。\n录音师说我拧扳手像在开手摇拖拉机……真的无语！但就算是拖拉机咱也是五档起步好吧！可怜了这个扳手和琴房的地板，它们承受了太多，也算是为整活献身了哈哈哈～\n这是第二次尝试指弹的移植了，感觉又学习到了很多！希望下次能给大家带来更有意思的曲子～', 355635, 26679, -1, 3797, 984, 7030, 15568, 898, '2022-5-29 04:04:59', 240, 1, '2025-8-28 09:46:06', 0.00890335, -0.28006);
