INSERT INTO `videoinfo` VALUES ('BV1KZ4y1w75S', '374622655', '98608863', '在做过的美妆视频里，这是我最喜欢的一个！', '这一次的GRWM是业余美妆博主Alex和亚文化领头人Kiva，在妆容层面上的一次交锋，除了使用@FentyBeautyOfficial必败经典产品打造出自信强大的女性妆容外，我们还在过程中讨论了如何寻找风格以及女性友谊的话题。要说友谊，我和kiva之间也存在过嫉妒，尤其是当看到对方身上存在着自己想要拥有的特质时。但这种时候，我们也会为对方感到由衷的高兴。当喜悦超越了嫉妒和自卑，彼此的存在就能让自己的人生也变得闪闪发光，我想这就是友谊对我们的意义吧！', 64127, 5600, -1, 202, 481, 447, 1130, 142, '2021-3-7 07:05:35', 776, 1, '2025-8-28 09:46:06', 0.00188309, -0.949818);
