INSERT INTO `videoinfo` VALUES ('BV1L64y157Ro', '579374222', '98608863', '啥都比就不比业务，啥都卷就不卷工作', '学做饭半年了，最近的我越发膨胀，竟然斗胆召开了厨艺大赛。要知道在这个爱赢的团队，只要跟「比赛」相关，就没有谁会掉以轻心。\n没错，这个团队就是很无聊，在一切微不足道的小事里，卷出自己的一片天地。\n没错，这场厨艺大赛是一场无意义、无奖品的胜利，但这是我们自尊心的比拼，是我们野心的较量，是绝对是个妞每个人的尊严之战。\n我们贯彻：什么都比就是不比业务，什么都卷就是不卷工作的比赛宗旨，在此宣布本届厨艺大赛圆满成功。\n欢迎你通过评论弹幕的形式，隔空评选你心中的厨艺之王，也可以在评论区找我们要菜谱哟！', 21550, 1681, -1, 24, 169, 129, 503, 78, '2023-12-4 09:10:14', 956, 1, '2025-8-28 09:46:06', 0.00372834, -0.773775);
