INSERT INTO `videoinfo` VALUES ('BV1La411c7rV', '203135626', '2374194', '【筝鼓和鸣】大氿歌 —— 你们不要再打了！', '2020最后一个月也是文艺复兴的一个月呢～很荣幸邀请到了川音的打击乐小伙伴一起演奏我一直很喜欢的《大氿歌》。\n\n话说演奏演奏，有演有奏，最近现代曲子弹多了好不容易有古风，那当然要不客气地发挥一下戏精本色！但是武侠不是想拍就能拍的，我们俩一个不会耍剑一个不会舞锤，当天五分钟新手教程后直接快进到PvP对打。当事人表示就是非常后悔，太苦了！感谢松溪大曲老师用她丰富的拍摄经验，让我们也体会了一把拍《中国电视史》的感觉哈哈哈哈。\n\n音乐方面这次的融合了戴荃老师的国风翻唱版，慢板铺垫情绪表明主题，间奏用古琴名曲《酒狂', 386318, 39700, -1, 1200, 972, 10508, 19408, 836, '2020-12-17 10:00:00', 280, 1, '2025-8-28 09:46:06', 0.00510886, -0.642069);
