INSERT INTO `videoinfo` VALUES ('BV1LM411v7SS', '523945511', '98608863', '我最难搭的丑衣服，竟然是别人最亮眼的单品', '作为一个时尚博主的困境就是拥有太多「潮流」单品，但你们知道潮流的另外一层意思就是「不好搭」。而我解决这个烦恼的方法就是让大家一起烦恼起来。我给团队的每一个人都分别挑选了最不适合他们的衣服，而他们也不是任我宰割的羔羊，纷纷给我寄来了压箱底的「丑衣服」来撼动我穿搭王者的地位。\n绝对是个妞团队哀嚎一片，开始颠覆自己对于时尚的理解。\n横看、竖看都只能用奇形怪状来形容的衣服，竟然在我们这帮人手中，有了又好看、又好笑的表达。懂不懂穿搭不敢乱说，但节目效果是被我们玩明白了！', 179173, 19597, -1, 1604, 2206, 2896, 8023, 381, '2023-2-6 11:44:05', 1051, 1, '2025-8-28 09:46:06', 0.00504919, -0.647761);
