INSERT INTO `videoinfo` VALUES ('BV1LM4y1r78E', '908419387', '26798384', '超级大的氢电池，能干什么？【柴知道×松下】', '火箭不能烧煤，只有热值高的燃料，才能释放足够的能量，推动火箭上天。像“长征五号”这样的大火箭，通常是以液氢为燃料。只有这样，才能把嫦娥五号、天问一号这样的载荷送到月球和火星。\n\n不过，这样的应用，距离我们还是太远了。有没有可能在现在就体验一把氢这样「future」的能源？', 182566, 8448, -1, 179, 439, 992, 1072, 466, '2023-3-14 09:30:00', 336, 1, '2025-8-28 09:46:06', 0.0053222, -0.621715);
