INSERT INTO `videoinfo` VALUES ('BV1LNidYyEcw', '113599116811067', '98608863', '为母险象环生，谁还选择生育？', '在当下这个恐婚恐育的年代，谁还愿意生孩子？谁还敢生孩子？而做出生育决策的女性，她们现在的生活是什么样的？\n\n最近，我看了《新生育时代》这本书，两位作者从实地调研和个人经历出发，说出了属于当代女性的「生育的理由」。\n\n这不是一本劝你生孩子的书，因为它从生育选择出发，还探讨了，家务分工、事业、教育、关系、追男宝等一系列问题，你会看到无论是否选择生育，女性仍在面临的困境。\n\n但，这个时代的转型已经开始，无论你做出什么样的选择，我们都已经加入到打破性别分工、家庭模板和母职绑架的行动中来。', 42104, 3020, -1, 354, 250, 659, 1484, 203, '2024-12-5 10:00:00', 613, 1, '2025-8-28 09:46:06', 0.00979095, -0.19538);
INSERT INTO `videoinfo` VALUES ('BV1Lo4y1f7Pf', '373540398', '26798384', '【柴知道】相机镜头为什么这么贵？还比手机镜头更大更沉？', '「摄影穷三代，单反毁一生。」一台相机，往往要配上好几支又大、又沉，还很贵的相机镜头。相比而言，手机摄像头却又小又轻。相机镜头为什么贵？还又大又沉？30块钱和30000块钱的镜头有什么区别？我们从镜头成像的光学原理和市场需求出发，为你解答这些问题~', 384503, 22903, -1, 1503, 1314, 6042, 7205, 801, '2021-1-8 09:50:29', 410, 1, '2025-8-28 09:46:06', 0.00203691, -0.935143);
