INSERT INTO `videoinfo` VALUES ('BV1Lp411R7Sy', '23911956', '26798384', '三分钟看懂神级脑洞“缸中之脑”', '【缸中之脑】是一个非常有趣的思想实验，它假设你的大脑被泡在营养液里，并且与一台超级计算机相连接。而这台计算机可以向你的大脑输入各类感官信号和运动体验，让你觉得世界一切正常。那么问题来了：正在玩手机的你，要怎么确定自己的大脑还在身体中呢？', 165645, 3731, -1, 1500, 635, 1975, 1146, 750, '2018-5-25 09:12:58', 166, 1, '2025-8-28 09:46:06', 0.0149353, 0.295406);
INSERT INTO `videoinfo` VALUES ('BV1Lp4y1C7D3', '967627082', '98608863', '职场这条升级路，怎么女性遇到的妖怪这么多？', '女性不能平等的拥有和男性一样的就业、发展机会，这是个不争的事实。在这次节目里我也采访了在大型国企做 HR 的朋友，讲述 HR 是怎么挑简历的。这些事实挺让人沮丧的，但无论如何，解决问题的第一步，是先确定它是一个问题，先把问题说出来。如果你有相关的经历想说，也留言告诉我吧。', 73929, 7799, -1, 1268, 887, 1582, 3582, 1184, '2020-4-13 11:18:20', 444, 1, '2025-8-28 09:46:06', 0.011134, -0.0672448);
