INSERT INTO `videoinfo` VALUES ('BV1Lp4y1z7FM', '970515727', '98608863', '我尝了一口母乳，是哈密瓜+我儿子的味道 ｜ 生育亲测', '之前你们说没见过母乳，我猜你们也没尝过。我（和菲姐&摄影师鹏鹏）尝了尝我的母乳，是哈密瓜+菜卷的味道！\n\n你现在看到的是我的新视频系列 #生育亲测# ，虽然做了不少相关选题，但这还是第一次给它们一个具体的名字。我相信生育是女性的选择，知道生育要面对什么，女性才好去做选择，我想用我个人的 #生育亲测# ，来展现生育在一个具体的女性生命里产生的可能性。', 95727, 9541, -1, 1076, 651, 1085, 3851, 472, '2020-12-7 11:39:11', 574, 1, '2025-8-28 09:46:06', 0.00820856, -0.346346);
