INSERT INTO `videoinfo` VALUES ('BV1Ls4y1F7yZ', '955295529', '116683', '⚡️三 摇 分 身⚡️ Roly Poly！ 【咬人猫】', '第一次正面和背面一起跳舞！也终于COS了一直很想出的屑狐狸和雷神将军，太过瘾了！偶然在ktv看到舞蹈教学有了这个点子，练习中我努力想让两面的合跳要看起来更和谐、三个角色要跳出三个性格还是让我充满挑战！虽然成片只有短短的一分多钟，但正式拍摄这支舞其实拍了三个通宵才完成，正、背面还有不同的服装和灯光，相当于平时12支舞以上的素材，录了上百次，跳完才发现脚都淤青了，才知道这一系列的安排要真的完成它有多难～圆满啦！特别开心！希望大家看这个三摇蹦迪能看的开心！\n歌曲/舞蹈：T-ara《Roly Poly》', 5316133, 308555, -1, 20319, 1923, 142451, 98785, 3266, '2023-6-30 11:00:00', 111, 1, '2025-8-28 09:46:06', 0.00669353, -0.490886);
