INSERT INTO `videoinfo` VALUES ('BV1M64y1t7R9', '761746565', '98608863', '从「复旦」到「单向历他妈」到「阿姐」', '每次当我的同事问我「职场经验」的时候，我总觉得没什么好说的，我就是上了个学，然后去了几个地方工作而已。她们拒绝接受这个答案，于是决定要面试我。（胆子还挺大的）\n\n在这期视频中你将看到：\n面试者如何合理展示自己的优势\n我的工作经历\n我最骄傲的作品（之一）\n我的优点和缺点\n我的团队如何互相拉扯\n以及\n我的（很多张）旧照', 115940, 12570, -1, 302, 532, 2189, 7249, 418, '2021-7-15 12:40:14', 597, 1, '2025-8-28 09:46:06', 0.00218419, -0.921092);
