INSERT INTO `videoinfo` VALUES ('BV1M8411N7vb', '222710611', '98608863', '被封在学校的年轻人，值得更辽阔的青春', '这是一期和大学生们一起创作的节目，记录他们在封校中的生活。\n我们收到了 800 多份问卷，看见这三年，大学生在严格的封校环境中，他们失去了丰富的校园生活，更失去了外面的世界。在制作过程中，我感觉自己不再是一个观察者，我是一个学习者，他们的经历和态度也在启发我的思考。我开始去反思自己的生活，我会不会在痛苦中感到麻木，会不会在还行的日子里遗忘苦难，还想不想要为自己争取。我们想让你们一起来听听大学生们的声音，希望一起去听见他们希望在过去之后还要记住什么。我们希望牺牲一代人青春的事情不会再在未来发生。', 116305, 10995, -1, 2988, 483, 2513, 6411, 575, '2023-1-11 12:05:00', 689, 1, '2025-8-28 09:46:06', 0.004715, -0.679644);
