INSERT INTO `videoinfo` VALUES ('BV1ma411M7VD', '216166928', '2374194', '【指弹古筝】冠军小星星Like A Star - 极致泛音唯美旋律', '这首Like A Star是计划中的指弹翻奏三部曲的最后一首了！吉他手Youngso Kim在看完《你的名字》后有感而发写下此曲，并借其一举拿下2019年日本指弹大赛冠军。\n\n它与Revolution和Thunderstruck风格迥异，没有奇异的调音、华丽的拍板或者特殊的道具，一切又回归到好听走心的旋律中来。最初听到小星星觉得它是最不适合移植的，因为其中最核心的吉他指法是扫弦，而在古筝上不可能横跨三个八度扫弦。但是这首曲子实在是太好听啦！！办法总比困难多，还是冲了！\n\nps. 你有你的滑动调音夹，我有我', 636295, 46004, -1, 12162, 2744, 18884, 39975, 1323, '2022-7-22 09:55:00', 357, 1, '2025-8-28 09:46:06', 0.0108606, -0.0933307);
