INSERT INTO `videoinfo` VALUES ('BV1mE411Q75L', '69874552', '116683', '【咬人猫】邮轮蹦迪初体验！❤️ FANCY！', '「FANCY」是今年夏天很喜欢的一首歌，特别阳光会不自觉的听着就很开心，于是计划了很久想到邮轮上录制这支舞，希望把旅行的快乐和舞蹈一起带给大家。但我没想到真正的考验还在后面，正式录制时因为风浪原因海上邮轮其实一直在左右摇摆，我在甲板上跳舞也是随着邮轮会来回倾斜，要一边保持平衡一边完成动作，真的是一次很大的考验。所以最终录制完成的时候我也真的很开心！希望能让大家感受到这份快乐！～最后说一句：邮轮上真好吃呀！\n舞蹈、音乐：FANCY【Twice】', 7011544, 126468, -1, 8716, 7064, 67604, 75328, 5722, '2019-10-3 11:00:58', 211, 1, '2025-8-28 09:46:06', 0.0094478, -0.228119);
