INSERT INTO `videoinfo` VALUES ('BV1mP4y1o7Zk', '900264786', '11799651', '文物保护有多紧迫？看看山西就知道了【中国观察】', '俗话说地下文物看陕西，地上文物看山西。作为名副其实的“文物大省”，山西可是创造了不少“第一”。然而，由于山西的文物大多都是户外的，因此也面临着严重的保护难题。今天这个视频，我们以云冈石窟为例，来讲讲山西文物的辉煌，以及辉煌背后的保护困境和解决方案。', 459096, 11942, -1, 937, 790, 2324, 1741, 554, '2022-9-5 10:27:46', 730, 1, '2025-8-28 09:46:06', 0.00172628, -0.964778);
