INSERT INTO `videoinfo` VALUES ('BV1ms4116737', '6127940', '26798384', '囧知读书：约翰密尔《论自由》', '今天囧知想和大家一起读本书，《论自由》。这是英国哲学家约翰·密尔的著作，他的核心观点是：如果一个人的行为没有伤害到其他人的利益，那就是他的个人自由，这就是社会和个人的界限。他为什么会这么说呢？', 37359, 680, -1, 422, 224, 938, 787, 254, '2016-9-2 10:45:08', 239, 1, '2025-8-28 09:46:06', 0.00471081, -0.680044);
