INSERT INTO `videoinfo` VALUES ('BV1mv4y167oY', '566044797', '11799651', '十堰是二汽的十堰，二汽不是十堰的二汽【中国城市观察30】', '2021年，十堰的GDP是2164亿，在湖北能排第7。但是在上世纪八十年代，十堰却是湖北仅次于武汉的第二大城市，并且在全国的小康城市排名里，都能排到第六。\n不过，再往前到50年代，十堰又只是一个连城镇都算不上的“乡村”。短短半个世纪，十堰发生了什么？这期视频，我们来聊聊十堰。', 900643, 18331, -1, 5799, 2116, 4927, 3824, 3283, '2023-1-31 10:00:00', 646, 1, '2025-8-28 09:46:06', 0.00514468, -0.638652);
