INSERT INTO `videoinfo` VALUES ('BV1my4y1V7NH', '804932124', '98608863', '老粉福利｜我斗胆打开了微在不懂爱的老片', '哈喽，今天给大家带来的是完整版的微在「考古」reaction。哎，回顾当年，不懂爱时期的我也是做过不少大胆的内容，比如经常把「阴/茎」「阴/道」挂在嘴边，镜头前检查肌肉猛男的胸肌，大聊性/生活什么的。我当时一方面很坦然，认为这些词语和话题就是可以大大方方说的。不过，这次回看的时候 Yilia 就指出，以前的内容有些时候抓人眼球却有点欠考虑。这样看来，我们现在的节目虽然没有那么「刺激」，但也更谨慎和温和了，也是好事。我也想知道大家是怎么想的：你们是喜欢以前的还是现在的？欢迎在评论区告诉我们！', 72518, 6207, -1, 111, 509, 396, 1210, 300, '2021-8-16 10:32:36', 574, 1, '2025-8-28 09:46:06', 0.0040464, -0.743431);
