INSERT INTO `videoinfo` VALUES ('BV1n7411b7Go', '87732724', '138832847', '2020国产新剧预告（上），猜猜谁是爆款谁会扑街？【哇妹】', '谁曾想，我去年盘点里的剧，到今年都还没有播呢？？？\n影视寒冬积压了一堆剧，一半以上都没有在播！可恶！\n所以应该叫做这两年的新剧预测。\nPS：新剧毒奶分上下两期来做。\n上期以流量和公司的剧为主，\n下期主要讨论男频和女频。', 1374941, 42893, -1, 4725, 69906, 3858, 6272, 7952, '2020-2-9 07:08:10', 903, 1, '2025-8-28 09:46:06', 0.0123898, 0.0525635);
INSERT INTO `videoinfo` VALUES ('BV1N7411H76d', '86846403', '98608863', '你今天还好吗 03｜我举报了我妈的小卖部', '「你今天还好吗？」\n\n今天是每日打 call 的第 3 天，我的聊天对象是王中王，即 Blex（B姐），aka 王老湿，不知道微在的粉丝还记不记得他，他曾经是微在视频的搞笑担当，浑身是梗。\n\n这些都不及他最近做的一件大事：疫情爆发后，他妈妈经营的小卖部想要继续开张。因为担心安全和卫生防范不够，他打了举报电话。（如果你们认识他妈妈，不要告诉她老人家）', 19203, 835, -1, 75, 133, 41, 150, 94, '2020-2-5 05:14:58', 438, 1, '2025-8-28 09:46:06', 0.0229152, 1.05672);
