INSERT INTO `videoinfo` VALUES ('BV1N94y1S7fN', '341969944', '98608863', '通过5件事，我终于知道了「Alex」是谁', '当 @HBN颜究所 让我来分享“内心的光”的时候，我第一反应是，我是一个内心有光的人吗？我回忆了让我找到我自己的 5 件事，它们是记忆中的发光片段，它们组成了我内心的光。在梳理和拍摄的过程中，我慢慢意识到内心的光不需要是那种3000瓦大灯，它可以只是能照亮一个温暖角落的一束微光，你在那个角落可以看到是什么让你成为了你自己，可以看到是什么让你成为了你自己。#别忘了内心有光的样子#，TA是你这一路最好的伙伴。\n#HBN 养成发光肌#', 57332, 3786, -1, 149, 272, 461, 1419, 121, '2022-5-27 10:40:32', 795, 1, '2025-8-28 09:46:06', 0.00127629, -1.00771);
