INSERT INTO `videoinfo` VALUES ('BV1Nd4y1z7v5', '388340989', '98608863', '英雌ep4：我想要她的吻、她的钱、她的灵魂', '坦白说，这期英雌系列，我有点虎，勇敢给自己挖下大坑，上来就要扮演最性感、最先锋、最有钱的三个女人。\n\n这三位姐姐，她们都来自上个世纪，身上都有非常鲜明标签：女明星，女哲学家，女商人。她们身后留下疯狂的崇拜与恶毒的诋毁。但好像无论外界如何去评说她们的故事，我都不在乎。我只在乎我在她们身上看到的什么是美。是坚定地去做突破时代的表达，是永远要留一个角落给真实的自己，是从不掩饰自己的野性，去追求自己的渴望。时空转瞬，但，至美永恒。\n\n最后，点赞过 1 万，出 Cos 纯享版。', 48456, 5664, -1, 154, 96, 693, 2292, 103, '2022-9-21 12:49:34', 552, 1, '2025-8-28 09:46:06', 0.00740079, -0.42341);
