INSERT INTO `videoinfo` VALUES ('BV1nE411Z749', '70993171', '98608863', '我该为爱打扮、爱买买买而感到羞愧吗？', '我应该为爱打扮爱买买买而感到羞愧吗？\n\n面对这个问题，大部分人可能会回答：是的。\n\n一个女性经常买衣服打扮自己，别人可能会评价她「败家」、「花男人的钱」，但如果换到男性身上，别人的评价可能就会变成「注重仪表」、「有品位」。不同的人，不同的语境，经常买买买打扮自己得到的评价是不同的。关键是，如果一个人懂自己需要什么，懂得时尚单品背后的故事，还该为买买买而羞愧吗？', 35478, 2676, -1, 191, 224, 479, 996, 107, '2019-10-12 11:42:03', 301, 1, '2025-8-28 09:46:06', 0.00635061, -0.523602);
