INSERT INTO `videoinfo` VALUES ('BV1ne4y1M7sV', '648758054', '138832847', '2022国产剧十大女主角盘点，你最喜欢谁？【哇妹】', '《开端》李诗情/《二十不惑2》姜小果/《苍兰诀》小兰花/《亲爱的小孩》方一诺/《星汉灿烂》程少商/《摇滚狂花》彭莱/《风吹半夏》许半夏/《她和她的她》林晨曦/《大山的女儿》黄文秀\n即便是已经算非常完美讨人喜欢的女主角也会受到很多指责，更何况是那些不完美的女主呢？这反而变成了一种限制，对女性角色的创作的限制，希望大家对女性角色能多一些宽容，允许她们有一些人都有的小缺点，允许她们成长，允许她们不完美，让她们有多一点可能性，让我们能看到更多不同的女性形象?', 1482991, 61755, -1, 1486, 13206, 7987, 15674, 2657, '2022-12-16 10:00:00', 1127, 1, '2025-8-28 09:46:06', 0.00401374, -0.746547);
