INSERT INTO `videoinfo` VALUES ('BV1Nf4y1F7ky', '380828610', '98608863', '【我们招人啦！】一起做了60期节目后，聊聊幕后的蜜糖和砒霜', '2021年，我们频道一共做了60期节目。有微笑和眼泪，有欢呼和无尽的热浪。这一次我们三个专门坐下来，评选出这一年的最佳和最累作品，当然也分享了很多节目背后的故事。\n这是一次大型的心理按摩。一开始纷纷抱怨“做节目真难”的我们，在最后往沙发椅背上一靠，只有一句话想说，“真好”。\n引用Gaga一句话来总结，你看，就是我们这些人，在一起做了一件还不错的事儿。\n如果你也想加入我们，发邮件给我 mengran.chang@me.com，附上过往经历+作品+你想要加入我们的原因。期待认识你。', 33846, 3685, -1, 69, 923, 344, 1386, 168, '2022-1-18 11:25:25', 854, 1, '2025-8-28 09:46:06', 0.00113828, -1.02088);
INSERT INTO `videoinfo` VALUES ('BV1nf4y1r7Vs', '289063121', '2920960', '【360全景】吃个日料感觉自己像憨豆', '从上海回来就被隔离了，原本计划的视频搁置了。\n不过刚好，我拿来实验的全景VR视频可以与大家分享！（如果手机看不了可以用电脑看哦）\n原视频太长，所以剪了一部分有意思的内容。\n大家先看个乐儿！如果觉得好玩有意思想看更多这种全景视频的话可以评论告诉我！\n今后有合适场景和内容的话我会继续拍摄制作类似视频，到时候肯定比现在精良的多！', 1424916, 87260, -1, 6363, 7623, 4802, 22609, 3448, '2021-2-5 10:00:18', 452, 1, '2025-8-28 09:46:06', 0.013495, 0.158001);
