INSERT INTO `videoinfo` VALUES ('BV1Ng411o7VP', '511808057', '138832847', '国产剧终于又有穷人做主角啦！搞笑真实又感人的《欢迎光临》安利【哇妹】', '我最喜欢这部剧对这群小人物的塑造，他拍了现在电视剧缺少的普通人视角，它没有市面上流行的霸道总裁和傻白甜，男女主也没有开金手指，没有大奸大恶之人，大家都是平凡的小人物，生活总是一地鸡毛，但我们还是要扑棱着向前，每个人都是生活中的盖世英熊，即使平凡也能活得闪耀！', 1240163, 50715, -1, 3903, 3819, 3896, 6729, 1941, '2022-5-21 14:30:00', 602, 1, '2025-8-28 09:46:06', 0.00318432, -0.825677);
INSERT INTO `videoinfo` VALUES ('BV1nG411V77M', '430356641', '98608863', '大熊猫有 1864 只，但它们只有不到 150 只', '上个月，我接受了@云山保护   的邀请，又去了一趟云南苏典乡，重访「天行长臂猿」生活的地方。这趟旅程可以说是我整个夏天的高光时刻，想起它，我做梦都会笑醒。\n我希望用这期视频，带你一起去感受这趟深入山林和社区肌理的游历，我相信你的嘴角会跟着我们颠簸的车箱、颤颤巍巍的上山路、不怎么熟练的舞步，自然上扬。', 35029, 3949, -1, 268, 184, 501, 2531, 103, '2022-9-7 15:00:59', 1141, 1, '2025-8-28 09:46:06', 0, -1.12947);
