INSERT INTO `videoinfo` VALUES ('BV1Ng4y1W78M', '822291261', '98608863', '我们与上野千鹤子的距离｜共读《始于极限》', '为了增进本频道的知识水平和性别意识，我们在今年 1 月份特别录制了一期《始于极限》读书会。\n在铃木凉美和上野千鹤子的往复交流中，我们看到了很多和自己的处境密切相关的问题，我们在日常生活中是否有「厌女」的时刻，我们是否还会被「浪漫爱」的叙事左右我们对关系的判断。关于「Xing」的自主权，我们是否已经掌握得足够多。\n我们把这些问题抛给自己，希望在《始于极限》中用作者的经验去思考我们的现状，也把这些问题，抛给大家，希望在交流中，找到一些方向。\n\n我们有很多问题都没有答案，我们留下了那些悬而未决的遗憾和尴尬，也留', 399786, 34112, -1, 10291, 1256, 13658, 19010, 790, '2023-2-22 11:07:21', 844, 1, '2025-8-28 09:46:06', 0.00524387, -0.629188);
