INSERT INTO `videoinfo` VALUES ('BV1nT411v7CX', '482759324', '26798384', '几百块和几万块的自行车真有区别吗？自行车好玩在哪里？【柴知道】', '在20世纪80年代，作为“三转一响”之一的自行车，是人们通勤的必需品。40年后，自行车这种古老的交通工具，又以“潮玩”的形态卖出了高价，成了许多发烧友的心头好。几万块和几百块的自行车有什么区别？发烧友们在玩哪些自行车？山地车、公路车比普通自行车强在哪儿？', 710377, 30560, -1, 1298, 2098, 9628, 4516, 2206, '2023-3-2 09:30:00', 389, 1, '2025-8-28 09:46:06', 0.00556587, -0.598468);
