INSERT INTO `videoinfo` VALUES ('BV1nt4y1B7Pg', '628956993', '26798384', '【柴知道×索尼】人眼为什么擅长抓重点？如何让画面更吸引你的眼睛？', '通常人在看内容的时候，只会注意画面中的一小部分「重点」内容，其他非重点内容则会被自动忽略，这是由人的眼睛结构和认知模式所决定的。为什么你的眼睛这么擅长「抓重点」？XR 认知芯片如何知道你想看什么？我们从人类视觉系统成像规律出发，为你解答这些问题。', 103579, 7651, -1, 129, 554, 819, 1616, 364, '2021-2-3 04:33:34', 319, 1, '2025-8-28 09:46:06', 0.0101686, -0.15935);
