INSERT INTO `videoinfo` VALUES ('BV1NW411f7VX', '30724586', '116683', '【咬人猫】BAAM❤️武装喵命中你了吗o(*≧▽≦)ツP2竖屏版', '暑期三部曲的最后一作来啦！这一次带来的是“武装喵”，想要尝试配合歌曲里多类似枪的元素。很喜欢momoland的风格，因为也是看了她们的舞蹈会很开心，经常练舞的间隙都会放她们的歌来换换感觉，这次也终于正式的尝试了～这也是第一次挑战完全的韩舞风格，很紧张～也不断的又发现很多不足的地方，这也是我接下来努力的方向。但是能完成这一作我也已经很开心了，希望大家在我新风格的舞里也能看的开心，感谢你们。\n视频中道具均为玩具，请大家不要随意效仿呀。\n原曲/舞：MOMOLAND/BAAM', 3372089, 76036, -1, 14203, 9524, 52637, 111743, 7638, '2018-8-30 12:11:40', 226, 1, '2025-8-28 09:46:06', 0.0101145, -0.164509);
