INSERT INTO `videoinfo` VALUES ('BV1nW411y7ot', '31715666', '116683', '【咬人猫/有咩酱/赤九玖】155小分队❤️三只血小板的UNI❤️o(*≧▽≦)ツP2竖屏版', '时隔两年，大家终于又有时间能再聚在一起的跳舞，155小分队也算是回到一个原点重新出发，就像最早合作的作品一样，一起开心的舞蹈是最重要的。所以选择了UNI这样一首简单欢乐的歌～这次也是第一次尝试在舞蹈里融入这么多玩耍的小剧场小分镜，感谢155的大家，陪着我一起去完善去优化它！整个录制过程我们现场都跳的很欢乐，也希望最后的成品大家能看的开心！我们也希望尽快再能凑准时间，为大家带来155小分队更多更好更不一样的作品！\n99：2年了终于又一起跳舞了，超开心惹~  \n有咩：开开心心的一作~\n舞蹈编排：咬人猫  音乐', 1908111, 58494, -1, 13402, 6593, 32521, 79088, 5099, '2018-9-14 13:42:12', 351, 1, '2025-8-28 09:46:06', 0.00933312, -0.239059);
