INSERT INTO `videoinfo` VALUES ('BV1o54y197ZP', '840385803', '26798384', '【柴知道】朋友，来一针干细胞吗？', '还记得前两年“富豪60万一针干细胞续命”的新闻吗？从生物学和医学角度来看，干细胞确实具有神奇的能力——因为它可以“再生”。所以，这些富豪注射的干细胞究竟是什么？假如你有钱了，有必要来一针吗？美容院里的“干细胞美容”项目靠不靠谱？我们和中科院一起回答了这些问题~', 118759, 11002, -1, 994, 542, 1821, 4196, 376, '2020-4-30 11:02:09', 285, 1, '2025-8-28 09:46:06', 0.0189819, 0.681467);
