INSERT INTO `videoinfo` VALUES ('BV1o841147F8', '218538594', '98608863', '女人的战场不在产床【国际月经简报·ep 8】', '这个月，天气转凉，但女性的「战场」，水深火热。\n月经简报继续与你一起，见证这个世界上与女性、与每一个人有关的大事小事。\n\n· 英国女王去世，她向全世界的女性留下了怎样的遗产？\n·《龙之家族》毫不避讳地拍出了残酷、血腥的分娩场景，在向我们传达什么？\n· 高铁售卖卫生巾挑动着谁的敏感神经？\n· 伊朗女性被鲜血点燃，她们想要焚烧的，不只有头巾，还有腐朽与枷锁；\n\n这个月的消息有点沉重，有些时候面对这些事件，会让我们觉得前路茫茫。但我依旧相信，流星陨落，就会有人在瞬间被照亮，火焰升起，就会有腐朽被焚烧。', 122964, 12834, -2, 1448, 0, 2248, 8192, 247, '2022-9-30 10:29:34', 452, 1, '2025-8-28 09:46:06', 0.00341016, -0.804131);
