INSERT INTO `videoinfo` VALUES ('BV1oG41147aY', '429865833', '98608863', '我们开了一个 7 小时的会，只为了说出对方的缺点', '2年前，我立flag要做一个好老板，为此，我做了一个不一样的尝试。\n网飞创始人在《不拘一格》这本书中提到了 360 度面对面反馈，我仿照这个形式，把团队聚在了一起，花了 7 个小时的时间，来说说每个人身上的毛病，坦白工作中遇到的不舒服的地方。\n过程当中，有人哭、有人笑、有人委屈，有人惶恐，但是结束时，我们彼此拥抱，好像收获了更亲密的关系。我们学会让「负面」的感受，成为积极的开始。我们在用真诚和善意，让那些不好听的话，变成有效的帮助。', 81379, 7631, -1, 1264, 612, 1731, 4598, 293, '2022-8-24 14:12:31', 1261, 1, '2025-8-28 09:46:06', 0.000686814, -1.06395);
