INSERT INTO `videoinfo` VALUES ('BV1oLt9ezEKH', '113165425712918', '2920960', '排了俩小时队才吃上的意大利面条，看看凭啥这么火？', '店名：CAPARESH 開府菜舍  位置：北京市朝阳区银泰中心B1\n\n意面这玩意做到头也终归是意面，虽然很出名，排队人很多，但我不觉得这家意面有多特别。但是作为西餐厅，这家出品是完全对得起价格的，这应该也是排队的主要原因。\n\n推荐指数个人向：★★★\n★★★★★（如果条件允许每月都会忍不住吃一两次）\n★★★★（有第二次去的冲动，也有推荐朋友去吃的想法） \n★★★（还不错，但暂时没有再去的想法） √\n★★（个人不喜欢，因人而异） \n★（太拉了，什么鬼？？？） \n\n淘宝唯一店铺：大祥哥来了', 662557, 40116, -1, 926, 2631, 2731, 17159, 700, '2024-9-20 10:00:00', 654, 1, '2025-8-28 09:46:06', 0.00450153, -0.70001);
