INSERT INTO `videoinfo` VALUES ('BV1os411t7MT', '6473104', '26798384', '科普：什么是水的酸碱性？', '你可能听过一个说法，叫“喝碱性水对人体更健康”。当然，这是一个没有任何科学根据的谣言。如果我们从分子层面，了解了“酸碱性”的本质，就会发现：我们喝的水偏酸或者碱，在强大的人体自我调节能力面前，并没有任何差别。', 53324, 256, -1, 260, 406, 641, 653, 314, '2016-9-30 12:40:26', 166, 1, '2025-8-28 09:46:06', 0.00606906, -0.550462);
