INSERT INTO `videoinfo` VALUES ('BV1oT41137ho', '470491452', '2374194', '【古筝】伯牙子期传闻故地再觅知音！高山流水时，江城鹤归处！', '黄鹤何年去杳冥，高楼千载倚江城。《一梦江湖》国风十二城联动·武汉站终于来啦，城市拟人款时装“江城鹤归”上线~“江城鹤归”取煌煌之金与湖水之碧为主要配色，以仙人费祎在黄鹤楼骑鹤归去的传说为灵感，多处运用仙鹤刺绣与祥云纹样，男女款式分别以夹江相望的黄鹤楼与晴川阁为设计元素，互为衬托，别有风趣。\n而此次所奏的乐曲节选自浙江传统筝曲《高山流水》。琴师于“高山流水”传说的起源地——江城武汉弹奏此曲，舞者循声而去。两人辗转于城中、寻觅途中经黄鹤楼、晴川阁等多个经典人文景观，最终蓦然回首，相遇在东湖畔。\n音乐-筝曲《高', 193472, 8395, -1, 263, 181, 1260, 1465, 212, '2022-7-2 10:00:25', 218, 1, '2025-8-28 09:46:06', 0.00389281, -0.758084);
INSERT INTO `videoinfo` VALUES ('BV1ot411M71v', '61885213', '2374194', '【墨韵】无羁（古筝/钢琴）-《陈情令》主题曲', '无羁这首曲子感觉柔中带刚，所以这次的改编没有在旋律上加太多技巧，只在间奏部分推了一下情绪。总体来说，是想呈现一个完整的器乐曲的结构，希望大家喜欢。\n\n作曲：林海\n编曲/钢琴：杨文昭\n古筝改编：墨韵\n录音/混音：刘嘉伦\n摄影/后期：余林峰', 1566223, 108000, -1, 12204, 6594, 58327, 81759, 3832, '2019-8-2 10:33:19', 184, 1, '2025-8-28 09:46:06', 0.00898303, -0.272459);
