INSERT INTO `videoinfo` VALUES ('BV1oU421Z72s', '1500243597', '98608863', '「梦里啥都有，现实中就别争了」', '欢迎来到最新的 #国际月经简报#。这个月我们准备了4条消息，从尓滨与南方小土豆的纠葛，到「美国小姐」泰勒·斯威夫特成为年度人物，一起来看看，刻板印象中被矮化的女性和在追求平等中自我赋权的女性。\n这档栏目成为本频道坚持最久，最有生命力的内容之一，是因为它何尝不是这个世界和女性相关的大事小事的一个简介。我们分享这些难过的、荒谬的、有趣的、有希望的故事，是因为我们可以一起去抵抗外界对女性的矮化，去决绝陷入「娇妻」的陷阱，去识破规则的不合理，去看到真正闪亮的女性叙事。\n今年就是这样，让我们来年继续聊！', 161906, 33648, -1, 2392, 872, 6350, 20695, 460, '2024-1-30 10:00:00', 584, 1, '2025-8-28 09:46:06', 0.00701286, -0.46042);
