INSERT INTO `videoinfo` VALUES ('BV1ox411K7VK', '1113839', '116683', '【咬人猫/有咩酱/赤九玖】虎视眈眈❤155小分队第三作o(*≧▽≦)ツ', '155小分队这个51全在成都合舞中度过，录到最后一天才有了现在的版本。投稿前想起来这段日子又累又充实，也许这正是宅舞带给我们的快乐和回忆，希望能分享这份快乐。也想努力尝试一支和以往不一样风格的舞蹈。不足之处请大家见谅。感谢摄像@argonium还有辛苦陪伴我的老婆@矮乐多Aliga（现场激动打板的样子真是太萌啦）本家：sm22110492使用音源：sm22221659振付：sm22987614。', 2427652, 7082, -1, 7275, 20177, 30817, 11776, 1817, '2014-5-9 19:55:43', 656, 1, '2025-8-28 09:46:06', 0.00748169, -0.415692);
INSERT INTO `videoinfo` VALUES ('BV1oX4y1b7HV', '356834720', '2374194', '【指弹古筝】《卡农》从入门到出门', '首先感谢陆晶老师将爱筝借给我，让这次的卡农更加完整了～这个13弦的小古筝真的太可爱了！\n\n卡农是一首整体非常清淡的曲子，正好用来展示一下我最近开始玩的不同形制的古筝。视频中分别是13弦、21弦和26弦，其中21弦区分了传统五声定弦和为了这个曲目而设计的特殊定弦。可以看到五声定弦可以通过按音来完成fa和si，但左手不能演奏会让声部有些不连贯。特殊定弦的21弦古筝对这首曲子已经可以有较高完成度的表现，但势必省略一些音（此曲是re）来调出fa和si，而过于密集的调音会让高音的弦很松，低音的弦很紧，导致音质的损失', 603148, 42653, -1, 3023, 1396, 10894, 20761, 910, '2023-5-31 10:05:00', 239, 1, '2025-8-28 09:46:06', 0.00757979, -0.406333);
