INSERT INTO `videoinfo` VALUES ('BV1oyfnYzEF3', '113882668470780', '2374194', '【指弹古筝】东方弗朗门戈《卡门/Carmen 》- Marcin版翻奏', '去年和Marcin简单互动后，终于把完整版的《卡门》拿下了，不得不说Marcin的段落设计太精彩了！所以即便时隔多年再次遭遇腱鞘炎，依然觉得此次翻奏很值得。\n\n原曲中切换了两种吉他，虽然26和21弦筝没有很大的音色差距，但也确实需要两种不同定弦的筝，才能完成整首曲子。Marcin改编的一大特点是即便旋律有重复，大量细微的节奏变化、泛音点缀和音效加持也会让曲子充满新鲜感和视听冲击力。我也在移植过程中学到了很多。\n\n其实我最近才发现在以往视频的评论中，这首《卡门》早就被多次提及。观众朋友们真是慧眼如炬！希望大', 302673, 21416, -1, 879, 379, 3810, 8612, 453, '2025-1-28 05:00:00', 165, 1, '2025-8-28 09:46:06', 0.00624853, -0.53334);
