INSERT INTO `videoinfo` VALUES ('BV1P1AHeYEKs', '114034670048255', '389400079', '长白山天池住着朝鲜人！朝鲜幸福指数高？免费住新房？', '欢迎搭乘小白胖极寒边境之旅！一起探秘神秘的长白山和朝鲜吧！这一次咱们继续从吉林省白山市临江市出发经过长白县、二道白河镇抵达长白山！在长白山脚下等了一周终于去看了天池，结果雾大风大。。。我俩不愧是天弃之子！感谢长白山文旅借了我们天池素材！！虽然在山脚下等了很久，但是二道白河镇也很好玩，各种朝鲜族美食～火山温泉～雾凇漂流～雪绒花乐园～还有云顶天宫！简直是巨大的盗墓笔记痛城！', 735077, 14307, -1, 735, 2312, 3319, 3505, 758, '2025-2-20 10:00:00', 1158, 1, '2025-8-28 09:46:06', 0.00266241, -0.875469);
