INSERT INTO `videoinfo` VALUES ('BV1P4411p7e2', '54142108', '116683', '【咬人猫】AIAIAI❤️MV版！爱酱穿越时空的降智打击！o(*≧▽≦)ツ', '请大家感受来自爱酱的降智打击吧！其实这是屏幕里寂寞的爱酱想和大家一起玩的故事呢~服装参考的是碧蓝航线联动爱酱的和风版本，这一作是拍摄AIAIAI舞蹈视频的时候很意外诞生的一作，感谢导演/编剧：萧影的临时一阵头脑风暴，就创作出了这个有趣的小故事，很感谢现场即兴来帮忙拍摄和群演的大家！当天拍到了第二天早上6点才收工，大家都非常非常辛苦了～第一次尝试剧情MV的形式录制，希望你们也能感受到视频中的欢乐哦！也祝接下来要高考的大家能取得好的成绩哟~\n场地：光影折学影视工厂\n原版视频：av47832767', 2442591, 91189, -1, 5048, 2804, 38105, 76943, 7583, '2019-5-31 11:27:15', 253, 1, '2025-8-28 09:46:06', 0.0119822, 0.0136731);
