INSERT INTO `videoinfo` VALUES ('BV1P54y1e7BL', '844339890', '26798384', '【柴知道】如何科学投资你的辛苦钱？科学理财为什么这么难？', '每一位大师都会告诉你，“不要把鸡蛋放在同一个篮子里”。但真正的难题是，到底要怎么把本来就不多的钱，科学地分配到不同的资产下呢？我们从这个问题出发，介绍了“现代资产组合理论”，以及投资中的一些基本常识，希望能和你一起探索科学的理财方式~', 190956, 14039, -1, 1546, 990, 4756, 5956, 494, '2021-2-20 10:01:32', 398, 1, '2025-8-28 09:46:06', 0.00450811, -0.699382);
INSERT INTO `videoinfo` VALUES ('BV1P54y1S7TB', '838874320', '122879', '2002年画面最好的沙雕游戏', '囧的呼唤275期(下)\n大家千万不要因为这期视频就头脑发热预购四海兄弟重制版,1代和重制版不是一个制作组弄的。我们也不知道重制版是不是优化良好，BUG会不会多，而且也不知道重制版最后能还原多少1代的风采。所以劝大家理性，等重制版发售后看看口碑和评价再购买也不迟，不要冲动去预购。', 3918874, 204968, -1, 3849, 13713, 25219, 78239, 3349, '2020-7-11 04:00:48', 618, 1, '2025-8-28 09:46:06', 0.00926365, -0.245687);
