INSERT INTO `videoinfo` VALUES ('BV1p741187QJ', '87447244', '98608863', '你今天还好吗 06｜她在胳膊上文了个口罩', '#你今天还好吗#系列第 6 天，连线对象是@BIE别的女孩 的内容负责人阿丽，Alexwood，我在微博里介绍过她和她做的内容。因为名字，每次我们一起做播客节目都得「隆重」介绍清楚她是谁我是谁，现在是哪个 Alex 在说话。\n比起在播客上聊的性别平等话题，这次我俩随意发挥了。最亮眼的是她的新文身：一个口罩，也是一种记录的方式。\n阿丽提个了好问题：看起来我们都还要在家工作一段时间，怎么适应这种状态？怎么让自己在家也高效率的工作呢？大家有什么自己的方法吗？', 15511, 789, -1, 79, 109, 36, 139, 66, '2020-2-8 04:00:25', 575, 1, '2025-8-28 09:46:06', 0, -1.12947);
