INSERT INTO `videoinfo` VALUES ('BV1PC4y1V76m', '747337031', '98608863', '我问张婉婷为什么没离婚，她说因为「战斗有效」', '婉婷想要被看到，是因为她敏锐地意识到，那些关系中情绪劳动不应该是默认的「妻子的义务」，那些传统的「性别分工」里本来就有很多地方逻辑不通。\n\n宋老师包容婉婷，或许他也知道自己的不表达，隐忍，陷入自己的世界也会成为关系中的一颗炸弹。\n\n或许按照传统的观念，忍一忍，让一让，大家各退一步婚姻就这样凑合地过下去。但婉婷不想要「破破烂烂的日子」，我们也不希望这个社会的「厌女症」可以被假装看不见，去像一个斗士一样，为我们自己争取，或许头破血流，但正如婉婷说的那样「战斗有效」。', 206719, 7062, -1, 2557, 1217, 2526, 4371, 507, '2023-10-19 13:47:45', 1785, 1, '2025-8-28 09:46:06', 0.0076599, -0.39869);
