INSERT INTO `videoinfo` VALUES ('BV1pE4m1R7Ev', '1256247853', '26798384', '“互相抄袭”还是“趋同演化”？“风”为什么让汽车外观越长越像？【柴知道：车圈化简】', '路上开过十辆车，其中七辆可能都长得差不多～在如今的车圈，有越来越多的轿车，都长成了相似的模样。有人说这是在抄袭模仿，也有人说这是在趋同演化，但还有那么一个原因，经常被人忽略——那就是：“风”。是风，把车吹成一个模子了。为什么如今的汽车外观越来越无聊了？“风”是如何让汽车设计，变得千篇一律的？“风阻系数”到底有多重要？这期视频将从空气动力学的角度出发，和你一起来看看风是怎样把车都吹成了一个样子～', 603419, 15896, -1, 493, 1648, 3458, 3744, 1034, '2024-7-9 09:30:00', 402, 1, '2025-8-28 09:46:06', 0.00405017, -0.743072);
