INSERT INTO `videoinfo` VALUES ('BV1pf4y1h7ew', '290761199', '2374194', '【古筝】咒术回战ED —— 迷之女子的迷之舞蹈', '兄弟们姐妹们父老乡亲们，之前看你们在评论区说想看LOST IN PARADISE，我直接一个鲤鱼打挺开始搞！但是，大哥你是了解我的，不会跳舞啊qwq，我只会迷之抖动～有一说一这波真的尽力了，再跳人没了。演奏的部分，主旨是跟着这个随性的节奏摇就完事儿了，还原了一些萨克斯得二声部，也加了很多滑音，以至于听起来有一些奇妙的东方味23333。希望大家喜欢，以后还有别的曲目推荐也可以在评论区留言哦～\n\n原曲：LOST IN PARADISE（楽園放浪）- 片尾曲1\n古筝演奏/改编：墨韵随步摇\n录音/混音', 260222, 30295, -1, 1098, 722, 6111, 11585, 701, '2021-5-28 10:00:00', 99, 1, '2025-8-28 09:46:06', 0.0129375, 0.104814);
INSERT INTO `videoinfo` VALUES ('BV1Pf4y1M7qx', '379205338', '98608863', '入坑心得：一个读不下去书的人，如何爱上读书?', '你爱读书吗？原来的我一直是：买书从不犹豫，但真正翻开书却看不下去几页。最近我有意识的留意那些爱读书人的方法论，发现自己身上有了积极的改变，这期视频分享一下我的入坑心得，建议搭配视频更加清晰明了！\n\n1.每天专门安排读书的时间\n2.用记读书笔记提高阅读的互动体验\n3.不管读的什么，只要去读就好了，会形成不可阻挡的惯性！\n\nP.S. 这期视频除了这些，还顺带推荐了几本我最近读过的书，之后也许会分享我的阅读文具和我读英文原版书的方法（我的英语最高段位是CET-6），感兴趣的朋友可以评论或者弹幕告诉我！', 90812, 7863, -1, 433, 810, 3271, 3441, 273, '2021-11-15 11:35:33', 556, 1, '2025-8-28 09:46:06', 0.00197557, -0.940995);
