INSERT INTO `videoinfo` VALUES ('BV1PK411j7Ti', '497765618', '138832847', '【科普SEVENTEEN】歌好听、舞超齐！团魂满分的小十七治愈向安利！【哇妹】', '粉丝和成员真正想要的是SEVENTEEN长久走下去！\n走过的五年，获过大赏，也负伤。\n但是唯一没有想过的就是放弃。\n不负来时路，不负少年梦，\n不负身边人，不负应援海。\n哇妹希望一步一个脚印的小十七，\n可以走得更长远！\n我们和十七还有很久很久的未来可以相伴！\n\nP.S.大型团太难了，十个标签不能同时拥有13个人的名字！(╥ω╥`)\n部分视频资源出处：@SEVENTEEN_Harbour站  @SEVENTEEN_ZER·0站 @西游字幕', 1011906, 56160, -1, 12004, 18419, 19613, 31387, 7270, '2020-4-19 04:00:04', 602, 1, '2025-8-28 09:46:06', 0.00280138, -0.862211);
INSERT INTO `videoinfo` VALUES ('BV1pK411j7YX', '497794736', '116683', '【咬人猫】在外太空蹦迪！蒂法喵❤️疑心暗鬼！', '在收藏夹里放了很久的一支帅气风的宅舞，今天终于产出啦！这次很开心受邀OPPO的合作，录制现场也用OPPO Ace2手机播放了BGM一起参与了这次录制，感受到闪充厉害了～Ace2手机将于4月20日开售，大家上天猫预订有礼有礼哟！\n这次的舞蹈我努力控制着往表情包，努力的想要跳出舞蹈的帅气感觉，不知道大家有没有被酷到鸭（并没有）！希望大家看的开心，挑战不常尝试的风格总还是会有一些遗憾，这次也因为场地确实很滑，导致没能发挥出最好的感觉，下一次我也会注意并且继续努力加油的！\n感谢ATY的编舞：sm23979969', 3833845, 114569, -1, 7434, 15821, 40071, 59757, 4627, '2020-4-18 12:00:52', 625, 1, '2025-8-28 09:46:06', 0.00714455, -0.447857);
