INSERT INTO `videoinfo` VALUES ('BV1Pk4y1b7bg', '738950809', '116683', '这小短腿可莉害了！❤️【咬人猫】', '给大家介绍我可爱的女儿！小可莉！一直都很想cos可莉去雪山下拍可莉版105°，终于在美丽的云南圆满了！小小可莉来炸鱼咯，不要告诉琴团长嗷！\n感谢“血盟工作室”的装备帮助，感谢荣小兔头的协助\n感谢编舞@阔少_申旭阔：BV1FK4y1V7wS\nBGM：《热爱105°C的可莉》原创填词版-蕾米Remi\n原唱：《热爱105°C的你》-阿肆', 1780910, 116324, -1, 5537, 931, 23937, 44337, 1964, '2023-3-24 11:00:00', 100, 1, '2025-8-28 09:46:06', 0.0058848, -0.568042);
INSERT INTO `videoinfo` VALUES ('BV1pK4y1s7Db', '883744021', '11799651', '说真的，还有比高考更公平的事吗？【中国观察】', '对于个人来讲，太过纠结大环境到底好或者不好意义并不大。\n大环境好或者不好，都一定有人可以好。希望那个人是你。\n今年很难，但我们不怵。祝所有即将高考的小伙伴不负青春乘风破浪，也祝所有人顺利。', 268373, 14726, -1, 753, 2574, 3286, 2621, 2686, '2020-7-5 02:53:15', 609, 1, '2025-8-28 09:46:06', 0.00843652, -0.324598);
