INSERT INTO `videoinfo` VALUES ('BV1PkTezMEek', '114652306544568', '98608863', '【国际月经简报ep.33】｜占领太空、占领舞台、占领话语权', '欢迎来到这个月的国际月经简报。我们看见女性的故事，ta们在宇宙中前行，在舞台上重生，ta们被边缘，在习俗中被物化，也在法律中被保护。\n\n1.蓝色起源：当全女性队伍飞上太空\n“蓝色起源”成功发射首个全女性太空旅程队伍。6名女性中包括歌手、飞行员、科学家、企业家与环保倡导者。虽然是科技巨头主导的太空项目，却意外成为展示“性别参与平权”进展的窗口。这不是粉饰性的“女性时刻”，而是技术与性别叙事终于汇合。\n\n2.法律可以决定谁是“女性”吗？\n4 月 16 日，英国最高法院裁定了什么是女人。根据判决，法律上“女性”', 20035, 3352, -1, 135, 226, 558, 2627, 128, '2025-6-9 10:00:00', 817, 1, '2025-8-28 09:46:06', 0.00387327, -0.759949);
