INSERT INTO `videoinfo` VALUES ('BV1pm411z7BA', '1902653846', '26798384', '人死之后会再社死一次吗？你在网上的秘密守得住吗？【柴知道：人生大题】', '人终有一死。最开始，人们许愿希望死后家里人不要翻日记。过几年，人们许愿死后能一键格式化硬盘。而现在你要操心的是，你的聊天记录，浏览历史，在QQ 空间等地发过的疯、犯过的蠢、经历过的尴尬，还会被人翻箱倒柜，社死一次吗？去世之后，我们留在虚拟世界的帐号、财产，究竟要如何处理？', 284468, 17946, -1, 928, 892, 6103, 7011, 1057, '2024-4-2 09:29:37', 483, 1, '2025-8-28 09:46:06', 0.0234105, 1.10397);
