INSERT INTO `videoinfo` VALUES ('BV1q7421f7Hb', '1654722909', '26798384', '“我怎么可能得带状疱疹？！”埋在每个人体内的雷，在她身上爆发了【柴知道】', '清明节前夕，柴司的设计师六月姐姐突然手臂抽痛、长满水疱，疼痛感类似于脱臼、电击，每过几秒钟就抽一下，痛不欲生——去了医院发现，她得了“带状疱疹”。此时我们才知道，原来我们每个人的身体里，都有水痘-带状疱疹病毒。我们记录了她一个多月的真实经历，在科普的同时，也祝愿大家能逃过一劫～', 304760, 11209, -1, 2765, 1331, 2384, 2590, 1471, '2024-5-17 10:00:17', 503, 1, '2025-8-28 09:46:06', 0.0242915, 1.18802);
