INSERT INTO `videoinfo` VALUES ('BV1QP4y1b7Xm', '890821663', '26798384', '为什么你的头会秃成M、C、U型？拿什么拯救你的发际线？|【柴知道×HeyBro】', '在全中国，有21.3%的男性患有“雄激素性脱发”。就算你年纪轻轻，也可能一不小心就把头秃成M型、C型或U型。为什么你会脱发？如何判断自己是否有脱发风险？以及该如何科学地治疗脱发？我们从脱发的原因，和防脱药物的原理出发，带你一起拯救越爬越高的发际线~', 203548, 10836, -1, 3601, 761, 4242, 3054, 1110, '2021-10-8 10:00:09', 388, 1, '2025-8-28 09:46:06', 0.00930419, -0.241819);
