INSERT INTO `videoinfo` VALUES ('BV1qs411b7BA', '8182926', '116683', '【咬人猫】PiNK CAT❤o(*≧▽≦)ツ', '这次真正的当了一次“咬人猫”，看了很多版本的PINK CAT，结合歌词自己也有了一些小的想法，小细节有做一些改动。跳舞的时候真的全部精力投入的安心的当一只“猫”，很忐忑这样的风格我能做好吗...只希望大家看的开心就好！由于录制场地条件限制，整整录了12个小时，凌晨4点过才完成，眼睛到后面也终于有点累了，录完才发现自己左眼不自觉的在闪，我安慰自己，我这是在疯狂wink…舞蹈上还有不足也说明自己还需要继续努力！谢谢大家一直以来的支持和鼓励！最后提前祝大家春节快乐！编舞：sm26045105', 3875979, 16539, -1, 11410, 13084, 48279, 115838, 7320, '2017-1-23 16:02:02', 241, 1, '2025-8-28 09:46:06', 0.00699809, -0.46183);
