INSERT INTO `videoinfo` VALUES ('BV1Qs411C7Sp', '5682645', '116683', '【咬人猫】落花情❤ o(*≧▽≦)ツ', '也许是有史以来最忐忑的一次投稿，这次尝试的风格对我来说挑战很大，完全没有这类舞蹈的基础，所以当时这支舞挖坑填了一段时间因为实在是能力有限，被我搁置了很久～后来因为确实是太喜欢这种感觉的舞蹈了，又重新鼓起劲去学，也尝试了不同的服装版本录制了很多次，非常想完成这一支舞，虽然还有很多地方不够好，也希望大家多多包涵，谢谢大家的支持和等待～\n服装：七秀萝莉定国套\n舞蹈歌曲：七朵组合（一代）的作品《落花情》。', 4055745, 18729, -1, 15495, 18409, 57310, 115476, 8047, '2016-8-6 12:20:45', 227, 1, '2025-8-28 09:46:06', 0.0056143, -0.593848);
