INSERT INTO `videoinfo` VALUES ('BV1QT4y1c72p', '927365267', '11799651', '住全球第一豪宅，给祖国采购二手战机，印度首富的黑暗发家史【世界观察】', '印度首富安巴尼最开始出现在中文互联网的视野，大概是源于那栋修在孟买贫民窟旁边的全球第一豪宅。\n今年中印冲突的关口，印度疑似买了法国掉漆的二手战机，军购案背后的大BOSS又是这位安巴尼。\n从开局500美元，到如今1500亿美元的商业帝国，印度首富家族的发家史也是印度国企私有化的发展史。\n\n今天这期视频，我们来扒一扒这位印度首富以及印度畸形的国企私有化战略。', 237432, 8249, -1, 268, 1343, 1375, 1407, 307, '2020-10-2 09:57:42', 1142, 1, '2025-8-28 09:46:06', 0.0108792, -0.0915622);
