INSERT INTO `videoinfo` VALUES ('BV1Qt4y1k7cL', '628263186', '98608863', '这个喜欢异形的设计师承包了我全部的耳饰！｜姑娘家家', '这期视频是新系列“姑娘家家”的第一期，我会在这个系列的视频中带你们去一些姑娘的家中进行 room tour，并把我欣赏的这些姑娘介绍给你们。\n\n今天我要讲的是独立饰品设计师——冬尾。她拥有超级酷的异形模型，喜欢当代艺术却时不时地写写毛笔字，她的饰品设计总是很大胆，像是来自外太空。\n\n冬尾没学过设计，但她觉得感兴趣，并且认识到当热爱的事情变为职业，就要接受它好和不好的方面。愿冬尾的故事也可以鼓舞你去追寻自己的理想❤️', 62371, 5016, -1, 152, 269, 459, 678, 229, '2020-12-28 13:17:27', 709, 1, '2025-8-28 09:46:06', 0.00276217, -0.865951);
