INSERT INTO `videoinfo` VALUES ('BV1qZ4y197Ex', '379724006', '26798384', '《废钢重生之路》|【柴知道×华为云】', '你目力所及的，都是成团出道的好钢铁。但那些曾经献力后被报废的钢铁——也就是「废钢」——同样有着大用。它们不仅能降低钢铁生产成本，减少环境污染，还能减轻我们对进口铁矿石的依赖。为什么说废钢并不「废」？如何科学有效地鉴定废钢？怎样才能让废钢投胎重生？', 256315, 17525, -1, 277, 527, 1901, 2731, 413, '2021-12-10 03:39:07', 364, 1, '2025-8-28 09:46:06', 0.0122192, 0.0362866);
