INSERT INTO `videoinfo` VALUES ('BV1r1S2YYEsB', '113418661207758', '98608863', '现在还不是庆祝的时候 | 【国际月经简报 ep.28】', '来了来了，这个月的国际月经简报来了。本月我们准备了 4 条消息，她们与女性的痛苦作战，书写自己的人生。\n\n1.韩江获得诺贝尔文学奖，希望更多人可以去阅读韩江的作品，在阅读中超越残忍与暴力，向人性之美伸出手来。\n2.时隔 6 年维密秀回归，没出错，但也没惊喜，我们很庆幸它过时了。\n3.法国奶奶被强奸，涉案人数超过 50 人，她站上原告席，用自己的勇气让法国司法去回答“性别”的问题。\n4.全球第一夫人学校是个什么组织？这些身居高位的女人还有什么需要学习？\n\n接下来，国际月经简报希望可以形式更有趣，内容更深度去', 156707, 31454, -1, 965, 527, 5728, 19860, 391, '2024-11-3 11:01:31', 674, 1, '2025-8-28 09:46:06', 0.00621577, -0.536465);
