INSERT INTO `videoinfo` VALUES ('BV1R3411Z7Gg', '435400829', '98608863', '你不该错过这些节目，和这些大奖！', '辛苦一年啦，按照绝对是个妞的传统，一定要在过年之前，自夸自擂一下，让满满的成就感来给我们做一下心理按摩。相比去年我们只有 3 个人，今年看上去真的是齐齐整整的一个团队了。\n今年我们做了六十多期节目，这些节目，为你们而做，也为我们自己而做。有自我暴露，也有抱团取暖。有不同观点的求同存异，也有不可撼动的心中信念。\n这是我们春节的最后一期节目啦，我们每位成员都给大家准备了礼物，留言夸夸我们，也写下你希望我们进步的地方，我们会从转赞评中抽粉丝送礼啦。\n最后，祝大家新年快乐，我们收工啦，兔年再见啦！', 42602, 5032, -1, 463, 586, 927, 3332, 615, '2023-1-17 12:58:30', 1240, 1, '2025-8-28 09:46:06', 0.000625914, -1.06976);
