INSERT INTO `videoinfo` VALUES ('BV1r441167gc', '65442886', '98608863', '用「女汉子」或「娘炮」评价别人，算歧视吗？', '这次我们邀请了 40 位男孩女孩（和 1 位阿姨）做了一个社会实验，看看大家的价值观相差多少。\n\n第一题：知名送命题「你妈和我掉水里了你救谁」，如果你的另一半选择救 TA 妈妈，你会介意吗？\n\n第二题：你愿意和收入比你低一半的对象结婚吗？\n\n第三题：用「女汉子」形容女性是歧视吗？\n\n第四题：用「娘炮」形容男性是歧视吗？\n\n你的答案是什么？欢迎在评论里告诉我们。', 24831, 1732, -1, 212, 229, 268, 585, 242, '2019-8-26 12:00:13', 401, 1, '2025-8-28 09:46:06', 0.0422333, 2.89973);
