INSERT INTO `videoinfo` VALUES ('BV1r44y137Z3', '980688328', '98608863', '是使命带领我，辞职回家带娃【成为母亲 Ep.5】', '「你是一个奇迹，我也是。」\n\n这是 Sabrina 经常对自己的宝宝说的话，她现在是一位全职妈妈。\n\n她是一个很有「觉知」的妈妈，她会不断的提醒自己，他是他，我是我，我生了他，并不代表我拥有他。\n\n在育儿上她也有一套独特的方法，叫做尊重回应式育儿。她把自己的宝宝当作一个独立的个体，而不是没有行为能力的婴儿。\n\n在 Sabrina 看来，成为母亲，并没有让她失去自我。母职的体验放大了她的感官和事业，明确了自己的使命感和想做的事。\n\n这就是第五期久违的「成为母亲」，希望你们喜欢。', 53905, 4328, -1, 508, 427, 855, 2282, 161, '2022-4-12 10:39:07', 995, 1, '2025-8-28 09:46:06', 0, -1.12947);
