INSERT INTO `videoinfo` VALUES ('BV1R44y1X7Tg', '989613015', '116683', '海 边 蹦 迪 ❤️ 极 限 温 差 ！【咬人猫】', '哼了很久的小城夏天，终于投稿啦，虽然现在是冬天了，但是海南的阳光完全就是夏天呀！歌里面的海浪声就是在告诉我：“去海边录去海边录！”果然这个舞和海边太搭了！比较有趣的是这支舞在练习的时候跳出来的是帅气版的猫，录制的时候磨合出了温柔大姐姐版，哈哈哈哈哈虽然露额头还是那么圆，出去玩还吃胖了，但是旅行真的很快乐，希望这份快乐可以传递给你们呀！2023年也一起健康快乐吧！\n音乐：LBI《小城夏天》\n编舞：阔少', 2621182, 121916, -1, 4977, 1452, 43286, 29470, 1885, '2023-1-1 11:00:00', 84, 1, '2025-8-28 09:46:06', 0.00521989, -0.631476);
