INSERT INTO `videoinfo` VALUES ('BV1R54y1m7eX', '839205194', '26798384', '【柴知道】在中国，出一本书能赚多少钱？滞销书到底有多滞销？我们找出版人做了一次采访', '我们三天两头给大家送书，也有出版社希望我们自己出书。但和你一样，我们并不清楚在中国出一本书到底能赚多少钱。出一本书有哪些流程？辛苦写一本书能挣多少钱？销量多少本才算是“畅销书”？没人看的滞销书命运如何？我们翻查资料，并采访了出版行业的朋友，来解答这些问题~', 158944, 16090, -1, 599, 968, 2811, 7529, 1063, '2020-8-6 13:11:47', 347, 1, '2025-8-28 09:46:06', 0.00245006, -0.895728);
