INSERT INTO `videoinfo` VALUES ('BV1R84y117kk', '619541036', '98608863', '这是 Alex 的家，not 一般般的家，是 Alex 设计的家', '终于要带你们参观，我住了一年「新」家了！没错，我又花了好多时间、好多钱，去布置了一个「租」来的房子。\n你们肯定经常能在节目里看见我的客厅和卧室，但今天是一个无死角的 Room Tour ，不光要给你们展示这些「光鲜亮丽」的出镜背景，还要和你们揭秘那些见不得光的「藏污纳垢」。', 76732, 5004, -1, 402, 252, 1030, 1906, 149, '2023-10-12 11:41:25', 1079, 1, '2025-8-28 09:46:06', 0, -1.12947);
