INSERT INTO `videoinfo` VALUES ('BV1r84y1z735', '604175511', '98608863', '练一次瑜伽，哭十斤眼泪，这是什么魔法！', '不装了，这期视频我们又把节目拍成了团建，又哭哭啼啼地抱在一起，感受到了很幸福的感觉。\n我一直想带大家去体验一下瑜伽和冥想，想让大家体会一下专注中打开自己的感觉，这一次特别邀请了林敏老师带领我们从最简单的体式开始，关注呼吸、关注自己。\n我希望这期节目也是一次你们可以参与的团建，你可以跟着节目里的我们一起去做那些简单的体式，也可以和我们一起冥想，具体能收获什么我说不好，但是体验是重要的，给自己 5 分钟的时间去整理心里的房间也是重要的，试试吧，说不定哪天它就可以成为一个你可以依靠的方法。', 41108, 3267, -1, 277, 91, 648, 1214, 92, '2022-10-19 11:53:05', 1182, 1, '2025-8-28 09:46:06', 0.00207001, -0.931986);
