INSERT INTO `videoinfo` VALUES ('BV1Re411o7wZ', '236950291', '138832847', '看完要长恋爱脑！冬日小甜剧《很想很想你》安利【哇妹】', '朋友们！墨宝亲自操刀的小甜剧《很想很想你》真的好适合冬天窝在被窝慢慢里看！i古风i美食的朋友真的可冲。听说这部剧的ost就制作了两年，我已经循环播放了。可能在一开始看的时候会觉得有点平淡，但这部剧属于是将两个人从陌生到熟识的爱情故事娓娓道来的那种，非快餐化，越看越甜，越品越上头！但是要追这部剧的话，记得旁边放好吃的，因为说不定什么时候你就会被馋晕~', 314491, 12852, -1, 1793, 2749, 3613, 7308, 908, '2023-12-7 12:41:15', 607, 1, '2025-8-28 09:46:06', 0.0015288, -0.983619);
