INSERT INTO `videoinfo` VALUES ('BV1rE421N7hf', '1655913974', '2920960', '傣家菜这么火吗？从饭点儿开始排队到深夜闭店，到底有什么特别之处？', '店名：浩海火烧云傣家菜  位置：北京朝阳区蓝色港湾内\n这家餐厅最特色也是所有桌必点的就是吐司铜锅油焖鸡。\n\n之所以排队这么离谱我后期分析有几个原因：\n1.地理位置好，在北京热门商圈内。\n2.在同样的地理位置这家餐厅相对价格实惠，菜品有特色。\n3.菜品口味符合年轻消费者，客人里很多大学生，且女性居多。\n4.服务贴心，出现问题会有“补偿”，特别说明不是因为有摄像机所以特殊对待，\n用餐过程中隔壁桌不知道什么原因可能有些不满意，直接全桌消费打了8折。\n\n但总体而言，可能我不是这家餐厅的受众群体，虽然整体体验可以，', 813481, 43717, -1, 1836, 2482, 3034, 16736, 862, '2024-6-18 10:00:00', 531, 1, '2025-8-28 09:46:06', 0.00256241, -0.885009);
INSERT INTO `videoinfo` VALUES ('BV1RE421N7PZ', '1653365447', '2374194', '【指弹古筝】Despacito 火爆全球神曲', '研究了一圈流行曲目，果然还是西语类的改成指弹最对味，毕竟本身的配器里吉他就是很重要的一环！刚开始练真的有点怀疑人生，为什么89的速度感觉这么快？熟练之后又很爽，因为这首曲子独奏也很好听～\n改编中我在开头保留了几句Remix版的旋律，也精简了一下后面段落，尽量保证在快慢错落中有休息的余地，不至于从头忙到尾。希望大家喜欢，反正我已经决定把这首当作逢年过节被点名表演的保留曲目了哈哈哈哈～', 432678, 34697, -1, 1731, 448, 8462, 18335, 638, '2024-4-19 10:05:00', 173, 1, '2025-8-28 09:46:06', 0.00570307, -0.585378);
