INSERT INTO `videoinfo` VALUES ('BV1rf4y1c7u8', '378484996', '2374194', '【古筝】不可阻挡 - 带着S11主题曲在成都街头走一走', '身为地道的成都人，想借着这次拍摄S11主题曲带大家逛一下“天府之都”——成都的街头，体验在成都旅游的一天。\n首先呢，先看熊猫、逛宽窄巷子、吃火锅；接着呢，游春熙路、盖碗茶、体验街头采耳；还有精力的话，还可以去走走杜甫草堂、武侯祠、浣花溪；晚上看川剧、打麻将······\n因为视频篇幅有限，能够展示的内容实在太少了，如果有空，欢迎你来成都街头走一走！\n\nP2还准备了彩蛋！跟同为四川人的Lvmao 一起去中国大熊猫保护研究中心 探望了腾竞体育认养的熊猫“盟盟”。不得不说熊猫也太可爱了吧！！！\n\n最后必须要再说一', 237256, 15053, -1, 655, 623, 2936, 5358, 356, '2021-10-4 10:00:09', 444, 1, '2025-8-28 09:46:06', 0.00552249, -0.602607);
