INSERT INTO `videoinfo` VALUES ('BV1Rh4y1B7iZ', '662003577', '26798384', '电车为何如此“易上火”？如何科学地防范新能源车自燃？【柴知道：车圈化简】', '买车时，最优先要考虑的因素是什么？是安全。但对于新能源电动车来说，想做到这一点却并不容易。仅2021一年，全国就发生了3000多起能源汽车火灾，其中约40%发生在行驶途中，35%发生在充电阶段，还有25%则是停车静止时发生的。为什么电车的自燃如此随机？如今的新能源车都采用了哪些技术方案防范自燃？它们可靠吗？我们专程来到武汉的上汽通用汽车奥特能超级工厂，实地考察了整个新能源电池包生产过程，只为找出这些问题的答案～', 335386, 8902, -1, 423, 511, 1662, 801, 767, '2023-10-13 10:50:00', 553, 1, '2025-8-28 09:46:06', 0.0113477, -0.0468646);
INSERT INTO `videoinfo` VALUES ('BV1Rh4y1R7Nz', '656728991', '26798384', '灯泡、LED、单色激光、三色激光…投影仪的光有什么区别？激光投影仪就一定更好吗？【柴知道×Vidda】', '买投影仪看电影，图的就是一个“氛围感”、“沉浸式”，但很多人会发现，投影仪要么亮度不够，要么色彩差那么点意思。而这些，都跟投影仪的光源有关。不同投影仪有什么区别？激光投影仪一定更好吗？什么样的投影仪能还原出准确、真实的色彩？', 169253, 8996, -1, 354, 261, 1470, 1350, 156, '2023-5-30 09:30:00', 549, 1, '2025-8-28 09:46:06', 0.000860175, -1.04741);
