INSERT INTO `videoinfo` VALUES ('BV1rP4y1N7Cr', '893640047', '116683', '【咬人猫】温 柔 姐 姐 ❤️丹青 更新2P竖屏版！', '感谢白老师的编舞，实在是太喜欢下地的部分，自己也根据服装的感觉改编了一部分，最后才出来了丹青这一版的舞蹈，希望大家可以欣赏到美美的风景，感受到快乐的氛围，水边有微风真的太美好了～虽然因为各种原因有很多地方没有呈现出最想要的效果，但是拍摄的那天景色很美一切都觉得很值得～今后我也会继续改进！\n快要过年啦，希望这支丹青可以给大家带来一份快乐！祝大家虎年大吉大利！\n编舞：白小白\n作曲：殇小谨\n作词：偏生梓归\n演唱：咬人猫\n编曲：邱沐阳\n音频编辑：冰镇小灯\n笛子：囚牛\n古筝：紫格\n二胡：二胡妹\n和声：皎月', 1291440, 61091, -1, 3184, 1204, 21231, 23749, 1598, '2022-1-30 11:00:07', 240, 1, '2025-8-28 09:46:06', 0.00464817, -0.68602);
INSERT INTO `videoinfo` VALUES ('BV1RP9gYbEdr', '114080086038627', '98608863', '把家里「扔」空之后，我看见了充实', '过去几个月，我在家里做了一次硬核断舍离，被姐夫逼的，过程真的痛苦，每天都在面对「我当时为什么买它的」灵魂拷问，但现在看着清爽的家，发现还挺香的。\n\n之前买的玩具、小摆件、衣服……每一样都是喜欢才买的，可最后全都成了“堆着吃灰”的负担。清理掉后，我才意识到：物品不只是占空间，还会牵绊人，让人越来越不自由。\n断舍离，不只是丢东西，而是看见自己真正的需求。我的衣柜空出了三分之一，留下的衣服都是最常穿的；化妆台上的护肤品，从“只增不减”变成了真正用得上的精简好物。\n这次整理完，我给自己立了个规矩：买东西前，先问自', 48321, 1611, -1, 67, 29, 408, 452, 54, '2025-2-28 10:00:00', 585, 1, '2025-8-28 09:46:06', 0, -1.12947);
