INSERT INTO `videoinfo` VALUES ('BV1Rt4y1i7tu', '627137272', '98608863', '我这么独一无二，你只关心我漂不漂亮？', '要逃出这种自我批判和不自信，对于女生来说，能看见别的选择真的特别重要。苗条白皙是漂亮的，不苗条不白皙也是漂亮的。当审美不那么狭隘，不同的漂亮都能被欣赏，我们才不再会永远带着不满打量自己的外表，我们才会知道如何塑造自己独有的美丽。\n在评论里告诉我，撕掉漂亮的标签之后，你是什么？', 1027305, 78217, -1, 18608, 3584, 30064, 44858, 2447, '2020-9-28 12:19:10', 436, 1, '2025-8-28 09:46:06', 0.0110083, -0.07924);
