INSERT INTO `videoinfo` VALUES ('BV1rT4y1k7kW', '936151778', '98608863', '如何温柔制服一只“不听话”的小孩', '菜卷到了一个超爱说“不”的年纪。刷牙“不要”，洗脸“不要”，穿衣服“不要”，吃饭“不要”。虽然这些事情必须得做，但我其实不想硬来。\n \n这次我决定开启一天不对菜卷说“不”的实验。规则很简单：\n1. 我不能对菜卷说“不行”\n2. 如果菜卷说“不要”，我们要尊重\n3. 与此同时，基本的卫生、整洁和安全的准则不能破坏', 56515, 4606, -1, 480, 268, 587, 1649, 146, '2022-1-30 12:00:18', 494, 1, '2025-8-28 09:46:06', 0.00452394, -0.697872);
