INSERT INTO `videoinfo` VALUES ('BV1rU411o7BR', '1904803684', '98608863', '专访张歆艺：不内耗的妈妈，有野心的演员', '这虽然是我跟张歆艺的第一次见面，却因为同为“妈妈”的身份，很快就找到了共鸣。\n\n在真实而具体的养娃日常中，我看到女性的敏锐与灵活是我们的生存技能也是我们共有的天赋。\n\n二姐之所以被称之为二姐，是她身上有一种松弛感，我几乎看不到她对育儿的焦虑，对职业前景的恐惧。\n\n对她来说生活不过是一个阶段有一个阶段的重点和难题，只要去面对，就都能过去。或许像她一样，为自己搏得一个主动选择的权利，就能够获得不内耗的生命能量。', 26854, 1721, -1, 45, 35, 249, 443, 40, '2024-5-22 11:00:00', 864, 1, '2025-8-28 09:46:06', 0, -1.12947);
