INSERT INTO `videoinfo` VALUES ('BV1RU4y1Z7KZ', '681922755', '26798384', '【柴知道】荔枝蘸酱油更好吃？花生米和豆腐干同嚼有火腿味？', '日本人吃西瓜，有时会撒盐；潮汕人吃荔枝，有时会蘸酱油；吃完神秘果，柠檬会变甜；金圣叹则说，花生米和豆腐干同嚼有火腿味。不同的食物会在嘴里碰撞出哪些惊喜？千百年来，人们总结出了哪些常见的调味手法？为什么无糖可乐难以复制普通可乐的甜味？我们从四种基本的味觉现象出发，来看看一下调味背后的小奥秘~', 175302, 11714, -1, 387, 762, 2212, 3349, 348, '2022-2-28 09:45:19', 381, 1, '2025-8-28 09:46:06', 0.00879393, -0.290499);
INSERT INTO `videoinfo` VALUES ('BV1rv411C7pr', '244678319', '26798384', '【柴知道】阿尔茨海默症无法治愈，你到底能做些什么？护理一位患者有多难？', '9月21日是世界阿尔茨海默症日。就在上周，比尔·盖茨的父亲也因为该病去世——是的，无论有多少钱，目前都不可能治愈阿尔茨海默症。\n\n哪些早期症状可能预示着阿尔茨海默症？护理一位阿尔茨海默症患者有多难，有多贵？面对无法治愈的疾病，我们到底能做些什么？我们翻查资料，制作了这支视频。', 168119, 11348, -1, 2082, 661, 2626, 2966, 474, '2020-9-21 02:00:25', 351, 1, '2025-8-28 09:46:06', 0.00742012, -0.421566);
