INSERT INTO `videoinfo` VALUES ('BV1Rv411z7iX', '243383166', '116683', '花20000元入住日本奢华酒店！竟然… 【深胖的日常①】', '为了能在日本找到稍大的房间录制深胖，我和露露一咬牙花光了经费在日本住了一万元/晚的酒店，于是有了这一期深胖的“日常”篇，介绍《深夜吃不胖》背后的故事，不知道这期vlog一些的风格大家喜欢吗？\n总之我们的宗旨永远不会变~只希望大家能从我们的视频中收获一份开心！！\n集齐6万个点赞！依然会加速召唤出下一期！', 1171235, 82960, -1, 1510, 6034, 10614, 54335, 1734, '2020-6-6 05:00:21', 674, 1, '2025-8-28 09:46:06', 0.00693575, -0.467777);
INSERT INTO `videoinfo` VALUES ('BV1rV411z7xN', '414143700', '11799651', '网络戾气为何越来越重？【中国观察】', '用黑暗森林的两条公理化用在网络世界，我们得出了网络世界的两条公理：\n网络世界公理一：获取他人的注意力是在网络世界中生存的第一需要。\n网络世界公理二：想要获取注意力的人不断增长和扩张，但整个网络世界中注意力的总量保持不变。\n基于这两条公理出发，我们来回答几个问题：\n#为什么刺激情绪是获取注意力最佳的方式？\n#为什么在网络世界中，大家倾向于不思考？\n#为什么会存在抱团，结成集体的情况？\n#为什么匿名属性会加剧网络戾气？\n#我们真的能逃离网络戾气的陷阱吗？\n这期视频不轻松，但是绝对值得好好看完。', 251176, 19174, -1, 1469, 9863, 7771, 8372, 1932, '2020-8-8 08:44:11', 680, 1, '2025-8-28 09:46:06', 0.0104189, -0.13547);
INSERT INTO `videoinfo` VALUES ('BV1Rv4y157aW', '569049498', '26798384', '真的吐了，VR眼镜最强劝退指南！【柴知道】', '从Pico4，到PS VR2，再到《三体》电视剧里的“V装具”，你最近可能会在各种广告和影视作品中，发现VR眼镜的身影。似乎在元宇宙到来之前，VR就是你通向未来沉浸式相互体验的唯一选择。可现在都2023年了，离“VR 元年”都过去了整整七年，VR设备却依然没有普及……VR技术出现了这么多年，为什么依然没能大众化？VR佩戴时的体验到底有多差？VR眼镜的这条技术路线，真的走错了吗？在这期视频里，柴司的小陈将以自己的亲身体验，和你分享他的答案～', 398464, 18481, -1, 901, 1320, 3736, 7826, 951, '2023-3-24 09:30:00', 893, 1, '2025-8-28 09:46:06', 0.00337285, -0.80769);
