INSERT INTO `videoinfo` VALUES ('BV1RV9qYTEfh', '114097215511359', '98608863', '从分崩离析到单飞不解散，这是我们的生活', '欢迎来到我们的王牌节目「This is Us，蜜糖与砒霜」。这是我们 6 个人的近期生活汇报（Gaga这期请假了，评论区把她喊回来），有宇宙给我们的能量，也有生活给我们的折磨。\n\n最近这段时间，菲菲做了自己的账号，小乔Gaga成为了非常女子，巧搬离了北京，翰文探索了人性，Alex 又接受到新的宇宙信号。\n\n其实我们的生活，没什么特别的，和大家一样经历着搬家、换工作、借钱、努力去找寻让自己感受好的事情，但这样的定期回顾，或许能让我们看清生活中没什么难过的坎，有很多平凡的习惯、爱好都能带给我们快乐。\n\n把难过', 55363, 1764, -1, 42, 138, 593, 687, 62, '2025-3-3 10:00:00', 4979, 1, '2025-8-28 09:46:06', 0.00264359, -0.877264);
