INSERT INTO `videoinfo` VALUES ('BV1RW41147is', '20087073', '26798384', '科普：感冒药真的可以“治”感冒么？', '普通感冒作为一种急性上呼吸道感染，可由上百种病毒引起，也正因如此人们至今还没有研制出针对普通感冒病毒的特效药。那么问题来了：既然“感冒药”不能治感冒病毒，那为什么还要吃感冒药呢？', 115895, 3066, -1, 1988, 223, 1676, 1766, 361, '2018-2-26 08:48:13', 158, 1, '2025-8-28 09:46:06', 0.00771804, -0.393143);
