INSERT INTO `videoinfo` VALUES ('BV1rW411d7F1', '31275895', '26798384', '为什么人们都喜欢在游泳池里尿尿？', '生活中我们经常发现：公厕的卫生纸总是消耗得特别快，公园里的狗便便总是比别处多。往大了说，还有河流污染、全球变暖、太空垃圾越来越多……这些其实都在昭示着同一个道理：不受规范的公共资源，一定会被自私的个体过度剥削。这就是所谓的“公地悲剧”。', 62566, 1966, -1, 272, 191, 698, 972, 226, '2018-9-7 12:44:32', 188, 1, '2025-8-28 09:46:06', 0.0235405, 1.11638);
INSERT INTO `videoinfo` VALUES ('BV1rW411E7ZT', '19536460', '26798384', '水滴到底是什么形状？99%的人可能都想错了', '【为什么世界充满球体？】如果让你画一个水滴，很多人可能会把它画成一头尖、一头圆的“水滴形”，但其实，现实中的水滴是近球体的形状；除此以外，天体、水果、气泡等自然界和人类社会中的很多物体也都是近球体。那为什么我们的世界会充满球体呢？', 101354, 1776, -1, 184, 717, 764, 639, 530, '2018-2-13 05:55:30', 184, 1, '2025-8-28 09:46:06', 0.0296146, 1.69587);
