INSERT INTO `videoinfo` VALUES ('BV1sd4y1N7Go', '344246540', '2374194', '【古筝x竹箫】倩女幽魂 | 秦腔x民乐- 陕西卫视梨园之约七夕晚会', '指路：完整版的节目看p2哦～\n \n【节目介绍】\n秦腔《再续红梅缘》取材于中国明代周朝俊的传奇作品《红梅记》，剧作借鉴京剧、粤剧等剧种同一题材剧目的精华，保留秦腔《游西湖》中《鬼怨·杀生》的经典桥段及“吹火”绝技，是戏曲回归传统经典的佳作，通过诗意的情景与唱词，为大家展示了裴瑞卿与李慧娘的坚贞不渝的爱情故事。\n \n国乐演奏《倩女幽魂》以影视音乐为蓝本，通过二次编创巧妙的以古筝、竹箫为叙事单元，情景再现戏曲《再续红梅缘》的故事，用不同的艺术语言传递着同样的爱情追求。\n \n当戏曲遇见国乐，凄美的爱情原来更动听。', 78205, 7084, -1, 399, 261, 1505, 2083, 199, '2022-8-4 11:30:00', 755, 1, '2025-8-28 09:46:06', 0.00650216, -0.509143);
