INSERT INTO `videoinfo` VALUES ('BV1Sjq8YPEyP', '113639281400985', '98608863', '为什么男女之间会有性别鸿沟', '最近有一位姐妹分享了自己和男朋友关于「性别红利」的讨论，男人将性别红利的概念偷换成「男人的责任」，把不公平的社会机会变成男人的无私奉献。让人哑口无言。以往，在这种争执中，我也觉得无力，懒得吵。\n\n我经常觉得，有部分异性真的很难沟通，那么真切的性别困境，他们选择视而不见，\n\n但最近我看了【第一人称她】所写的《性别鸿沟之谜》系列文章，我觉得里面的很多观点可以用在这类争论之中，也可以梳理清楚他们就是坚决不承认男人拥有性别红利的原因，可以看到为什么他们看不到女性真实的性别困境。', 112598, 9633, -1, 2067, 2032, 4471, 7189, 3773, '2024-12-12 10:10:28', 424, 1, '2025-8-28 09:46:06', 0.0065756, -0.502136);
