INSERT INTO `videoinfo` VALUES ('BV1SK4y1G71k', '888299610', '11799651', '一场发生在中国的战争，却改变了整个西方的历史进程【世界观察】', '在我国的西南地区，有一座小城，它被13世纪的欧洲人称作“上帝折鞭处”和“东方的麦加城”。在这里，发生了一场可以说改变了世界历史进程的战争。因为这场战争，蒙古帝国停止了正在进行的第三次西征，并且再也无力进行下一次西征。而西方文明也因此终于获得了一个喘息的机会，并重获生机。', 427899, 11996, -1, 560, 1272, 2018, 929, 604, '2021-5-28 10:00:00', 705, 1, '2025-8-28 09:46:06', 0.00665605, -0.494461);
