INSERT INTO `videoinfo` VALUES ('BV1sN4y1s7xi', '880784710', '26798384', '你家外墙怎么总是鼓包掉皮？掏空6个钱包，买不来一个正经外立面？【柴知道】', '作为门面担当，小区外墙就像是人脸。不幸的是，即便房价再贵的小区，门面也有拉垮的时候，破破烂烂远看就像贴满了各种狗皮膏药，甚至还出现砸人、砸车的现象。小区外墙鼓包、掉皮，究竟是谁的锅？想买到一个体面的外墙，究竟有多难？', 492447, 20428, -1, 974, 2047, 3820, 3730, 1214, '2024-1-4 09:30:00', 516, 1, '2025-8-28 09:46:06', 0.00393394, -0.75416);
INSERT INTO `videoinfo` VALUES ('BV1snj4zrE54', '114561675959741', '98608863', '我的盆底肌：第一胎漏了，第二胎还漏吗？', '二胎之后又开始了漫长的康复，跳绳漏一点，跑步漏一点，打喷嚏漏一点，产后康复的自信渐渐漏掉一半。好在，二胎之后，我对盆底的损伤不再愤怒，转为一种不尴尬、不害怕的松弛，好像盆底问题也没有那么烦。我去见了一位擅长产后康复的物理治疗师，她给我打开了一整个潘多拉魔盒。\n\n视频后面，我学习了几个锻炼和放松盆底区域的动作（不只是凯格尔运动），有需要的姐妹一起练起来。', 33699, 1605, -1, 150, 26, 483, 665, 79, '2025-5-24 07:46:54', 767, 1, '2025-8-28 09:46:06', 0.0105165, -0.126165);
