INSERT INTO `videoinfo` VALUES ('BV1Sr421c7A2', '1405519416', '98608863', '和 7 个月的铁血孕妇过一天', '欢迎收看「A Day With Alex」\n孕晚期除了躺平还可以做什么？\n吃一顿通便的早餐，做一组有一搭没一搭的凯格尔训练，欣赏家中那个男人买回来的鲜花感慨它的配色之美，然后去负重攀岩……\n我就是那个在孕期还能打满鸡血的人，出门、运动、工作确实都能让我感受到能量在体内流动。我记得北京那天的天气特别好，亮马河畔吹起的风让人觉得很舒畅。我们乘船划着桨板在河面穿行，城市和自然也模糊了界限。\n你们会喜欢这样的一天吗？如果还想和我一起过更多天，就在评论区告诉我哦，我会不定期和大家分享生活。', 51609, 3050, -1, 134, 131, 311, 886, 106, '2024-6-7 11:25:00', 558, 1, '2025-8-28 09:46:06', 0.00228704, -0.91128);
