INSERT INTO `videoinfo` VALUES ('BV1Sr4y11773', '763374526', '116683', '【咬人猫】你 的 女 友！❤️不咬人！', '真的真的好喜欢这支舞，七河版本的编舞一出来就决定要跳了，两年后终于实现了！这次服装是超可爱的“黄豆粉”，在家里跳了它，觉得这支舞自己圆满了！买了好多件黄豆粉的T恤都不是很满意，最后感谢荣荣借了她的T恤给我，终于满意了！（于是家里多了好多好多黄豆粉T恤睡衣～）\n拍舞的过程整个人都超级开心，自己也尝试了元气和少女一点的不同感觉拍了两天，最后觉得你的女友应该是少女心满满的，于是选择了第二天的版本～两个版本我很都喜欢，所以自己个人是不留遗憾了～这次家里的猫猫（除了uu女王不想出镜）都出镜啦，还多了一只可爱的白熊熊', 2337361, 122432, -1, 8015, 2254, 46415, 48129, 3297, '2021-9-30 10:44:57', 236, 1, '2025-8-28 09:46:06', 0.00757088, -0.407183);
