INSERT INTO `videoinfo` VALUES ('BV1sS23YwEmY', '113282681674375', '98608863', '把自由挂在嘴上的人，现在「下场」怎么样', '妹妹出生 28 天，我彻底坐不住了，独自带她奔向北京最美的秋天。驾乘 #凯迪拉克XT5# #为自由而生的全路况SUV #，来一次冒险。一路颠簸，但回归山林的我觉得一切都那么有趣、神奇、引诱我不断向前。希望初遇自然的西蒙，也会从刚睁开眼的时候，就能看见自然的奇迹、感受到探索的魅力，我会和她一起，永远追求自然。', 31737, 1929, -1, 48, 53, 238, 674, 60, '2024-10-10 11:33:05', 390, 1, '2025-8-28 09:46:06', 0.00324201, -0.820172);
