INSERT INTO `videoinfo` VALUES ('BV1St411S7G3', '37680744', '138832847', '年终盘点2018国产十大烂剧：ab关晓彤激情对决【哇妹年度策划No.3】', '作为长期关注国剧的up，今年是哇妹非常失望的一年。\n烂剧多到排不下，前十竞争实在太激烈了！Σ(ﾟдﾟ;)\n哇妹激情盘点2018国产十大烂剧(｀・ω・´)\n你们心中烂剧no.1是哪部？（￣▽￣）', 935829, 30933, -1, 2345, 12776, 3911, 18743, 2185, '2018-12-8 05:47:48', 586, 1, '2025-8-28 09:46:06', 0.0271981, 1.46532);
