INSERT INTO `videoinfo` VALUES ('BV1sT421a7VC', '1705828287', '2920960', '抚慰心灵的羊肚火锅，吃完满血复活！', '店名：简阳·羊肚火锅(金台路店)  位置：北京朝阳区水碓子东里附近\n\n这家餐厅吊霸子十年前就去过，据说当时基本坐满，很热闹。\n但这次探店去的时候挺冷清的，不知道是不是天热的原因。\n总体来说羊肉羊杂处理的很下功夫，其他中规中矩。\n喜欢羊汤、羊杂的人群应该会喜欢！适合哥几个喝酒聊天！', 782761, 68480, -1, 1322, 2671, 7305, 51031, 942, '2024-6-25 10:00:00', 730, 1, '2025-8-28 09:46:06', 0.00686801, -0.474239);
INSERT INTO `videoinfo` VALUES ('BV1St4y1B7Jq', '629050321', '116683', '【咬人猫X露露】心电感应❤️新 单 曲！我的超能力是我超喜欢你！', '2021年我带着新年的第一支原创单曲《心电感应》来啦，这首歌从制作到正式投稿用了近一年的时间，一开始就计划着《心电感应》是要和露露儿一起跳双人的舞蹈，所以露露一回来我们就马不停蹄的开始了不停的修改编舞、学舞、不断的改进、最终成品、筹备拍摄，期间编舞修改了很多次才有了一个雏形，整个过程都非常的充实且开心，原创只有0次和无数次，现在更喜欢全身心的把时间和心思投入到自己的原创制作中，确实让大家久等啦!《心电感应》是一首元气满满的宅舞风格的歌曲，很喜欢宅舞的我终于也有属于自己的宅舞歌曲和舞蹈视频了～希望能在新年给', 2862194, 119036, -1, 19081, 4365, 48234, 64913, 4641, '2021-2-4 11:10:19', 397, 1, '2025-8-28 09:46:06', 0.00466375, -0.684534);
