INSERT INTO `videoinfo` VALUES ('BV1sx411t7WG', '14020273', '26798384', '五分钟速读《海陆的起源》', '泛读科普经典《海陆的起源》：我们赖以生存的岩石大地，其实只是地球在表面凝固出的一层小薄壳而已。而地下的深处存在着一种强大的力量，它推动着我们脚下的土地在不断地漂移，形成了我们现在看到的七大洲四大洋，同时也创造了高耸入云的山峰，和深不见底的海沟。', 33235, 652, -1, 339, 229, 948, 947, 111, '2017-8-31 04:33:04', 364, 1, '2025-8-28 09:46:06', 0.00254769, -0.886414);
