INSERT INTO `videoinfo` VALUES ('BV1Sx4y1b76U', '1005775566', '2920960', '餐饮界的胖东来？暖心的服务，满满的细节！最后竟然给我吃哭了QAQ', '店名：匠牛饺子·酱牛肉·饺子馆  位置：北京朝阳区顺源街附近\n\n这家餐厅拍完，自己又去吃了两次晚饭，老板每次都在，都是一如既往的热情。\n虽然只是个吃饺子酱牛肉的小饭馆，但却能感受到与众不同，无论是服务，还是店员和老板的热情，都给人一种回家的感觉。我觉得这家店在用心程度上比喻是餐饮界的胖东来并不过分。饺子是那种馅料很香，吃着很满足很正常的饺子，并没有皮薄馅大的噱头，但真的很好吃。酱牛肉类绝对T0不接受反驳，推荐走过路过的朋友们来尝尝。\n但夸归夸，好归好，特意驾车开大老远就为吃个饺子酱牛肉也属实没太大必要。', 1184908, 88671, -1, 5217, 3259, 14836, 91515, 2354, '2024-6-28 10:00:00', 786, 1, '2025-8-28 09:46:06', 0.00612272, -0.545343);
