INSERT INTO `videoinfo` VALUES ('BV1T44y1L7eP', '978243081', '98608863', '世界这么大，我要去闻闻｜Vlog', '据说当你幸福的时候，要留意你看到的、闻到的、听到的、感觉到的东西，下次如果遇到同样的场景，那么一个味道、一个声音、一个触摸，就可以把你送回过去，记起你自己有多么幸福。\n\n就像观夏，把让人感觉美好的气味小心制造，她们挖掘和捕捉我们东方人记忆中的情结，然后用珍贵的植物成分调配出迷人的香气，每一次的表达都能给到情感的共鸣。\n\n或许将来，菜卷真的会记得我带他去进行了这么一场探险，妈妈让他在大冷天，闻了那么多奇奇怪怪的东西，他可能有一天会说，“冬天是驴打滚的味道。”', 44124, 5021, -1, 110, 165, 339, 659, 110, '2022-1-13 11:02:04', 477, 1, '2025-8-28 09:46:06', 0.00164976, -0.972079);
