INSERT INTO `videoinfo` VALUES ('BV1Tg41157Gh', '505390201', '98608863', '作为健全人，我为什么要看残奥会？', '其实残奥会，paralympic，在台湾的翻译不是残奥会而是音译成帕运会。para的意思不是残疾paralysed（瘫痪），实际上是 paralle（平行的），意为残奥会与奥运会并驾齐驱残疾人和身体健全的人，除了身体上的不同，并没有什么区别。当我们关注残奥会的时候，不该把他们的人生故事当作励志故事来消费，而是应该去积极地了解他们的成就与需求。就像我的朋友潘潘说的：「希望大家不只看到轮椅，也看到轮椅上的这个人。」', 42458, 6592, -1, 406, 361, 1060, 4390, 168, '2021-9-13 13:30:54', 582, 1, '2025-8-28 09:46:06', 0, -1.12947);
