INSERT INTO `videoinfo` VALUES ('BV1tG411b7Lm', '429634651', '98608863', '「我的孩子我管不好，我控制不了他」', '这期视频要邀请你走进我的「沉浸式」带娃日常中。\n最近菜卷进入糟糕的两岁，我非常真切地感受到我有点「卷」不动了。\n这个过程要不断去探索他的需求，思考我究竟想要成为一个什么样的妈妈，走着走着，我找到了一种「做自己」的感觉：\n不会因为害怕别人说我「惯着孩子」，就拧着自己的感情，成为一个冷漠的妈妈。\n不会因为和孩子的「分离焦虑」就放弃找回那个独立、自由的感觉。\n会沉浸地投入到自己的专注和热爱中，让菜卷看到「做自己的事」是很快乐的过程。\n\n我觉得我确实有做妈妈的天赋，这种天赋就是Be Yourself。', 113328, 10327, -1, 1210, 470, 1653, 5307, 270, '2022-8-18 12:00:00', 532, 1, '2025-8-28 09:46:06', 0.00487952, -0.663948);
