INSERT INTO `videoinfo` VALUES ('BV1tG411Q7Qh', '408236821', '98608863', '菜卷说，这些好东西想要推荐给你们', '这些东西不光是买来给菜卷用，也是我在购物和使用过程中都能体会到愉悦的东西，我发现它们有一个共同特点，就是它们在设计过程中是非常贴近家庭生活中的实际场景，它们很强调安全实用，也拥有童趣和审美，将亲子关系和育儿理念都融入到设计中。在每天使用这些产品的过程中，我觉得我们不是在过一个以孩子为中心的生活，而是在和孩子一起在生活。', 51227, 2514, -1, 134, 110, 494, 515, 75, '2023-11-9 11:31:29', 983, 1, '2025-8-28 09:46:06', 0, -1.12947);
