INSERT INTO `videoinfo` VALUES ('BV1TN41177oD', '493957952', '98608863', '为了不孤独终老，现在开始巴结朋友的小孩 | 共读《暮色将尽》', '「个体出生、长大、生儿育女、凋零死亡让位给后来者。不管人类做着怎样的白日梦，也无法幸免这样的命运」。\n\n这句话赫然印在戴安娜·阿西尔的老年回忆录《暮色将尽》的底页上。这位发掘了奈保尔，出版了《藻海无边》的杰出编辑也无可避免地走向自己人生的凋零，她所描述的衰老、丧失都是萧瑟的，一路往下坠落，却能看见「衰老」本身所存在的意义。因为，这如她所说，即便将死的人，依然充满了生机，自我依然鲜活地存在其中。\n\n朋友推荐这本书说的时候，说看完就不用再担心一个人孤独的老去。阅读这一本书的时候，我们无限次去接近作者做形容的衰', 49560, 3380, -1, 458, 299, 811, 1481, 88, '2023-11-28 11:20:13', 832, 1, '2025-8-28 09:46:06', 0.00461774, -0.688924);
