INSERT INTO `videoinfo` VALUES ('BV1TN4y127us', '876467981', '26798384', '8年246起“刹车失灵”，全是司机的锅？为什么电车总是刹车失灵？【柴知道：车圈化简】', '过去几年里，不论是特斯拉，还是比亚迪、理想、蔚来、小鹏，但凡叫得出名的新能源车企，基本都闹出过“刹车失灵”事件。而且不论最终调查结果如何，总有一拨人坚信是电车的刹车设计有问题，同时又有另一拨人，认为是车主踩错了踏板导致的。电车为什么总是“刹车失灵”？它们的刹车系统跟传统油车有什么区别？我们希望从电车刹车系统结构，和刹车方式入手，来理清这个问题～', 659805, 32584, -1, 2143, 4810, 4918, 6055, 5844, '2023-11-27 09:30:00', 626, 1, '2025-8-28 09:46:06', 0.00337219, -0.807753);
