INSERT INTO `videoinfo` VALUES ('BV1TN4y1p7yL', '878798130', '98608863', '不同身材穿同一件衣服，都能好看吗？', '时隔一年我们又来搞穿搭啦。\n我们选择同一件衣服，挑战不同的身材、挑战不同的风格。 6 个人，有女有男，有高有矮，有胖有瘦，Ta 们可以穿同一件衣服吗？Ta 们可以把同一件衣服都穿出好看的感觉吗？\n这一次穿搭挑战很冒险：乖乖女、格雷风、黑怕噗，我们都在自己的不擅长的领域疯狂蹦迪。\n那么效果究竟好不好呢，就交给各位看官啦。\n我们自己默默觉得，衣服不挑人，我们穿什么都好看！', 193726, 6831, -1, 277, 541, 1368, 1064, 254, '2024-1-15 12:16:14', 934, 1, '2025-8-28 09:46:06', 0.00596766, -0.560136);
