INSERT INTO `videoinfo` VALUES ('BV1ts411m7v5', '2751717', '116683', '【咬人猫】干物妹！小埋OP o(*≧▽≦)ツ', '看了干物妹！小埋，实在好欢乐！“ぽんた”给OP的编舞也好棒，把小埋的两种状态都跳进了一支舞里，在机场就忍不住循环了很久，于是决定也要翻跳。在练习过程对部分动作有做改动，有不足的地方还请大家多多包涵。我一直都很喜欢这样的欢乐又有点逗的舞蹈，录制完的时候已经接近凌晨4点，但是过程中一直很开心，最希望的就是能传递给大家一份欢乐就好啦！\r\n参考编舞：https://youtu.be/01dwYZGZs98', 7620296, 28921, -1, 17935, 31449, 70203, 86648, 6537, '2015-8-17 07:08:30', 132, 1, '2025-8-28 09:46:06', 0.0178512, 0.573599);
