INSERT INTO `videoinfo` VALUES ('BV1Tv41177Ew', '247553281', '2374194', '【墨韵】LOSER - 奥义！指弹古筝～', '一直都很喜欢八爷的歌，这次终于有机会自己翻奏了！不仅选择了一首风格和以往不同的曲目，在演奏技巧上其实也在不停探索。观看了很多LOSER的器乐视频，大部分都是吉他，所以也想融入一点指弹吉他的泛音和拍板技巧。但是！！古筝的琴弦和能拍的琴板实在隔得太远了，整个中间一段看起来十分忙碌2333～所幸这首曲子的节奏并不是很快，勉强能来得及反复横跳……果然日系歌曲都好难啊qwq\n希望大家喜欢哦！\n\n原曲：《LOSER》米津玄师\n古筝演奏/改编：墨韵随步摇\n录音/混音：刘嘉伦\n古筝拍摄/后期：余林峰\n妆发：璐璐\n统筹：雁', 1098475, 104529, -1, 4993, 1761, 31198, 72553, 1803, '2021-4-16 10:00:15', 228, 1, '2025-8-28 09:46:06', 0.0123462, 0.0483963);
