INSERT INTO `videoinfo` VALUES ('BV1Tv4y1B7A2', '564472004', '26798384', '梦游惊魂、梦话骂人，还梦中打人？！异态睡眠是怎么发生的？【柴知道】', '你住宿舍的时候，应该听过室友说梦话，说不定还被他在梦中骂过少部分幸运的朋友说不定还见过室友梦游。还有更幸运的朋友，说不定睡着的时候被枕边人暴揍过 ~人类为什么有这么多奇怪的睡眠行为？梦游、梦话、梦中打人是什么原因导致的？遇到梦游的人到底要不要叫醒？ 这些行为会影响身体健康吗？', 163050, 11252, -1, 513, 696, 1184, 2758, 620, '2022-12-30 09:30:00', 379, 1, '2025-8-28 09:46:06', 0.0128016, 0.0918444);
INSERT INTO `videoinfo` VALUES ('BV1TV4y1c7Pi', '861423748', '98608863', '一堂大山里的寻梦直播课', '长大后发现，人在小时候的梦想是最炙热的。那时候不会“思前想后”，更不会“量力而行”，无论想法有多么不切实际，但心里总觉得自己会有实现的一天。也许有的时候我们走着走着会忘记了初衷，但心底的梦想，不会随着时间淡忘。\n#来自大山的寻梦邀约 12月18日，我将与芬必得、新世相 一起，在上海真爱梦想公益基金会的特别支持下，为大山里的孩子带去一堂大山里的寻梦直播课。欢迎大家观看直播，跟我一起见证一场关于梦想的绚丽流星雨。#有梦的孩子不怕痛', 8542, 1075, -1, 4, 2, 70, 187, 17, '2022-12-17 12:55:14', 237, 1, '2025-8-28 09:46:06', 0, -1.12947);
