INSERT INTO `videoinfo` VALUES ('BV1tx411M7YR', '15562698', '26798384', '为什么水在4℃时密度最大？', '在0-4℃的范围内，水不再遵循“热胀冷缩”的规律，十分“倔强”地随着温度的降低而变大，这使得江河湖海在冬季不至于完全冰冻，保护了水中的生物。可以这么说：如果水没有这样“反常”的性质，地球上可能就进化不出我们人类。', 101071, 1797, -1, 403, 113, 1282, 667, 181, '2017-10-20 10:50:38', 86, 1, '2025-8-28 09:46:06', 0.00280867, -0.861515);
