INSERT INTO `videoinfo` VALUES ('BV1U1421x7hu', '1556653922', '2920960', '北京烤鸭做的最好吃的竟然是新荣记？而且只有在米其林三星的店能吃到！', '店名：新荣记 位置：北京市朝阳区新源南路附近\n\n推荐指数个人向：★★★★★\n★★★★★（如果条件允许每月都会忍不住吃一两次）√\n★★★★（有第二次去的冲动，也有推荐朋友去吃的想法）\n★★★（还不错，但暂时没有再去的想法）\n★★（个人不喜欢，不推荐）\n★（太拉了，什么鬼？？？）\n\n这期视频忍不住多说两句，新荣记说是中餐业界标杆真的不夸张，他的出品太稳定了！食材的话也是顶级中的顶级，哪怕是餐前和餐后赠送的水果品质都是顶中顶。另外想夸夸自己真会点菜！这一顿，鸡、鸭、鱼、鸽子、虾、蟹、菌、蛙不管是水里游的路上跑的', 771521, 53732, -1, 4193, 7085, 5468, 32416, 1490, '2024-9-3 10:00:00', 1187, 1, '2025-8-28 09:46:06', 0.00385162, -0.762014);
