INSERT INTO `videoinfo` VALUES ('BV1u24y1U7cz', '691994615', '98608863', '谢谢你，让这不确定的一年过得还不错｜2022年终总结', '2022 年，是不太正常的一年，我们经历了很多封控，也看见了很多历史正在发生。但在这些不确定中，我看到我自己作为个体，内心有很多理想主义的小火苗再次被点燃。\n\n我写下这一年「进步」，认可自己的「努力」。希望你也可以去拥抱，2022 年的自己，感谢 TA 这一年为你带来的成长。\n\n我们明年再见。', 40947, 4621, -1, 93, 421, 567, 2197, 145, '2022-12-30 11:00:00', 660, 1, '2025-8-28 09:46:06', 0.00123183, -1.01195);
