INSERT INTO `videoinfo` VALUES ('BV1Uf4y1x7uT', '289868126', '138832847', '《大宋宫词》吐槽，为什么总是把霸气大女主拍成白莲花圣母？【哇妹】', '《大明宫词》为我们展现了一个有野心有能力的武则天，可惜了，《大宋宫词》的刘娥本来也可以有更多发掘的点，李少红从《大明宫词》倒退到《大宋宫词》，没有了过去的浪漫的情怀，是电视剧女性意识的倒退，也是暴露了一个问题，现在很多大女主都是，外表大女主，内心玛丽苏，什么时候影视剧里女政治家们可以摆脱一定要傻白甜一定要谈恋爱的魔咒呢？', 836363, 27636, -1, 640, 4500, 1099, 2359, 1007, '2021-3-25 11:48:47', 612, 1, '2025-8-28 09:46:06', 0.0126397, 0.0763972);
INSERT INTO `videoinfo` VALUES ('BV1ug411F7z8', '505812550', '122879', '如何欺骗玩家去买注定失败的游戏', '囧的呼唤系列\n\n本期视频由敖厂长独立制作 绝对原汁原味\n\n=======================================\n本期视频选题上有参考以下国内文章\nHUDSON大篷车:与 作者:Leon Lee\nhttps://zhuanlan.zhihu.com/p/75982673\n红白机\"名人\"群像----80年代业界的造星风潮 作者:游研社\nhttps://www.sohu.com/a/280697104_628730\n由于以上两篇文章都具体提到了HUDSO', 1691920, 111506, -1, 855, 5305, 9860, 35922, 1878, '2021-10-5 04:00:12', 924, 1, '2025-8-28 09:46:06', 0.00901013, -0.269874);
INSERT INTO `videoinfo` VALUES ('BV1UG411i7Ha', '409049966', '520819684', '荣耀独立三年了，它过得还好么？', '荣耀从华为独立也已经三年了，市场份额一度跌到3%，如今第三季度又以19%重返国内市场出货量第一。\n\n咱们今天就来聊聊荣耀的这三年，究竟从华为带走了什么？又经历了什么？如今“中华有为”了，它能“世界荣耀”么？', 2211498, 68234, -1, 4061, 3659, 7561, 10000, 3017, '2023-11-30 09:51:37', 639, 1, '2025-8-28 09:46:06', 0.00316221, -0.827786);
