INSERT INTO `videoinfo` VALUES ('BV1Ug4y147WX', '823538126', '520819684', '称他是中国最牛CTO，没人有异议吧？', '云，15年前还鲜为人知，现在却成几乎每个人生活密不可分的基建。而中国云的崛起，离不开王坚。\n他曾经被骂了4年骗子，甚至在公开场合失声痛哭，而如今，他成了中国近十年来最好的CTO、中国云计算之父、第一个互联网科技企业走出来的院士。\n从骗子到院士，王坚是怎样炼成的？中国云计算又是如何一步一步发展起来的呢？', 1551670, 47210, -1, 5176, 2775, 7985, 13982, 1214, '2023-3-16 09:30:00', 874, 1, '2025-8-28 09:46:06', 0.00560181, -0.595039);
