INSERT INTO `videoinfo` VALUES ('BV1UJ411c7u9', '67967977', '98608863', '日常被注视、评判和嘲笑，她们却希望不要给别人添麻烦 | 绝对是个妞', '「我就是搞不懂女人为什么允许自己胖成这样。你明明知道会被像屎一样对待。」\n\n这是网络上的一个陌生人给我的采访嘉宾之一、艺术家 Haley Morris-Cafiero 留下的评论。\n\n这期节目我们采访了 3 位不同年龄、不同背景的大码女性，聊了聊她们被注视、评判和嘲笑的日常，以及她们和这个充满敌意的世界共处的方式。', 45579, 4309, -1, 772, 439, 1072, 2590, 333, '2019-9-16 12:20:47', 687, 1, '2025-8-28 09:46:06', 0.0607388, 4.66523);
