INSERT INTO `videoinfo` VALUES ('BV1UK411z7zm', '476510061', '98608863', '耳朵听到了：买它！', '我要做一件开拓性的壮举，把12 月 20 日，定义为绝对是个妞耳环购物狂欢节，还准备了粉丝专属福利（暗号是：阿姐）。\n\n1、最佳建筑设计奖：ME TOO WORKSHOP。设计师在材质上拥有非凡的想象力，无论是软陶、硅胶还是毛线、珍珠，在极简和华丽上找到最佳的平衡点。\n\n2、最佳设计态度奖：OF HUNGER。暗黑中透露着俏皮，繁复中凸显个性，把看似混搭的元素结合在一起，呈现出一半海水一半火焰的反差感。\n\n3、最佳色彩碰撞奖：小黄香蕉手钩。只有你想不到设计元素，没有小黄香蕉做不到的天马行空。', 35396, 2560, -1, 93, 289, 243, 346, 58, '2022-12-20 10:58:43', 831, 1, '2025-8-28 09:46:06', 0.00708461, -0.453575);
