INSERT INTO `videoinfo` VALUES ('BV1Um4y1X7YQ', '677449629', '116683', '【咬人猫】The Light❤️4K版！期待更好的再见！', '时隔两年 终于完整了这支the light的舞蹈，之前总感觉后期还不是最想要的效果，所以先放在了p2，导致很多小鱼干都不知道这一作。今天终于在准备新舞的间隙把它也完完整整的制作完成投放出来啦～喜欢爱酱的性格也很喜欢她的歌曲，这首The Light当年就好喜欢好喜欢，找了正义老师编了舞，对于当时的我真的很难但也努力去完成了～知道爱酱要进入休眠，很意外，也始终抱着期待，毕竟说再见是为了更好的再见！相信不久的将来一定可以见到更活力的爱酱快乐地和大家说哦哈哟！我也一起加油！\n感谢The light编舞:正義\n音乐', 1399489, 66894, -1, 1593, 1064, 19267, 19430, 1172, '2021-12-17 11:07:57', 178, 1, '2025-8-28 09:46:06', 0.00498029, -0.654334);
