INSERT INTO `videoinfo` VALUES ('BV1uR4y1F7CA', '339770272', '98608863', '性别不平等就像重力，看不见，但时刻存在', '最近，女性主义的讨论越来越多进入大家的视野。\n今天，我们把线上讨论拉回到现实生活，看一看这些思想如何影响了大家真实的生活，这就是今天的新系列，100个女性主义者。\n第一期的嘉宾是@Emma陈艾茵  ，她是一位内衣设计师，月经裤品牌如里 Relief 的创始人。这次聊天中，虽然并没有得出鼓舞人心的结论，但我感受到彼此理解，同频互动的酣畅淋漓。\n这个系列的视频，可能我无法给你答案，无法告诉你一个女性主义者该怎样生活。但是，希望可以提供一种相互理解的语境，一种继续讨论的空间与可能。所以，期待与你交流。', 83242, 10354, -1, 626, 621, 1937, 5861, 646, '2022-3-16 10:27:49', 663, 1, '2025-8-28 09:46:06', 0.0131822, 0.12816);
