INSERT INTO `videoinfo` VALUES ('BV1Us41117tp', '2919915', '116683', '【咬人猫】Marine Dreamin\'❤o(*≧▽≦)ツ', 'MD这支舞一出就各种翻跳洗脑了，yumiko老师的编舞太棒，对节奏感的要求也比较高，用了很多时间练习，录制完后还是发现有节奏不太对的地方，以后我也会多多努力克服。这次的舞蹈也是在服装上最纠结的一作，试跳过一套私服，定做过一套打歌服，可最后都pass掉了，因为不是自己想要的感觉，最后想到bml时做的梦想之门的打歌服意外的很合适~于是才完成了这支舞。编舞：so26103065参考：so26239613', 2994098, 9601, -1, 3927, 12835, 29453, 34455, 2988, '2015-9-17 13:46:29', 221, 1, '2025-8-28 09:46:06', 0.00905865, -0.265244);
