INSERT INTO `videoinfo` VALUES ('BV1us411e7D8', '7495672', '116683', '【咬人猫X露露】深夜吃不胖⑦！挑战世界上最硬的食物！', '这一期和露露一起尝试挑战了世界上最硬的食材：干鲣鱼。不管味道如何，相信我们它的气味是真的让人上瘾。转眼间深夜吃不胖也来到了第七期，虽然更新很慢，但是很喜欢这个记录我和露露日常状态的节目。也依然希望大家能感受到一份开心就好，非常感谢大家对这档节目的期待，谢谢大家！我们下一期再见！', 1543857, 4593, -1, 2854, 12437, 6506, 21464, 4236, '2016-12-12 05:03:18', 905, 1, '2025-8-28 09:46:06', 0.0125278, 0.0657212);
INSERT INTO `videoinfo` VALUES ('BV1us411J7AM', '26744489', '138832847', '《我不是药神》王传君X徐峥X章宇の毁容式演技安利！优秀演员就该配国产佳作！', '《我不是药神》中的每一个演员都是实力派！\n哇妹快乐安利优秀的实力派演员，希望他们能接到更多好剧本，为我们带来更多国产好电影、国产好剧！\n\n恭喜王传君彻底摆脱关谷神奇的标签！٩(๑❛ᴗ❛๑)۶\n希望山争大哥在年末的各大颁奖礼靠演技C位出道！蒸饭小糖为你打call！（づ￣3￣）づ╭❤～\n章宇是我新男神了嘻嘻~罒ω罒', 97364, 4208, -1, 46, 545, 380, 1160, 125, '2018-7-13 02:52:41', 388, 1, '2025-8-28 09:46:06', 0.0158727, 0.384845);
INSERT INTO `videoinfo` VALUES ('BV1US411K7rU', '1905497872', '2374194', '【墨韵】到希望小学上一堂音乐课，他们竟相信我是从 2000 年前来的！', '这次我扮演一位从 2000 年前来的古人，来到捷豹路虎希望小学给他们上一节音乐课。\n\n作为 “2000 年前来的人”，我想用音乐和孩子们一起体验时光的流逝与沉淀——“今人不见古时月，今月曾经照古人。”\n\n我问他们最喜欢的声音是什么？我想要他们知道，古人也曾经听着这些声音在这片土地上灿烂的生活过。\n\n这次参与捷豹路虎共创公益音乐企划，是一个声音与文化的探索之旅，也有许多音乐UP主结伴同行。带着各自的民族乐器和西洋乐器，我们跋山涉水来到了这所学校，希望能将音乐的种子播种在孩子们的心中。我也很荣幸能参与由@尔冬', 247006, 12410, -1, 138, 481, 1316, 2552, 284, '2024-5-31 10:00:36', 575, 1, '2025-8-28 09:46:06', 0.00896708, -0.27398);
