INSERT INTO `videoinfo` VALUES ('BV1uV411f7bq', '412507811', '2374194', '【一人双筝】黄金之风处刑曲 il vento d’oro —— 我真是high到不行！', '我不做鸽子了，JOJO！一个月双更的不是别人，ko no 墨韵 da！从去年全集上线就沉迷JOJO并且开始扒谱，今年终于搞出来了！虽然每一部的音乐都很喜欢，最后还是选择了il vento d’oro。不过这个曲风太骚，以至于一台琴的弦完全不够用啊qwq，只好再加一台琴来增加演奏的可能性。服装上要感谢毛毛老师圆我梦想，设计了这套装满了拉链的布加拉提魔改旗袍23333！当然，视频上也夹带了很多私货，哪个替身使者不想拥有无敌的白金之星呢？于是我反手一个砸瓦鲁多，对着两台琴就是一顿欧拉。仔细数了一下，居然8秒过去', 2105897, 255429, -1, 34180, 10800, 109161, 264852, 5589, '2020-3-31 10:00:36', 253, 1, '2025-8-28 09:46:06', 0.0144411, 0.248257);
INSERT INTO `videoinfo` VALUES ('BV1uv411H7cR', '248864192', '26798384', '【柴知道】为什么加黑边=电影感？电影幕幅的最全科普！', '如何让你的 vlog 更有电影感？很简单，给视频上下加个黑边和字幕，做成宽幅就行~不过，像《魂断蓝桥》这样的经典老电影，画幅根本就没有今天这么宽。电影画面为什么变宽了？为什么我们如今会认为宽幅更有电影感？电影幕幅到底有什么意义？我们从电影的起源、市场的变化，和艺术表达的角度出发，试图来解答这个问题~', 192844, 17000, -1, 400, 728, 3373, 8598, 394, '2021-6-23 09:50:48', 516, 1, '2025-8-28 09:46:06', 0.00275543, -0.866594);
