INSERT INTO `videoinfo` VALUES ('BV1UV4y1579j', '858823695', '2374194', '【指弹古筝】S12主题曲《逐星》，LPL冲冲冲！', '翻奏了几首吉他经典之后赶紧活学活用一下，于是有了指弹版STAR WALKIN’。也借此曲祝LPL在S12世界赛所向披靡，勇夺桂冠！\n这次的改编尝试了一下之前没有的底鼓奏法，非常费手，第一天练完我觉得会整出腱鞘炎。所以在手腕的地方改装了一下，属于是真正的邪门歪道了哈哈哈哈！虽然体验到了指弹技法移植的物理限制，但好在旋律不难，还是可以勉强完成！以后还会继续探索～希望大家多多建议！', 229195, 13979, -1, 1297, 225, 3788, 7031, 328, '2022-10-7 08:00:00', 147, 1, '2025-8-28 09:46:06', 0.00254425, -0.886741);
