INSERT INTO `videoinfo` VALUES ('BV1v94y127wr', '342527959', '116683', '约 尔 太 太，但 是 蹦 迪！ ❤️ 【咬人猫】', '间谍过家家开播前就已经在期待了，看了以后就果断想cos约尔太太跳一次舞！恰好之前特别喜欢的一首歌很适合，连名字都仿佛量身打造的《KILLER B》哈哈哈！很久没有这么鸡血的就赶紧练舞、驾驭高跟鞋起来！这支舞平底鞋我已经练到可以原地起飞了，9cm细高跟的高跟鞋还是一座我好难攀登的高峰呀，现场地面也增加了一点难度，但是很开心这个视频能基本达到自己预期的感觉！当晚拍了一个通宵结束还去吃了个早饭才回家！起来就很兴奋的开始准备后续制作，希望这一支不太容易的视频，能给大家带来新的感觉，总之这次超飒的约尔太太大家还喜欢', 14427367, 952769, -1, 44521, 11468, 276786, 237134, 6277, '2022-6-17 11:00:26', 110, 1, '2025-8-28 09:46:06', 0.00862732, -0.306395);
