INSERT INTO `videoinfo` VALUES ('BV1vB4y1F7Yx', '588177418', '98608863', '她从女孩长成男孩，再终于成为女孩', '5 月 17 日是国际不再恐同恐跨恐双日。而我相信改变歧视的第一步就是让更多人看到这些被抹去的少数群体的故事。比如在 MAIA ACTIVE 最新的广告片中，我第一次看到了跨性别女孩的故事。这个广告让我很受启发，于是我决定去采访我的朋友 Yayo，一个我身边的跨性别女孩。\n如果社会要阻拦每一个Yayo 做自己，那更说明我们应该去和她们站在一起，向这个想要给我们设下限制的世界说不。因为没有什么决定是我们不能做的，而每一个做出自我决定的瞬间，都让我们活得更像自己。', 147352, 12592, -1, 806, 1220, 1483, 4986, 582, '2021-5-17 14:45:09', 669, 1, '2025-8-28 09:46:06', 0.00572871, -0.582933);
