INSERT INTO `videoinfo` VALUES ('BV1Vc41147tD', '283743128', '98608863', '让男人做好家务到底有多难？', '这是一期关于家务的视频，体现我的生活小技巧，体现我对一个家的劳心劳力，体现我作为一个新时代妇女还是不得不被家务所困的辛酸与怨怼。\n\n但这绝不单纯只是一期关于家务的视频，也是揭秘为什么我们女人在家庭生活中总是会觉得疲惫，揭秘为什么男人在家务面前总是会展现出笨拙、偷懒和视而不见。\n\n这个答案就是：看不见的情绪劳动。\n\n我设计了一些考题来考考阿姐夫有没有对家务上心，这些问题看上去很简单，但其实，如果你没有加入过这个家庭的「设计」「筹划」「分配」的情绪劳动，很难找到正确的解题思路。', 85461, 4955, -1, 1897, 680, 1088, 2071, 548, '2024-1-12 08:27:59', 623, 1, '2025-8-28 09:46:06', 0.00649762, -0.509576);
