INSERT INTO `videoinfo` VALUES ('BV1VE421V7Wg', '1654231303', '98608863', '怀孕的好，姐姐知道，怀孕的痛，姐姐明了', '怀孕累不累？孕吐会持续多久？还能不能做运动？还能不能做那种运动？今天我要从我的个体经验出发，来和大家分享怀孕感受。\n做这个视频一方面，我希望有过怀孕经历的姐妹，都可以一起说说大家的孕期体验，我们来找找共鸣，成群结队地度过孕期、顺利生产。另一方面我也想要让对怀孕有恐惧的姐妹，可以看到一个不渲染焦虑情绪，也不过分轻描淡写的孕期分享，这样我们可以更谨慎、更客观地去看待怀孕、生产这件事情。\n\n想生 or 不想生都是一个个人选择的问题，无论你做什么决定，我都会在。', 181184, 4707, -1, 314, 178, 1229, 1193, 202, '2024-5-3 09:50:49', 434, 1, '2025-8-28 09:46:06', 0.00683266, -0.477612);
