INSERT INTO `videoinfo` VALUES ('BV1vW411R7M4', '29523121', '116683', '【咬人猫】Toxic❤️你的专属小恶魔 o(*≧▽≦)ツP2竖屏版', '第一次尝试欧美风的舞很紧张，Toxic这首歌喜欢了很多很多年，她的舞蹈同时也是魔兽世界血精灵女的种族舞蹈，作为魔兽玩家的我印象一直很深刻，今天终于有机会去翻跳它，对我也是很大的挑战！因为没能找到完整统一的原版动作，所以我在舞蹈衔接中我也融入了自己原创的部分动作，有不足的地方希望大家多多包涵，最后甩鞭子的动作灵感来源于魔兽世界术士魅魔的技能，不知道有没有吓到大家呢？希望这一作能让大家看到一只魅魔一样的小恶魔猫，也希望大家看的开心，我也会继续加油的，谢谢你们的支持！\n舞/曲：Britney Spears', 3575870, 68213, -1, 10581, 10106, 49653, 85605, 7795, '2018-8-16 12:00:53', 424, 1, '2025-8-28 09:46:06', 0.0146921, 0.272205);
