INSERT INTO `videoinfo` VALUES ('BV1VW4y1R775', '954311695', '395991094', '丧尸病毒大爆发，大长腿姐姐带领童子军大杀四方，全程高能的不正经丧尸电影《童子军手册之僵尸启示录》', '丧尸病毒大爆发，大长腿姐姐带领童子军大杀四方，全程高能的不正经丧尸电影《童子军手册之僵尸启示录》', 346459, 10004, -1, 135, 1441, 1571, 1270, 348, '2023-6-1 12:14:23', 1175, 1, '2025-8-28 09:46:06', 0.014728, 0.27563);
INSERT INTO `videoinfo` VALUES ('BV1VwUXYAEtH', '113521991884004', '116683', '猫 步 轻 点，水 中 起 舞！❤️ 月白 【咬人猫】', '月白舞蹈版终于和大家见面啦！先要给一直在关注着月白舞蹈版的小鱼干们说一声感谢！其实不光大家想快点看到成品，我也一样，然而在这背后的制作过程中，有很多很多当时还无法跟大家分享的小困难，从服装到选景到最最重要的编舞，每个环节都让我挠破脑袋。月白的编舞前后经历了三个我都很尊敬很喜欢的编舞老师完全不同的版本，但前面两个版本都和我心中想象的月白不太一样，所以最后邀请到了自己一直以来都很想合作的深雪老师，出了第三版，终于看到了心里的“月白”！是我想象中的她！在这一版上自己又想做一些小小的调整，这样真的花了很长的时间去', 3434412, 210234, -1, 10038, 1640, 103194, 54292, 4874, '2024-11-22 11:00:00', 172, 1, '2025-8-28 09:46:06', 0.00593555, -0.5632);
INSERT INTO `videoinfo` VALUES ('BV1vwZcYCE73', '114242908852262', '98608863', '她们说的自律，是 J 人游戏，P 人的地狱', '如果要列出每天的 to do list，工作、带娃、运动、阅读、家务、社交，我每天要做的事情真的不少，真的有很多人关心我过得累不累。说实话，有时候会觉得很充实，安排得很满，身体上也会有疲惫的时候，但总体来说，按照「做事做事做事」的节奏去生活才是我舒服的频率，不这样的活着，才会真的累。\n\n今天我邀请了好朋友莎莎，一个典型的J人，和我一样，闲不下来的人，也叫来巧，一个总是觉得自己没什么力气的人，一起来聊聊，精力和时间管理，互相走近彼此的精神世界，在「卷」与「躺」这件事情上达成一个世纪和解。\n\n当然，本期节目也', 12527, 506, -1, 25, 24, 144, 119, 31, '2025-3-29 03:00:00', 4889, 1, '2025-8-28 09:46:06', 0, -1.12947);
