INSERT INTO `videoinfo` VALUES ('BV1vx41157DL', '16726890', '2374194', '【古筝】天地有灵', '本家av16079028\n得知玉先生和尊尊合作了我是十分激动的！两位的合唱与戏腔真的太精彩了，于是赶紧拿起我的小本本扒谱子~\n后半段连升两个调令人窒息，不能一次弹下来还是比较遗憾，所以花了一些功夫在改编上。\n 第一段比较注重滑音，第二段加上了一些和音，希望整体能表现得更丰满一些。\n高音摇指太用力导致个把音突破天际，感谢埋葬桑@闫东炜_埋葬YJ 在寒风中帮我修复！虽然这次我又失去了我的头，但是有皇桑正脸作为补偿哦。(=・ω・=)最后希望年初有机会去看捉妖记2！', 670163, 24750, -1, 4344, 10013, 17738, 63381, 8098, '2017-11-27 12:54:03', 272, 1, '2025-8-28 09:46:06', 0.00884107, -0.286002);
