INSERT INTO `videoinfo` VALUES ('BV1vx41187Ej', '11294175', '26798384', '科普：台风是怎么被命名的？', '台风的名字千奇百怪，有萌系的“浣熊”，小清新系的“蔷薇”，神话系的“龙王”，以及....臭豆腐系的“榴莲”。还有一些名字不太看得懂，比如正在朋友圈刷屏的“苗柏”~那台风的名字，都是怎么取出来的呢？', 116407, 1367, -1, 1210, 445, 1739, 942, 587, '2017-6-13 07:13:12', 120, 1, '2025-8-28 09:46:06', 0.00242237, -0.898369);
