INSERT INTO `videoinfo` VALUES ('BV1Vx411G7nW', '14689336', '26798384', '时代在召唤：5分钟速读《数字化生存》', '《数字化生存》这本1995年问世的“老”书，被称为中国第一代互联网创业者们的「指路圣经」。这是一本“神准”的预言集，20年前作者在书中描绘的那个科幻世界，如今几乎已经成真；而那些尚未实现的部分，更加值得当代人去探索和反思……', 35269, 606, -1, 413, 360, 932, 704, 122, '2017-9-22 09:06:45', 386, 1, '2025-8-28 09:46:06', 0.0142505, 0.23008);
