INSERT INTO `videoinfo` VALUES ('BV1Vx411w7rm', '191273', '116683', '【咬人猫】电星★外拍初尝试~夕阳下の第四弹舞蹈~喵~', '小喵的第四弹终于完成了。这一次下决心尝试要外拍，但是冬日里的外拍真的好难。第一次的尝试由于各种情况和坏天气失败而终~于是这一周再次挑战，结果好欣喜圣诞遇见少有的晴天，这种夕阳的画面是我做梦都想要的。舞蹈外各种路人各种围观~第一次经历，好紧张。天气也好冷好冷。小喵只希望能把画面里的温暖的感觉传递给冬日里的大家。希望你们能感受到O(∩_∩)O 微博http://weibo.com/1933719015', 444326, 2263, -1, 509, 2030, 1652, 1100, 643, '2011-12-26 17:54:41', 267, 1, '2025-8-28 09:46:06', 0.00293323, -0.849631);
