INSERT INTO `videoinfo` VALUES ('BV1vy411a7PF', '1954970083', '520819684', '【硬核】HPV感染背后到底有何不为人知的内幕？', '生活中我们对HPV并不陌生，几乎大部分人都听说过它，但却都觉得HPV离自己很远——「没那么容易感染吧」「没对象就没事吧」「感染了也没啥吧」…\n\n但真相真的如此吗？HPV感染真的和你没有关系吗？\n\n本期视频由前三甲医院医生@六层楼先生  、前华尔街分析师@小Lin说   、人气普法新锐@俏佳人xxx   、北大科普新星@二二酸酸   四位来自不同领域的科普大咖，通过HPV公开课为我们揭开关于HPV那些不为人知的内幕，让每一个人都能重新认识并正确了解HPV感染真相！', 3314307, 26717, -2, 22216, 0, 4289, 3916, 0, '2024-5-27 03:00:00', 178, 0, '2025-8-26 13:47:51', NULL, NULL);
