INSERT INTO `videoinfo` VALUES ('BV1wU4y1g7KA', '676447836', '138832847', '狠狠真香！以为是中年玛丽苏，结果是励志大女主，刘涛林峰《星辰大海》解说【哇妹】', '这部剧把职场线搞出了升级打怪刷关的爽感，而且女主角的人设也升级，不再是唯唯诺诺的恋爱脑，而是努力赚钱的女强人。女主大喊我不要谈恋爱我只想赚钱，简直完美贴合了现在观众对恋爱线的厌恶心理，只想看女主角搞事业的迫切需求。\n它比以前传统大妈剧好的一点是，它是一部与时俱进的狗血大妈剧，它不再强调女人要委曲求全，而是强调女人搞事业的重要性，赚钱才是最重要的呀！如果是这样的电视剧抢占了大妈们的市场，我觉得OK。而且还希望多来几部这样的剧给爸爸妈妈们洗一下脑，开放一下他们的思想吧！', 950162, 44129, -1, 1655, 3455, 2539, 7197, 3215, '2021-11-5 03:45:33', 609, 1, '2025-8-28 09:46:06', 0.0118083, -0.00292284);
