INSERT INTO `videoinfo` VALUES ('BV1wx411678L', '11563082', '26798384', '科普：空调是怎样制冷的？', '夏天我们经常会听人说：我们的命是空调给的。那么，空调是怎样制冷的呢？其实，空调的基本原理，就是简单的物态变化：我们只需要让制冷剂在室内汽化吸热，再到室外冷凝放热，就可以源源不断地将室内的热量搬运到室外。', 88684, 1768, -1, 657, 286, 1577, 954, 229, '2017-6-23 13:33:55', 202, 1, '2025-8-28 09:46:06', 0.00179496, -0.958226);
