INSERT INTO `videoinfo` VALUES ('BV1Xd4y1k7xY', '389633477', '98608863', '得奖了、离婚了、官司打完了，新的生活开始了【国际月经简报·ep 9】', '做月经简报会不会疲惫，如果这个月没有大事发生要说些什么？\n\n这期月经简报在筹备过程中，我们确实产生了一些疑惑，但是去了解每一个有关女性的故事，我们发现，讲出来，不但有意思，有意义，还有力量。\n\n贝尔托西获得诺贝尔化学奖，科技进步，性别意识也在进步；\n阴蒂不承担生育职能，但不代表她可以被忽视；\n吉赛尔邦辰离婚，恭喜吉赛尔走出丧偶式婚姻，我们期待更多男人走进家庭；\njingyao诉刘强东案达成庭前和解，感谢她非凡的勇气，过程本身就代表着一种胜利；\n\n希望这些消息能给你力量，让你周身温热地走进寒冬。', 62011, 6709, -1, 376, 161, 953, 4479, 115, '2022-11-1 07:59:39', 397, 1, '2025-8-28 09:46:06', 0.00175798, -0.961755);
INSERT INTO `videoinfo` VALUES ('BV1xD4y1o7qS', '712138303', '2374194', '【民乐合奏】被封印的我们，被一滴仙水盘活了！', '终于终于它横空出世啦~ 这次我们对经典独奏进行改编，6种乐器交错配合，让古风旋律焕发新声。\n感谢佰草集#翡翠水还把我们放进国风动画，大家和我们一起体验被修护焕活的感觉吧~~\n对了，片尾有彩蛋，月宫小兔仙下凡的秘密是…提前祝大家中秋快乐 (oﾟ▽ﾟ)o  \n\n古筝演奏：墨韵随步摇\n琵琶演奏：团团子\n笛子演奏：囚牛牛\n古琴演奏：南一先生\n二胡演奏：二胡妹\n中阮演奏：那爷\n编曲：胡多多\n音频后期：Niko\n出品：佰草集', 162391, 15115, -1, 817, 741, 2914, 5568, 474, '2020-9-24 05:30:47', 99, 1, '2025-8-28 09:46:06', 0.0057085, -0.58486);
