INSERT INTO `videoinfo` VALUES ('BV1Xg41147sD', '519416742', '2374194', '【指弹古筝】核爆神曲《aLIEz》，这个人又在揍古筝！', '刚糟蹋完老师们的指弹原创，丧心病狂如我连指弹翻奏也不会放过！这次惨遭我毒手的是@苍小天然呆bb 的经典翻奏核爆神曲。为了丰富一下低音部分的编配，做了比较多的特殊定弦，以至于中音区缺少了很多音。所以这次的移植相对来说自由度就比较大了，并没有完全按照苍老师的谱子来，主要保留了我最喜欢的泛音和扫弦部分。间奏尾奏也加入霍元甲的彩蛋，因为那个aHUOz实在是太洗脑了我到了中间就忍不住要拐过去哈哈哈！索性直接当个过门儿，还挺嗨～ 请大家多多指教！', 883722, 64262, -1, 3169, 1256, 15267, 31942, 1168, '2022-12-30 10:14:58', 201, 1, '2025-8-28 09:46:06', 0.00646212, -0.512963);
