INSERT INTO `videoinfo` VALUES ('BV1Xg411G7kE', '505180627', '26798384', '【柴知道】糖尿病怎么让人截肢、失明？瘦子和年轻人也会得糖尿病？', '目前中国大约有 1.3 亿糖尿病患者，而这些患者并不是都是胖子或老年人，许多二三十岁的年轻人，身形正常，也会不幸中招。而糖尿病所引发的种种凶险的并发症，很多人还不了解。哪些人容易得糖尿病？它怎么会让人截肢、失明、昏厥？糖尿病患者会面对哪些痛苦？这都要从糖尿病的发病原理讲起~', 651346, 26580, -1, 8242, 1671, 9324, 7238, 2592, '2021-8-31 09:34:14', 426, 1, '2025-8-28 09:46:06', 0.0185249, 0.63787);
