INSERT INTO `videoinfo` VALUES ('BV1Xs411U7bq', '2467931', '546195', '【老番茄】如何在监狱中吃香喝辣？在线等，挺急的', '自制 蹲监狱也要按照基本法。本次，老番茄以波澜不惊的语调，向您详实记叙诈骗犯煞笔先生的监狱生活。本辣鸡视频旨在以细致入微的视角为即将入狱的各位提供温馨贴士。祝各位的监狱生活春暖，花开。想看武士奇美拉的黄暴生活的，请戳:av2468750', 5513275, 62404, -1, 1831, 19581, 15683, 11922, 3152, '2015-6-21 16:41:53', 608, 1, '2025-8-28 09:46:06', 0.0164519, 0.4401);
INSERT INTO `videoinfo` VALUES ('BV1Xs411W7RC', '7223979', '26798384', '科普：公交卡是什么原理？', '【科普：公交卡是什么原理？】公交卡等IC卡里没电池，却能够实时更新余额和时间，究竟是怎么传输信息的呢？其实，在听到“滴”的那一刻，卡里的确是有电的。但电能的来源，却是在卡之外，传输方式也很神奇。这个90S的漫画短视频会说明其中的奥秘。', 44830, 445, -1, 158, 121, 466, 287, 96, '2016-11-23 12:02:14', 94, 1, '2025-8-28 09:46:06', 0.00362984, -0.783172);
INSERT INTO `videoinfo` VALUES ('BV1Xs411W7RL', '7223950', '26798384', '科普：“双面镜”是什么原理？', '新闻中经常出现一种用来偷窥的“双面镜”：一面看来是普通镜子，另一面看来却是透明的玻璃。其实，“双面镜”的两面并无区别，要想实现偷窥，主要是靠两边环境的明暗对比。这个2分钟的短视频，会告诉你原理和破解之道。', 59091, 733, -1, 222, 101, 828, 350, 108, '2016-11-23 12:00:11', 118, 1, '2025-8-28 09:46:06', 0.0020322, -0.935592);
INSERT INTO `videoinfo` VALUES ('BV1Xs411W7RY', '7223997', '26798384', '实验：如何手工修复和改装断裂的公交卡', '【实验：如何手工修复断裂的公交卡】公交卡的核心元件，是芯片和线圈。断裂的公交卡，芯片完好，线圈损坏。所以只要取出芯片，接上线圈，就可以修好啦～只需看100S的短视频，就可以包教包会。对了，还可以用同样的技术来改装迷你公交卡哦～（转载请注明@囧知道 来源） ', 23254, 189, -1, 117, 111, 446, 282, 81, '2016-11-23 12:03:26', 110, 1, '2025-8-28 09:46:06', 0.00960141, -0.213463);
