INSERT INTO `videoinfo` VALUES ('BV1XwomYKENM', '114217357155901', '98608863', '波伏瓦 ｜她絮絮叨叨的一生是惊艳的一生', '作为一个女性主义者，视波伏瓦为女神，把波伏瓦的观点当作金句。\n但好像一直以来对她都不是太了解。\n既八卦，又严肃地，想要窥探她如何成为了波伏瓦。\n\n是什么样的家庭，让她如此决绝的和社会规训做切割？\n是什么样的感情，让她和萨特的关系先锋又充满争议？\n什么启发了她？什么推动了她？什么奠定了她？\n\n所以我邀请阿姐夫一起，和我一起从自传开始，到所有和波伏瓦有关的材料，通过阅读去接近她。\n她好难读，好难懂，但在她絮絮叨叨的语言中，只言片语的态度里，我们依然能感受到伟大的女性灵感。', 24102, 1113, -1, 72, 24, 392, 428, 50, '2025-3-24 12:18:46', 3571, 1, '2025-8-28 09:46:06', 0.0129815, 0.109011);
