INSERT INTO `videoinfo` VALUES ('BV1yK411o74m', '475098573', '98608863', '如果直男和Gay在一起好好说话', '为什么有一些直男会恐同，为什么男性性少数群体会主动疏远直男？我邀请了两位直男朋友、两位性少数朋友，两两组队尝试去做一日朋友。让他们去自然里观鸟，去跳舞，去感受酷儿的社群文化。去理解对方的性取向、理解对方的处境，如果可以更进一步，去欣赏对方作为「人」的特质，而不仅仅用性别和性取向，去割裂了联结。\n嘉宾之一的许烨为我们准备了一次观鸟活动，我们看见不同种类的鸟在同一片栖息地觅食、休憩。我们或许是世界上最不同的人，但不也正是「我们」共享着一片土地，共同组成这个土地上多样性的奇观。', 793578, 48053, -1, 19193, 7249, 16185, 34831, 967, '2022-11-14 10:50:00', 1101, 1, '2025-8-28 09:46:06', 0.00930852, -0.241406);
