INSERT INTO `videoinfo` VALUES ('BV1Ys41167aL', '6117110', '116683', '【极乐净土】咬人猫/有咩酱/赤九玖❤155小分队o(*≧▽≦)ツ', '自制 极乐净土原作一出大家就决定要一起翻跳。155小分队的每一次合舞都很艰辛，这次也计划了很久才能敲定时间，请假相聚到同一个城市。接下来的一周每天都在舞蹈房里度过，全身心的投入宝贵的合练。我们也从第一天的各种问题，到一步步的去解决，再到今天的投稿，真的很开心又紧张，这支舞我们还有需要改善的地方，在有限的时间里我们只能尽力的去完善，也希望没有让大家失望。\r\n编舞：sm28709238 av4468694', 31291228, 513891, -1, 179326, 96435, 546359, 559946, 31724, '2016-9-1 12:35:43', 227, 1, '2025-8-28 09:46:06', 0.00484704, -0.667048);
