INSERT INTO `videoinfo` VALUES ('BV1yS411w7MB', '1906310026', '98608863', '令人害怕的分娩痛，可以预习怎样缓解吗？', '在生菜卷的时候，我不知道「分娩」的过程是可以计划的，要不要打无痛、要不要提出我自己的想法，在慌乱和疼痛中，孩子就出生了。但这一次，可能是我人生最后一次分娩，我希望我可以更清醒地去体验整个过程，去拥有更平静的、更舒服、更自信的分娩的过程。\n\n所以在生产之前，我请来了我的朋友 Robyn，一位瑜伽老师，同时也是陪伴过 50 多次分娩的导乐，来家里教给我，也教给所有准妈妈们一些分娩过程中会用到的呼吸方式和按摩姿势，也教给我们在分娩过程如何有效计划、如何尊重自己。在这次「复盘」和「预习」的过程中，我坚定了对自己身', 39024, 1873, -1, 395, 23, 822, 488, 65, '2024-7-29 04:20:00', 656, 1, '2025-8-28 09:46:06', 0.00216184, -0.923225);
