INSERT INTO `videoinfo` VALUES ('BV1yT4y177mM', '926234147', '26798384', '【柴知道】卖片小广告满天飞，正经内容被误伤，内容平台的算法是到底怎么回事？', '天天开业的澳门赌场，层出不穷的卖片僵尸号，都可以在每一个评论区留下垃圾信息。而一条普普通通的微博，检查 99 遍关键词后却还是发不出来。内容平台的反垃圾系统用了哪些算法？为什么正常内容也会被误伤？神乎其神的 AI 怎么识别垃圾信息？饱受困扰的我们研究了其中的机制，制作了这支视频~', 146988, 11786, -1, 298, 868, 1560, 3162, 581, '2020-6-25 10:00:31', 328, 1, '2025-8-28 09:46:06', 0.0134326, 0.15205);
