INSERT INTO `videoinfo` VALUES ('BV1z24y1Z7Dv', '688081503', '26798384', '搭几根树枝就下蛋~你这鸟巢怎么这么敷衍？【柴知道】', '喜鹊筑巢，需要花一个月时间。而斑鸠筑巢，几根树枝随便一堆，不到一小时就能搞定。大家都是鸟，为什么有的鸟筑巢能这么摆烂？一座结实又精致的鸟窝是如何修出来的？那些千奇百怪的鸟巢背后，藏着多少属于鸟儿们的「生育哲学」？', 424044, 20938, -1, 857, 1638, 2285, 3986, 767, '2022-9-15 09:53:54', 397, 1, '2025-8-28 09:46:06', 0.0116185, -0.0210227);
