INSERT INTO `videoinfo` VALUES ('BV1z3411L7Ya', '424240996', '98608863', '请问一下：男生为什么总有调整「那里」的动作啊？', '「绝对是个妞」从不羞于讲述女性身体的奥妙，然而对于男性身体的奥秘，我们居然还没探索过？今天这期「请问一下」，我们请 3 个女孩问问 3 个男孩，男孩青春期时身体有什么变化？\n\n· 第一次遗米青那天还好吗？\n· 真的每天勃（啊）起好多次吗，被人看见要怎么办？\n· 怎么总有摸 JJ 的动作啊，是在干嘛？\n· 不能写出来的其他问题，此处省略1万字\n\n「请问一下」是我们尝试去在不同群体间建立对话的栏目，我们希望在这里可以打破性别的隔阂，去大胆地提问、无保留地分享、真诚地感受，在差异里寻求共通。', 203302, 14640, -1, 2398, 1298, 1625, 3641, 518, '2022-2-21 11:30:02', 648, 1, '2025-8-28 09:46:06', 0.0195272, 0.733494);
