INSERT INTO `videoinfo` VALUES ('BV1Z34y1c7PQ', '833708777', '98608863', '哪怕是 99%，那也不是真正的平等【国际月经简报ep·20】', 'hello，这个月过得好吗？#国际月经简报# 提醒您，在女性有关的事情上，即使入冬，也要燃起来。\n\n冰岛努力去实现100%的平等，听上去天方夜谭，但不断去接近的过程中，就会让那些隐形的不平等被揭穿，被改变。麦当娜努力留在舞台上，让我们可以看见一个女人的一生，它有挣扎，但也会冲破枷锁。社会更积极去面对女性的处境，去倾听她们的声音，看见她们的需要，而这就是改变的开始，\n\n有些事情，可能努力真的就会有结果。', 166791, 33927, -1, 2418, 558, 5687, 17895, 1135, '2023-11-20 10:47:19', 604, 1, '2025-8-28 09:46:06', 0.0123916, 0.052726);
