INSERT INTO `videoinfo` VALUES ('BV1z54y187M2', '844753606', '11799651', '爱拼才会赢，福建的逆袭之路【中国城市观察08】', '这是城市观察系列的第08期，这期我们来讲讲福建。城市观察系列我现在一共做了6期正片+2期番外。\n北京周边为什么没有上海周边发达？【01】\n江西为什么这么缺乏存在感？【02】\n宁夏到底是个什么地方【03】\n广西为何成了沿海经济最差的省份？【04】\n河南为什么被黑得这么惨？【05】\n被煤炭“诅咒”的山西【06】\n缺乏存在感的安徽【07】\n番外1讲了山东为什么会给人“土”的错觉，番外2讲了为什么东北是全国女性地位最高的地区之一。\n这个系列会持续更新，讲完全中国每一个省份。关注我不迷路哦~', 673290, 23632, -1, 4317, 8349, 6420, 5997, 3100, '2021-3-25 11:05:01', 916, 1, '2025-8-28 09:46:06', 0.0057979, -0.576332);
INSERT INTO `videoinfo` VALUES ('BV1z54y1E7i4', '846766251', '1377430946', '美国高官确定访华，背地却和日韩对付中国？反复横跳只为自身利益', '当地时间7月21日，美国国务院在一份公开声明中宣布，正在亚洲访问的美国常务副国务卿温迪·谢尔曼（Wendy Sherman），将于7月25日至26日访问中国，并于7月27日访问阿曼。', 6577, 182, -1, 2, 13, 9, 12, 16, '2021-7-22 09:27:36', 401, 1, '2025-8-28 09:46:06', 0, -1.12947);
INSERT INTO `videoinfo` VALUES ('BV1z54y1E7qo', '846766108', '98608863', '退网！竟然说我没有以前好！？', '你们觉得 Alex 变了吗？变得没有以前敢了？我要听实话！变得越来越像一个无聊的大人这件事情，让我觉得有些惶恐，因为我一直觉得「非常态」才意味着我「敢」。\n每个人的血液里都有一些「疯」的因子，是专注、执着的根源。在对自己和未来不确定时，它会成为我找寻自己的方式。在我对一切都很笃定的时候，它会让位于理性思考。\n我给自己订了一套 APM 爱疯乐的首饰。CM 的字母证明着我现在是一个 Cool Mom，也会是一个Crazy Mom，提醒我在下次经历不确定的时候，不要害怕，因为未来的我会给自己带来惊喜。', 86888, 7285, -1, 139, 296, 634, 2068, 256, '2021-7-23 11:04:43', 466, 1, '2025-8-28 09:46:06', 0.00458657, -0.691897);
