INSERT INTO `videoinfo` VALUES ('BV1Z7411t7Qw', '87664805', '98608863', '你今天还好吗 07｜疫情期间，时尚博主还营业吗？', '#你今天还好吗# 进行到第 7 天，连线的另一边是时装博主 @AvaFoo，我决定和 Ava 做点不一样的，所以今天就一起边化妆边聊天。\n\n我们聊了聊被疫情改变的计划，时装周计划取消了，原定的推送计划改期了，以前每天要出镜的时装博主都快忘了要怎么化妆了。我让她给我种草她最近发现的好东西时，Ava 说，最近买得最多的就是，菜（这是 real 种草了）。\n\n最后 Ava 问的问题是：你觉得自己在家的这些天收获了什么？疫情改变了多少人的生活计划，你的计划被改变了吗？', 9409, 475, -1, 61, 41, 20, 73, 35, '2020-2-9 04:34:34', 462, 1, '2025-8-28 09:46:06', 0, -1.12947);
