INSERT INTO `videoinfo` VALUES ('BV1zb4y1z7Zt', '632143848', '98608863', '一张病危通知书：性生活终将离你远去 | 欲望ICU vol.1', '我最近读到的这本来自著名婚恋咨询师 Esther Perel 的《亲密陷阱——爱、欲望与平衡艺术》告诉我，激情会消失、性会消失，你终将走向无性。这听起来真的很吓人，而且身边和私信上的朋友的故事告诉我这好像确实是真的。无关年龄、婚否，很多长久稳定的关系都没有性了。更可怕的是，这件事情并不是缓慢柔和地发生的，而是带着很多负面情绪、突如其来地发生的。大家感到疑惑：为什么我被拒绝了？为什么我（或者ta）好像没有性欲了呢？是不是我不够好？是不是我们的感情不够好？', 556420, 29431, -1, 7619, 4138, 6990, 11112, 2746, '2021-8-5 11:10:20', 738, 1, '2025-8-28 09:46:06', 0.0218263, 0.952832);
