INSERT INTO `videoinfo` VALUES ('BV1zr4y1q7hA', '767056252', '98608863', '揭秘光鲜博主的「阴暗面」', '网络上的我，被人说总是呈现出一种春风得意、光鲜美好的形象，就连朋友都在吐槽我不够真实。但其实生活中能戳中我的丧不要太多。以前我觉得讲出来没不会有什么解决办法，还会给别人带来困扰。但这期节目让我觉得跟大家\"分享小确丧\"这个行为本身还挺好笑的，（希望脱口秀节目看看我），如果你也看笑了，你就肯定也能 get 到泡泡骚挂在嘴边的\"唾手可得的快乐\"。\"丧\"和\"快乐\"本来就是可以转化的一体两面，年轻人可以丧，但也能继续骚。', 93244, 7316, -1, 146, 911, 593, 2012, 183, '2022-3-5 13:00:02', 602, 1, '2025-8-28 09:46:06', 0.00204169, -0.934687);
