INSERT INTO `videoinfo` VALUES ('BV1zs411o7ah', '870223', '116683', '【咬人猫】水色SummerDays❤想给你治愈的微笑~第②⑤作舞蹈(<ゝω·)☆', '冬天跳夏天的舞感觉有点小违和。不过因为自己垂头丧气的时候被这支舞治愈过，于是也想传递相同的心情给大家。一直很想在铺满银杏的画面里跳舞，这次终于圆满了。P2看卖蠢的露露，听现场围观群众各种四川话ww因为围观的人太多所以鸭梨很大，跳得不好时常面瘫啥的。【PS：你们才看不出小熊是后期上去的，因为我忘记带小熊出门！谢谢后期argonium 微博@-咬人猫xs- 原创振幅sm21590350', 460840, 1394, -1, 783, 4990, 3473, 2618, 704, '2013-12-12 16:02:48', 558, 1, '2025-8-28 09:46:06', 0.00281622, -0.860794);
