INSERT INTO `videoinfo` VALUES ('BV1Zt411s7cw', '40362327', '98608863', 'Alex\'s Vlog 01 | 2019 好运来了吗', '微博关注我 @Alex绝对是个妞儿 有抽奖哦。\n\n每年一次的交换礼物派对，今年主题“好运来”，成就了一个大型土嗨秧歌现场！视频一定要看到最后你就知道[阴险]\n\n可惜没拍下来的是派对结束后大家坐在一起分享，有什么东西是你在 2018 年得到并想要带到 2019 年的。我想我的应该是 Resilience 复原力吧，面对创伤和压力你如何去适应它，并且有足够的韧性反弹回来。\n\n那你从 2018 带到 2019 的是什么呢？', 21454, 889, -1, 106, 85, 99, 354, 100, '2019-1-10 04:06:16', 301, 1, '2025-8-28 09:46:06', 0, -1.12947);
