INSERT INTO `videoinfo` VALUES ('BV1zx4y1479k', '1005878674', '2920960', '这是一条无可挑剔的，梦寐以求的，在心中能排在宇宙第一的烤鱼！！', '店名：CHARCOAL 煤球  位置：北京朝阳区工体附近\n\n这家餐厅工业风的装修又有些轻奢的感觉，主打的特色是炭烤。\n并且这家餐厅可以说是褒贬不一，因为凡是沾上炭烤的做法，菜品的价格确实都比较高，如果戳中你的味蕾，是你想要的味道，那绝对物超所值，但如果出品的风味不符合你的审美，你可能会觉得自己像个大冤种。总体来说这家店是把炭烤做到了极致，有自己的理念和创新。就烤鱼来说，价格就算翻倍我可能馋了都会忍不住去吃，但章鱼足哪怕只需要一半的价格，我也不会再吃。', 961281, 74958, -1, 2949, 3197, 9142, 60888, 1206, '2024-7-2 10:00:00', 764, 1, '2025-8-28 09:46:06', 0.00315878, -0.828113);
