INSERT INTO `videoinfo` VALUES ('BV1zzKHzoEE4', '114743373209541', '98608863', '如果女儿说，穿得少是我的自由，我该担心吗？', '生完女儿的第一个夏天，我开始对“穿衣自由”动摇了。\n以前我也是吊带短裤的忠实信徒，但当我看见高中女生穿着热裤进校园，或者小女孩跟着流行文化模仿性感的时候，我突然开始犹豫：性感的表达，是不是也会变成另一个规训？\n我想这是成为母亲之后变一种本能的提问。\n我和大家分享我的困惑，我们聊了聊性感、凝视、信任、自由边界。也聊了聊，作为母亲，我的陪伴和教育会如何发挥作用，让她成为一个真正为自己选择的人。', 127592, 2676, -1, 181, 181, 925, 624, 293, '2025-6-25 09:55:14', 612, 1, '2025-8-28 09:46:06', 0.0188754, 0.671304);
